insert into public.questions (id, topic, source, q, opts, ans_idx, exp, category, category_icon, is_active)
values
(7552, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'During adult cardiac arrest, what is the primary rationale for administering epinephrine?', '["Alpha-1 mediated vasoconstriction increases coronary and cerebral perfusion pressure during CPR", "Beta-2 mediated bronchodilation improves oxygenation during compressions", "Direct positive inotropy restores spontaneous myocardial contraction immediately", "It corrects the underlying metabolic acidosis driving the arrest"]'::jsonb, 0, 'Epinephrine''s alpha-1 vasoconstrictor effect raises aortic diastolic pressure, improving coronary and cerebral perfusion pressure generated by chest compressions; it does not primarily act via bronchodilation or acidosis correction.', 'Pre-Council', '🎓', true),
(7553, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'In adult ACLS, standard IV/IO epinephrine dosing during cardiac arrest is:', '["1 mg every 3-5 minutes", "0.1 mg every minute", "1 mg once only, then switch to vasopressin", "10 mg every 10 minutes"]'::jsonb, 0, 'The standard adult ACLS dose is 1 mg IV/IO push every 3-5 minutes throughout the resuscitation.', 'Pre-Council', '🎓', true),
(7554, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Atropine improves symptomatic bradycardia primarily by:', '["Competitively blocking muscarinic acetylcholine receptors at the SA and AV nodes, reducing vagal tone", "Stimulating beta-1 receptors on the sinoatrial node directly", "Blocking potassium efflux to prolong the action potential", "Increasing intracellular calcium in cardiac myocytes via a receptor-independent mechanism"]'::jsonb, 0, 'Atropine is an antimuscarinic that blocks vagal (parasympathetic) input to the SA and AV nodes, increasing heart rate and conduction velocity.', 'Pre-Council', '🎓', true),
(7555, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Atropine is least likely to be effective for bradycardia caused by:', '["Mobitz type II or third-degree AV block with a wide QRS (infranodal block)", "High vagal tone from an inferior wall myocardial infarction", "A vasovagal reaction", "Sinus node dysfunction"]'::jsonb, 0, 'Infranodal blocks (Mobitz II, complete heart block with wide QRS) are usually below the level atropine can influence and respond poorly; transcutaneous pacing or a catecholamine infusion is preferred.', 'Pre-Council', '🎓', true),
(7556, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Amiodarone is classified as which type of antiarrhythmic, and is used for what type of arrest rhythm?', '["Class III agent, used for shock-refractory ventricular fibrillation/pulseless VT", "Class I agent, used for asystole", "Class II agent, used for PEA", "Class IV agent, used for sinus tachycardia"]'::jsonb, 0, 'Amiodarone is a Class III antiarrhythmic (predominantly potassium channel blockade, with additional sodium, calcium, and beta-blocking properties) given for VF/pulseless VT that persists after defibrillation and epinephrine.', 'Pre-Council', '🎓', true),
(7557, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'A patient on long-term oral amiodarone should be monitored for which combination of toxicities?', '["Pulmonary fibrosis, thyroid dysfunction, and hepatotoxicity", "Ototoxicity, nephrotoxicity, and red man syndrome", "Adrenal suppression, hypoglycemia, and priapism", "Serotonin syndrome, tendon rupture, and QT shortening"]'::jsonb, 0, 'Amiodarone''s iodine-containing structure and long half-life predispose to pulmonary fibrosis, thyroid dysfunction, hepatotoxicity, and corneal microdeposits with chronic use.', 'Pre-Council', '🎓', true),
(7558, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Vasopressin is useful in catecholamine-resistant vasodilatory (septic) shock because it:', '["Activates V1 receptors on vascular smooth muscle, causing vasoconstriction independent of adrenergic receptors", "Increases myocardial contractility via beta-1 stimulation", "Directly inhibits nitric oxide synthase in the myocardium", "Enhances renal free water excretion to reduce preload"]'::jsonb, 0, 'Vasopressin causes vasoconstriction through V1 receptors, a pathway independent of catecholamine receptors, which is why it remains effective when adrenergic receptors are downregulated or unresponsive, as can occur in prolonged septic shock.', 'Pre-Council', '🎓', true),
(7559, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Calcium chloride is indicated during resuscitation in all of the following EXCEPT:', '["Digoxin toxicity", "Severe hyperkalemia with ECG changes", "Calcium channel blocker overdose", "Hypocalcemia after massive transfusion"]'::jsonb, 0, 'Calcium is avoided in digoxin toxicity because it can worsen digoxin-induced arrhythmias; it is indicated for hyperkalemia, calcium channel blocker or magnesium overdose, and symptomatic hypocalcemia.', 'Pre-Council', '🎓', true),
(7560, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'A key nursing consideration when administering IV calcium chloride is:', '["Give through a central line when possible, as it is highly irritating and can cause tissue necrosis if extravasated", "It may be mixed in the same line as sodium bicarbonate for compatibility", "It should be given as a rapid IV push in all situations", "No cardiac monitoring is required during administration"]'::jsonb, 0, 'Calcium chloride is a vesicant that can cause severe tissue necrosis with extravasation, so central venous administration is preferred; it precipitates when mixed with bicarbonate and should be given slowly with cardiac monitoring.', 'Pre-Council', '🎓', true),
(7561, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Sodium bicarbonate during cardiac arrest is most appropriate for:', '["Known severe hyperkalemia or tricyclic antidepressant overdose", "Routine use in every cardiac arrest to correct acidosis", "Ventricular fibrillation as a first-line agent", "Replacing epinephrine when unavailable"]'::jsonb, 0, 'Bicarbonate is not routinely recommended in arrest but has specific indications such as pre-existing severe hyperkalemia or tricyclic antidepressant toxicity, where it can be lifesaving.', 'Pre-Council', '🎓', true),
(7562, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Lidocaine''s mechanism of action as an antiarrhythmic is:', '["Blockade of fast sodium channels, decreasing automaticity in ischemic ventricular tissue", "Beta-1 receptor blockade, slowing AV conduction", "Potassium channel blockade, prolonging repolarization", "Calcium channel blockade at the SA node"]'::jsonb, 0, 'Lidocaine is a Class Ib antiarrhythmic that blocks sodium channels preferentially in depolarized/ischemic tissue, suppressing ventricular ectopy and serving as an alternative to amiodarone for shock-refractory VF/pulseless VT.', 'Pre-Council', '🎓', true),
(7563, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'IV magnesium sulfate is the treatment of choice for which arrhythmia?', '["Torsades de pointes", "Sinus bradycardia", "Atrial fibrillation with rapid ventricular response", "First-degree AV block"]'::jsonb, 0, 'Magnesium sulfate stabilizes the cardiac membrane and is first-line for torsades de pointes, even when serum magnesium levels are normal.', 'Pre-Council', '🎓', true),
(7564, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'A significant risk of epinephrine administration during and after resuscitation is:', '["Increased myocardial oxygen demand that can precipitate ischemia and tachyarrhythmias", "Profound bradycardia due to beta-1 blockade", "Hypoglycemia from increased insulin release", "Bronchoconstriction from beta-2 antagonism"]'::jsonb, 0, 'Epinephrine increases heart rate, contractility, and afterload, raising myocardial oxygen demand and the risk of ischemia or tachyarrhythmias, particularly with repeated dosing.', 'Pre-Council', '🎓', true),
(7565, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'The recommended adult IV dose of atropine for symptomatic bradycardia is:', '["0.5 mg every 3-5 minutes, maximum total 3 mg", "1 mg once only, with no repeat dosing", "0.1 mg/kg as a single bolus", "5 mg every minute until heart rate normalizes"]'::jsonb, 0, 'The recommended regimen is 0.5 mg IV every 3-5 minutes up to a total of 3 mg, which produces full vagal blockade.', 'Pre-Council', '🎓', true),
(7566, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Adenosine terminates paroxysmal supraventricular tachycardia (PSVT) by:', '["Transiently blocking conduction through the AV node; it must be given as a rapid IV push followed by a saline flush due to its extremely short half-life", "Permanently ablating the AV node", "Increasing sympathetic tone to overdrive the reentrant circuit", "Prolonging the QT interval to interrupt reentry"]'::jsonb, 0, 'Adenosine causes a brief, transient AV nodal block that interrupts reentrant circuits involving the AV node; because its half-life is under 10 seconds, it must be given as a rapid push immediately followed by a flush.', 'Pre-Council', '🎓', true),
(7567, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'In shock-refractory VF/pulseless VT, the initial IV dose of amiodarone is:', '["300 mg IV push, with a second dose of 150 mg if needed", "150 mg IV push, repeated every minute", "1200 mg IV push as a single dose", "50 mg IV push, titrated to effect"]'::jsonb, 0, 'The ACLS-recommended first dose is 300 mg IV/IO push; a second dose of 150 mg may be given for recurrent/refractory VF/pulseless VT.', 'Pre-Council', '🎓', true),
(7568, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Compared with lidocaine, a key feature of amiodarone that supports its use for refractory VF/pulseless VT is:', '["Broader multichannel antiarrhythmic activity (sodium, potassium, calcium, and beta-blocking effects)", "Amiodarone has no effect on blood pressure whatsoever", "Amiodarone has a much shorter half-life allowing more frequent dosing", "Amiodarone can be given safely with no cardiac monitoring"]'::jsonb, 0, 'Amiodarone''s broad multichannel blocking activity gives it efficacy against a wider range of arrhythmias, though both drugs remain acceptable per current guidelines with similar survival outcomes.', 'Pre-Council', '🎓', true),
(7569, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'When atropine fails to improve symptomatic bradycardia and transcutaneous pacing is not immediately available, the next appropriate step is:', '["Start a dopamine or epinephrine infusion titrated to effect", "Give a second full dose of atropine up to 6 mg total", "Administer high-dose calcium chloride", "Give amiodarone 300 mg IV push"]'::jsonb, 0, 'If atropine is ineffective or pacing is unavailable/delayed, a chronotropic infusion such as dopamine or epinephrine should be started while preparing for transcutaneous pacing.', 'Pre-Council', '🎓', true),
(7570, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Vancomycin exerts its bactericidal effect against MRSA by:', '["Inhibiting cell wall synthesis through binding to the D-alanyl-D-alanine terminus of peptidoglycan precursors", "Inhibiting bacterial protein synthesis at the 50S ribosomal subunit", "Inhibiting DNA gyrase", "Disrupting folic acid synthesis"]'::jsonb, 0, 'Vancomycin, a glycopeptide, binds the D-Ala-D-Ala terminus of peptidoglycan precursors, blocking cell wall cross-linking and causing bacterial cell lysis.', 'Pre-Council', '🎓', true),
(7571, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'A patient develops flushing, pruritus, and a rash on the neck and upper torso shortly after a rapid vancomycin infusion. The most appropriate nursing action is to:', '["Slow the infusion rate, as this is histamine-mediated red man syndrome rather than a true allergic reaction", "Stop vancomycin permanently and document a severe anaphylactic allergy", "Administer epinephrine immediately", "Increase the infusion rate since the reaction is self-limited"]'::jsonb, 0, 'Red man syndrome is caused by nonimmune histamine release from rapid vancomycin infusion; it is managed by slowing the infusion rate and can often be prevented with a longer infusion time, not by labeling the patient allergic.', 'Pre-Council', '🎓', true),
(7572, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'For serious MRSA infections (e.g., bacteremia, pneumonia), target vancomycin trough levels are generally:', '["15-20 mcg/mL", "1-5 mcg/mL", "40-50 mcg/mL", "Troughs are not monitored for vancomycin"]'::jsonb, 0, 'For serious invasive MRSA infections, troughs of 15-20 mcg/mL (or AUC-guided dosing) are targeted to optimize efficacy while balancing nephrotoxicity risk.', 'Pre-Council', '🎓', true),
(7573, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Key nursing considerations for a patient receiving IV gentamicin include monitoring for:', '["Nephrotoxicity and ototoxicity, with peak and trough level monitoring", "Hepatotoxicity and QT prolongation only", "Serotonin syndrome", "Red man syndrome"]'::jsonb, 0, 'Aminoglycosides carry significant risk of nephrotoxicity and irreversible ototoxicity, requiring monitoring of renal function and drug levels (peak/trough or extended-interval dosing).', 'Pre-Council', '🎓', true),
(7574, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Piperacillin-tazobactam provides broad-spectrum gram-negative and anaerobic coverage because:', '["Tazobactam inhibits bacterial beta-lactamase enzymes, protecting piperacillin from degradation", "Tazobactam is itself a potent antibiotic against anaerobes", "Piperacillin alone covers ESBL-producing organisms without tazobactam", "The combination works by inhibiting protein synthesis"]'::jsonb, 0, 'Tazobactam is a beta-lactamase inhibitor that protects the beta-lactam piperacillin from enzymatic degradation by many bacterial beta-lactamases, extending its spectrum against resistant gram-negative organisms and anaerobes.', 'Pre-Council', '🎓', true),
(7575, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Which carbapenem carries a comparatively higher risk of seizures, particularly at high doses or in renal impairment?', '["Imipenem-cilastatin", "Meropenem", "Ertapenem", "All carbapenems carry equal seizure risk"]'::jsonb, 0, 'Imipenem-cilastatin has a comparatively higher seizure risk than meropenem or ertapenem, especially with high doses, CNS disorders, or inadequate renal dose adjustment.', 'Pre-Council', '🎓', true),
(7576, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'A patient on linezolid who is also taking an SSRI is at increased risk for:', '["Serotonin syndrome, because linezolid has weak monoamine oxidase inhibitor activity", "Red man syndrome", "QT interval shortening", "Nephrotoxicity"]'::jsonb, 0, 'Linezolid has weak, nonselective MAO-inhibiting activity; combined with serotonergic drugs like SSRIs, it increases the risk of serotonin syndrome.', 'Pre-Council', '🎓', true),
(7577, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Colistin (polymyxin E) is typically reserved for treatment of:', '["Multidrug-resistant gram-negative organisms such as carbapenem-resistant Enterobacteriaceae or Pseudomonas", "Uncomplicated urinary tract infections caused by susceptible E. coli", "MRSA bacteremia", "Anaerobic intra-abdominal infections"]'::jsonb, 0, 'Colistin is a last-resort agent for multidrug-resistant gram-negative infections due to its significant nephrotoxicity and neurotoxicity, reserved for cases with few other options.', 'Pre-Council', '🎓', true),
(7578, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Adverse effects associated with fluoroquinolones (e.g., ciprofloxacin) include:', '["QT interval prolongation and tendon rupture/tendinopathy", "Ototoxicity and red man syndrome", "Disulfiram-like reaction with alcohol", "Adrenal suppression"]'::jsonb, 0, 'Fluoroquinolones can prolong the QT interval and increase risk of tendinopathy/tendon rupture, especially with concurrent corticosteroid use or in older adults.', 'Pre-Council', '🎓', true),
(7579, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'A patient receiving metronidazole should be counseled to avoid alcohol because of the risk of:', '["A disulfiram-like reaction (flushing, nausea, tachycardia)", "Red man syndrome", "Serotonin syndrome", "Malignant hyperthermia"]'::jsonb, 0, 'Metronidazole can cause a disulfiram-like reaction with alcohol due to inhibition of aldehyde dehydrogenase, leading to acetaldehyde accumulation.', 'Pre-Council', '🎓', true),
(7580, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'For surgical site infection prophylaxis, the antibiotic dose should generally be administered:', '["Within 60 minutes prior to surgical incision (up to about 120 minutes for agents like vancomycin or fluoroquinolones)", "Immediately after wound closure", "24 hours before the scheduled surgery", "Only if signs of infection develop postoperatively"]'::jsonb, 0, 'Prophylactic antibiotics should achieve adequate tissue levels at the time of incision, so they are given within 60 minutes before incision (extended for drugs requiring longer infusion times, like vancomycin or fluoroquinolones).', 'Pre-Council', '🎓', true),
(7581, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Pharmacologic stress ulcer prophylaxis (e.g., PPI or H2 blocker) is generally indicated in ICU patients who:', '["Are mechanically ventilated for more than 48 hours or have a coagulopathy", "Are hemodynamically stable and tolerating a full oral diet", "Have no risk factors for GI bleeding", "Are receiving prophylactic anticoagulation only"]'::jsonb, 0, 'Major risk factors warranting stress ulcer prophylaxis include mechanical ventilation beyond 48 hours and coagulopathy, both of which significantly increase risk of clinically important GI bleeding in critically ill patients.', 'Pre-Council', '🎓', true),
(7582, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'In a critically ill patient with active major bleeding, appropriate VTE prophylaxis would be:', '["Mechanical prophylaxis (sequential compression devices) alone, withholding pharmacologic anticoagulation", "A full-dose therapeutic heparin infusion", "Low molecular weight heparin at prophylactic dose", "No VTE prophylaxis of any kind is ever appropriate"]'::jsonb, 0, 'Active bleeding is a contraindication to pharmacologic anticoagulant prophylaxis; mechanical methods such as sequential compression devices should be used until the bleeding risk resolves.', 'Pre-Council', '🎓', true),
(7583, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Norepinephrine is the first-line vasopressor in septic shock primarily because of its:', '["Predominant alpha-1 agonist activity causing vasoconstriction, with modest beta-1 inotropic effect", "Pure beta-2 agonist activity causing bronchodilation", "Selective dopamine-1 receptor activity improving renal perfusion", "Direct nitric oxide donor activity causing vasodilation"]'::jsonb, 0, 'Norepinephrine''s potent alpha-1 mediated vasoconstriction raises mean arterial pressure with less tachycardia than pure beta-agonists, while its mild beta-1 activity supports cardiac output, making it first-line for septic shock.', 'Pre-Council', '🎓', true),
(7584, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'If norepinephrine extravasates into subcutaneous tissue, the appropriate local treatment is infiltration with:', '["Phentolamine, an alpha-adrenergic antagonist", "Additional norepinephrine to dilute the concentration", "Calcium gluconate", "Protamine sulfate"]'::jsonb, 0, 'Phentolamine, an alpha-blocker, reverses the intense local vasoconstriction from extravasated vasopressors, preventing tissue ischemia and necrosis.', 'Pre-Council', '🎓', true),
(7585, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Dobutamine is used in cardiogenic shock/low cardiac output states because it:', '["Is a predominantly beta-1 agonist that increases myocardial contractility (positive inotropy)", "Is a pure alpha-1 agonist that increases systemic vascular resistance", "Blocks angiotensin-converting enzyme", "Inhibits phosphodiesterase-3 exclusively in vascular smooth muscle"]'::jsonb, 0, 'Dobutamine primarily stimulates beta-1 receptors, increasing myocardial contractility and cardiac output; it can cause tachycardia and mild vasodilation (beta-2 effect), sometimes causing hypotension.', 'Pre-Council', '🎓', true),
(7586, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Phenylephrine differs from norepinephrine in that it:', '["Is a pure alpha-1 agonist with no significant beta activity, which can cause reflex bradycardia", "Has significant beta-1 inotropic activity", "Is primarily used to treat bradycardia", "Causes bronchodilation via beta-2 stimulation"]'::jsonb, 0, 'Phenylephrine is a selective alpha-1 agonist that raises blood pressure through vasoconstriction alone, without inotropic or chronotropic effect, and can trigger reflex bradycardia via the baroreceptor response.', 'Pre-Council', '🎓', true),
(7587, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Milrinone improves cardiac output in decompensated heart failure by:', '["Inhibiting phosphodiesterase-3, increasing cAMP to produce both inotropy and vasodilation", "Blocking beta-1 receptors to reduce myocardial oxygen demand", "Directly stimulating alpha-1 receptors", "Inhibiting the sodium-potassium ATPase pump"]'::jsonb, 0, 'Milrinone is a phosphodiesterase-3 inhibitor that increases intracellular cAMP in cardiac and vascular smooth muscle, producing an inodilator effect; it is renally eliminated, so the dose should be adjusted in renal impairment.', 'Pre-Council', '🎓', true),
(7588, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Dopamine''s pharmacologic effects are dose-dependent; at moderate infusion rates, it primarily:', '["Stimulates beta-1 receptors, producing inotropic and chronotropic effects", "Stimulates only dopaminergic receptors, causing renal vasodilation with no cardiac effect", "Stimulates alpha-1 receptors exclusively, causing vasoconstriction", "Has no receptor activity at any dose"]'::jsonb, 0, 'At moderate (intermediate) doses, dopamine predominantly stimulates beta-1 receptors, increasing heart rate and contractility; at higher doses alpha-1 effects predominate, and low-dose renal dopamine''s clinical benefit is not supported by evidence.', 'Pre-Council', '🎓', true),
(7589, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Labetalol is useful in hypertensive emergencies because it:', '["Blocks both alpha-1 and beta receptors, lowering blood pressure without significant reflex tachycardia", "Is a pure alpha-1 antagonist", "Is a direct arteriolar vasodilator with no receptor activity", "Selectively blocks beta-2 receptors only"]'::jsonb, 0, 'Labetalol''s combined alpha-1 and nonselective beta blockade reduces blood pressure via vasodilation and decreased heart rate/contractility, minimizing the reflex tachycardia seen with pure vasodilators.', 'Pre-Council', '🎓', true),
(7590, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Esmolol is favored for rapid, titratable heart rate/blood pressure control because:', '["It is a cardioselective beta-1 blocker with an ultra-short half-life of about 9 minutes", "It has a half-life of approximately 24 hours", "It is a nonselective beta blocker requiring hepatic metabolism", "It has significant intrinsic sympathomimetic activity"]'::jsonb, 0, 'Esmolol is metabolized by red blood cell esterases, giving it an extremely short half-life (about 9 minutes), allowing rapid titration and quick offset if adverse effects occur.', 'Pre-Council', '🎓', true),
(7591, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Nicardipine is often preferred in neurologic emergencies (e.g., subarachnoid hemorrhage, acute stroke) because it:', '["Provides smooth, titratable arterial vasodilation without the significant reflex tachycardia seen with some other agents", "Directly lowers intracranial pressure through diuresis", "Has no effect on cerebral blood flow", "Is a beta-blocker that reduces cerebral perfusion pressure"]'::jsonb, 0, 'Nicardipine, a dihydropyridine calcium channel blocker, provides smooth and predictable blood pressure control via arterial vasodilation, making it a preferred agent in neurocritical care hypertensive emergencies.', 'Pre-Council', '🎓', true),
(7592, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'A known adverse effect of hydralazine that requires nursing monitoring is:', '["Reflex tachycardia and fluid retention due to direct arteriolar vasodilation", "Severe bradycardia", "Hyperkalemia", "QT interval shortening"]'::jsonb, 0, 'As a direct arteriolar vasodilator without any effect on veins, hydralazine drops SVR abruptly, triggering baroreceptor-mediated reflex tachycardia and compensatory sodium/water retention.', 'Pre-Council', '🎓', true),
(7593, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Clevidipine, a short-acting dihydropyridine calcium channel blocker used for hypertensive emergencies, requires caution in patients with:', '["Egg or soy allergy, since it is formulated in a lipid emulsion", "Renal impairment, since it depends entirely on renal clearance", "Iodine allergy", "Sulfa allergy"]'::jsonb, 0, 'Clevidipine is formulated in a lipid emulsion similar to propofol, so it should be used cautiously in patients with egg or soy allergies and monitored for hypertriglyceridemia.', 'Pre-Council', '🎓', true),
(7594, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'At low-to-moderate infusion doses, epinephrine''s predominant cardiovascular effect is:', '["Beta-1 and beta-2 mediated increases in heart rate and contractility, with some vasodilation", "Pure alpha-1 vasoconstriction only", "Pure vagal stimulation causing bradycardia", "Selective renal vasodilation"]'::jsonb, 0, 'At lower doses, beta effects (increased contractility, heart rate, and some beta-2 vasodilation) predominate; at higher doses alpha-1 vasoconstriction becomes more prominent, making epinephrine''s effect dose-dependent.', 'Pre-Council', '🎓', true),
(7595, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Adding low-dose vasopressin to norepinephrine in septic shock is done primarily to:', '["Achieve target MAP while potentially reducing the required norepinephrine (catecholamine) dose", "Replace norepinephrine entirely due to superior efficacy", "Treat associated bronchospasm", "Provide an antiarrhythmic effect"]'::jsonb, 0, 'Vasopressin acts through non-adrenergic V1 receptors, providing an additive vasoconstrictive effect that can help achieve target MAP and may allow reduction of catecholamine dose.', 'Pre-Council', '🎓', true),
(7596, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Vasopressor infusions such as norepinephrine and dopamine should preferably be administered via:', '["A central venous catheter, to reduce the risk of extravasation injury and tissue necrosis", "A peripheral IV in the hand for at least 24 hours before central access", "Intramuscular injection", "Oral route once the patient is hemodynamically stable"]'::jsonb, 0, 'Vasopressors are potent vasoconstrictors that can cause severe tissue ischemia/necrosis if extravasated peripherally, so central venous administration is preferred whenever feasible.', 'Pre-Council', '🎓', true),
(7597, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'In treating a hypertensive emergency, a generally safe target for initial blood pressure reduction is:', '["Reduce mean arterial pressure by no more than 25% within the first hour", "Normalize blood pressure to less than 120/80 mmHg within 15 minutes", "Reduce blood pressure by 50% within the first 30 minutes", "There is no need to control the rate of blood pressure reduction"]'::jsonb, 0, 'Rapid, excessive blood pressure reduction can cause organ hypoperfusion; guidelines generally recommend lowering MAP by no more than about 25% in the first hour, then more gradual reduction thereafter.', 'Pre-Council', '🎓', true),
(7598, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Sodium nitroprusside lowers blood pressure through:', '["Direct arterial and venous vasodilation via release of nitric oxide", "Selective venodilation only", "Beta-1 receptor blockade", "Inhibition of the renin-angiotensin system"]'::jsonb, 0, 'Nitroprusside releases nitric oxide, activating guanylate cyclase to increase cGMP in both arterial and venous smooth muscle, causing balanced vasodilation with rapid onset and offset.', 'Pre-Council', '🎓', true),
(7599, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'A patient on a high-dose, prolonged sodium nitroprusside infusion develops altered mental status and unexplained metabolic acidosis. This should raise suspicion for:', '["Cyanide toxicity from accumulation of nitroprusside metabolites", "Serotonin syndrome", "Malignant hyperthermia", "Digoxin toxicity"]'::jsonb, 0, 'Nitroprusside is metabolized to cyanide, normally converted to thiocyanate by the liver; prolonged high-dose infusions or hepatic/renal impairment can cause cyanide accumulation, presenting with metabolic acidosis and altered mental status; treatment includes sodium thiosulfate or hydroxocobalamin.', 'Pre-Council', '🎓', true),
(7600, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'At low infusion doses, nitroglycerin primarily causes:', '["Venodilation, reducing preload", "Arterial vasodilation, reducing afterload", "Coronary vasospasm", "Pulmonary vasoconstriction"]'::jsonb, 0, 'At lower doses, nitroglycerin predominantly dilates veins, reducing venous return (preload) and myocardial oxygen demand; higher doses also produce arterial dilation.', 'Pre-Council', '🎓', true),
(7601, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Nitroglycerin should not be given to a patient who has recently taken:', '["Sildenafil or another phosphodiesterase-5 inhibitor, due to risk of severe, refractory hypotension", "Acetaminophen", "A statin", "An oral antibiotic"]'::jsonb, 0, 'Concurrent nitrates and PDE-5 inhibitors cause profound, potentially life-threatening hypotension due to excessive additive cGMP-mediated vasodilation; nitrates should be avoided for 24-48 hours after PDE-5 inhibitor use.', 'Pre-Council', '🎓', true),
(7602, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'A patient on continuous nitroglycerin infusion for several days develops reduced antianginal effect at the same dose. This is best explained by:', '["Nitrate tolerance, which may be reduced by allowing a nitrate-free interval", "Development of a true drug allergy", "Cyanide toxicity", "Increased renal clearance of nitroglycerin"]'::jsonb, 0, 'Continuous nitrate exposure leads to tolerance, thought to relate to depletion of sulfhydryl groups needed for nitric oxide generation; intermittent dosing or a nitrate-free interval can help restore responsiveness.', 'Pre-Council', '🎓', true),
(7603, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Fenoldopam is a useful antihypertensive agent in patients with renal insufficiency because it:', '["Is a selective dopamine-1 receptor agonist that causes renal as well as systemic vasodilation", "Is a potent nephrotoxin that requires renal monitoring", "Works by inhibiting the renin-angiotensin-aldosterone system", "Is contraindicated in any degree of renal impairment"]'::jsonb, 0, 'Fenoldopam selectively activates dopamine-1 receptors, producing systemic vasodilation while maintaining or increasing renal blood flow, making it useful in hypertensive emergencies with renal compromise.', 'Pre-Council', '🎓', true),
(7604, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Phentolamine''s mechanism of action, which makes it useful for treating vasopressor extravasation and pheochromocytoma-related hypertensive crises, is:', '["Nonselective alpha-adrenergic receptor antagonism", "Selective beta-1 receptor antagonism", "Direct nitric oxide donation", "Calcium channel blockade"]'::jsonb, 0, 'Phentolamine is a nonselective alpha-adrenergic antagonist that reverses alpha-1 mediated vasoconstriction, useful both for infiltrating extravasated vasopressors and for treating catecholamine-excess hypertensive crises.', 'Pre-Council', '🎓', true),
(7605, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Sildenafil is used in pulmonary arterial hypertension because, as a PDE-5 inhibitor, it:', '["Increases cGMP levels in pulmonary vascular smooth muscle, producing pulmonary vasodilation", "Blocks endothelin receptors directly", "Increases systemic vascular resistance to improve right ventricular perfusion", "Inhibits nitric oxide synthase"]'::jsonb, 0, 'By inhibiting phosphodiesterase-5, sildenafil prevents breakdown of cGMP generated by nitric oxide, prolonging pulmonary vasodilation and reducing pulmonary vascular resistance.', 'Pre-Council', '🎓', true),
(7606, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Compared to hydralazine, nicardipine causes less reflex tachycardia mainly because it:', '["Produces smoother, more gradual vasodilation with less abrupt drop in systemic vascular resistance", "Has intrinsic beta-blocking activity that blunts the reflex", "Directly slows the sinoatrial node", "Is a venodilator rather than an arterial dilator"]'::jsonb, 0, 'Nicardipine''s more gradual, titratable arterial vasodilation produces a less abrupt baroreceptor-mediated reflex than hydralazine''s more unpredictable, sudden vasodilation.', 'Pre-Council', '🎓', true),
(7607, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Nesiritide, used in acute decompensated heart failure, is:', '["A recombinant human B-type natriuretic peptide that causes vasodilation and natriuresis", "A synthetic ACE inhibitor", "A calcium channel blocker", "A beta-1 agonist"]'::jsonb, 0, 'Nesiritide is recombinant BNP that promotes venous and arterial vasodilation along with natriuresis/diuresis, though its use has declined due to concerns about hypotension and renal effects without clear mortality benefit.', 'Pre-Council', '🎓', true),
(7608, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'In acute cardiogenic pulmonary edema, morphine has historically been used because it:', '["Produces venodilation, reducing preload, along with reducing anxiety-driven sympathetic tone", "Is a potent arterial vasodilator that significantly reduces afterload", "Directly increases myocardial contractility", "Increases respiratory drive"]'::jsonb, 0, 'Morphine reduces venous tone (preload) and anxiety; though historically used in pulmonary edema, current evidence has raised concerns about worse outcomes, so routine use has declined in favor of more targeted vasodilators/diuretics.', 'Pre-Council', '🎓', true),
(7609, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Hydralazine is commonly used to treat severe hypertension in pregnancy (e.g., preeclampsia) because it:', '["Directly relaxes arteriolar smooth muscle without significantly reducing uteroplacental blood flow", "Crosses into breast milk causing no fetal risk", "Has no effect on maternal heart rate", "Is contraindicated in all pregnant patients"]'::jsonb, 0, 'Hydralazine is a direct arteriolar vasodilator with a long history of safe use in pregnancy-related hypertensive emergencies, though maternal reflex tachycardia and fetal heart rate should be monitored.', 'Pre-Council', '🎓', true),
(7610, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'A key nursing/pharmacy consideration for sodium nitroprusside infusions is that the drug:', '["Degrades when exposed to light and should be protected with an opaque covering", "Must be administered orally for full effect", "Is stable at room temperature for weeks once mixed", "Requires no special protection from light or temperature"]'::jsonb, 0, 'Nitroprusside solutions are light-sensitive and degrade with light exposure, so the bag and tubing should be wrapped in opaque material during infusion.', 'Pre-Council', '🎓', true),
(7611, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'N-acetylcysteine acts as a mucolytic by:', '["Breaking disulfide bonds within mucoprotein complexes via its free sulfhydryl group, reducing sputum viscosity", "Increasing ciliary beat frequency directly", "Osmotically drawing water into the airway lumen", "Digesting extracellular DNA released by neutrophils"]'::jsonb, 0, 'NAC''s free sulfhydryl group cleaves disulfide bonds that cross-link mucoprotein, thinning tenacious secretions and making them easier to clear.', 'Pre-Council', '🎓', true),
(7612, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Besides its mucolytic action, N-acetylcysteine is also used as an antidote in:', '["Paracetamol (acetaminophen) overdose, by replenishing glutathione stores to detoxify the toxic metabolite NAPQI", "Opioid overdose", "Benzodiazepine overdose", "Aspirin overdose"]'::jsonb, 0, 'NAC replenishes hepatic glutathione, which conjugates and detoxifies NAPQI, the hepatotoxic metabolite of acetaminophen, preventing or limiting liver injury.', 'Pre-Council', '🎓', true),
(7613, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'A patient with a history of asthma receiving nebulized acetylcysteine should be monitored closely for:', '["Bronchospasm", "Hypertension", "Hyperkalemia", "Serotonin syndrome"]'::jsonb, 0, 'Acetylcysteine can irritate the airway and precipitate bronchospasm, particularly in patients with reactive airway disease; a bronchodilator should be available or co-administered.', 'Pre-Council', '🎓', true),
(7614, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'A common patient complaint that may reduce adherence with nebulized acetylcysteine is:', '["A strong rotten-egg (sulfur) odor that can cause nausea", "A sweet fruity smell", "Complete absence of taste or odor", "A metallic taste only, with no smell"]'::jsonb, 0, 'Acetylcysteine has a characteristic sulfurous, rotten-egg odor due to its sulfhydryl group, which can cause nausea or reluctance to use the nebulizer.', 'Pre-Council', '🎓', true),
(7615, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Dornase alfa (recombinant human DNase) reduces sputum viscosity in cystic fibrosis by:', '["Cleaving extracellular DNA released from degraded neutrophils in purulent secretions", "Breaking disulfide bonds in mucoproteins", "Osmotically hydrating respiratory secretions", "Stimulating goblet cell mucus production"]'::jsonb, 0, 'In infected/inflamed airways, degenerating neutrophils release large amounts of DNA that increase sputum viscosity; dornase alfa enzymatically cleaves this DNA, thinning secretions.', 'Pre-Council', '🎓', true),
(7616, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Nebulized hypertonic saline aids secretion clearance primarily through:', '["An osmotic effect that draws water into the airway surface liquid, rehydrating and thinning mucus", "Direct dissolution of disulfide bonds", "Enzymatic digestion of mucus glycoproteins", "Beta-2 receptor stimulation"]'::jsonb, 0, 'Hypertonic saline osmotically draws fluid into the airway lumen, improving mucus hydration and mucociliary clearance, though it can trigger cough or bronchospasm.', 'Pre-Council', '🎓', true),
(7617, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'After administering a mucolytic agent, the nurse should anticipate the need for:', '["Airway clearance techniques such as suctioning or chest physiotherapy, since loosened secretions still require active removal", "Immediate extubation", "Withholding all oral intake for 24 hours", "Discontinuing supplemental oxygen"]'::jsonb, 0, 'Mucolytics loosen and liquefy secretions but do not remove them; effective secretion clearance still requires suctioning, coughing, or chest physiotherapy afterward.', 'Pre-Council', '🎓', true),
(7618, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'During the IV loading dose of N-acetylcysteine for paracetamol overdose, a patient develops flushing, urticaria, and mild wheeze. This anaphylactoid reaction is best managed by:', '["Slowing the infusion rate and treating symptoms, since it is typically a non-IgE-mediated histamine reaction rather than true anaphylaxis", "Immediately and permanently discontinuing NAC therapy", "Doubling the infusion rate to complete dosing faster", "Switching to oral acetylcysteine only, with no further monitoring"]'::jsonb, 0, 'Anaphylactoid reactions to IV NAC are common, dose/rate related, and usually managed by slowing or briefly pausing the infusion and treating symptoms, rather than permanently stopping this life-saving antidote.', 'Pre-Council', '🎓', true),
(7619, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'The key pharmacologic difference between a mucolytic and a bronchodilator is that a mucolytic:', '["Reduces the viscosity of respiratory secretions, whereas a bronchodilator relaxes airway smooth muscle to widen the airway lumen", "Relaxes bronchial smooth muscle, whereas a bronchodilator thins mucus", "Works by an identical receptor mechanism to bronchodilators", "Always also produces bronchodilation as its primary action"]'::jsonb, 0, 'Mucolytics act on the physical/chemical properties of mucus to make it less viscous and easier to clear, while bronchodilators act on airway smooth muscle tone; the two classes are often used together but work by distinct mechanisms.', 'Pre-Council', '🎓', true),
(7620, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Salbutamol (albuterol) relieves bronchospasm by:', '["Stimulating beta-2 adrenergic receptors, increasing cAMP and relaxing bronchial smooth muscle", "Blocking muscarinic receptors on airway smooth muscle", "Inhibiting phosphodiesterase-3 in the myocardium", "Stabilizing mast cell membranes to prevent histamine release"]'::jsonb, 0, 'Salbutamol is a short-acting beta-2 agonist; receptor stimulation increases intracellular cAMP, leading to bronchial smooth muscle relaxation.', 'Pre-Council', '🎓', true),
(7621, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'A common metabolic adverse effect of beta-2 agonist therapy such as salbutamol is:', '["Hypokalemia, due to intracellular shifting of potassium via stimulation of the Na-K-ATPase pump", "Hyperkalemia", "Hypernatremia", "Hypercalcemia"]'::jsonb, 0, 'Beta-2 stimulation activates the Na-K-ATPase pump, driving potassium intracellularly and lowering serum potassium; this is also why beta-2 agonists like salbutamol are used to treat hyperkalemia.', 'Pre-Council', '🎓', true),
(7622, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Ipratropium bromide produces bronchodilation by:', '["Blocking muscarinic acetylcholine receptors in the airway, reducing cholinergic-mediated bronchoconstriction and secretions", "Stimulating beta-2 receptors", "Inhibiting leukotriene synthesis", "Blocking histamine H1 receptors"]'::jsonb, 0, 'Ipratropium is an anticholinergic (antimuscarinic) that blocks vagally mediated bronchoconstriction and reduces mucus secretion; it has a slower onset than short-acting beta-2 agonists.', 'Pre-Council', '🎓', true),
(7623, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'A patient on IV aminophylline should have serum theophylline levels monitored because:', '["It has a narrow therapeutic index (roughly 10-20 mcg/mL), and toxicity can cause nausea, seizures, and arrhythmias", "It has an extremely wide therapeutic index with no need for monitoring", "Toxicity presents only as mild drowsiness", "It is not metabolized and therefore accumulates predictably"]'::jsonb, 0, 'Theophylline has a narrow therapeutic window; levels above the therapeutic range can cause serious toxicity including seizures and life-threatening arrhythmias, so monitoring is essential.', 'Pre-Council', '🎓', true),
(7624, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Which of the following is most likely to increase serum theophylline levels and precipitate toxicity?', '["Concurrent ciprofloxacin or erythromycin, which inhibit theophylline''s hepatic (CYP450) metabolism", "Concurrent cigarette smoking", "Concurrent phenytoin therapy", "Concurrent rifampin therapy"]'::jsonb, 0, 'Ciprofloxacin and macrolides such as erythromycin inhibit CYP1A2, reducing theophylline clearance and raising serum levels, while smoking, phenytoin, and rifampin are enzyme inducers that tend to lower theophylline levels.', 'Pre-Council', '🎓', true),
(7625, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'IV magnesium sulfate may be used as an adjunct in severe asthma exacerbation refractory to beta-agonists because it:', '["Produces bronchial smooth muscle relaxation via calcium channel antagonism", "Directly stimulates beta-2 receptors", "Reverses mucus plugging enzymatically", "Acts as a potent anticholinergic"]'::jsonb, 0, 'Magnesium acts as a smooth muscle relaxant partly through calcium channel antagonism, providing additional bronchodilation in patients with severe exacerbations not responding adequately to standard bronchodilators.', 'Pre-Council', '🎓', true),
(7626, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Combining albuterol and ipratropium in a single nebulizer treatment is beneficial because:', '["The two drugs act on different receptor pathways (beta-2 agonism and anticholinergic blockade), producing synergistic bronchodilation", "Ipratropium potentiates renal clearance of albuterol", "Combining the two eliminates the need for corticosteroids", "The combination has no additional benefit over either drug alone"]'::jsonb, 0, 'Because albuterol and ipratropium act through distinct mechanisms, their combination produces greater bronchodilation than either agent alone in acute exacerbations.', 'Pre-Council', '🎓', true),
(7627, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Terbutaline may be used subcutaneously in a patient with severe bronchospasm who cannot effectively use a nebulizer because it:', '["Is a beta-2 agonist that can be administered parenterally when inhaled therapy is not feasible", "Is an anticholinergic agent with a long duration of action", "Works only via inhalation and has no parenteral form", "Is a corticosteroid with rapid onset"]'::jsonb, 0, 'Terbutaline is a beta-2 agonist available for subcutaneous administration, providing systemic bronchodilation when inhaled delivery is impractical or ineffective.', 'Pre-Council', '🎓', true),
(7628, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Nebulized racemic epinephrine is used in croup or post-extubation stridor primarily to:', '["Cause mucosal vasoconstriction via alpha-adrenergic effect, reducing airway edema", "Provide long-term anti-inflammatory control", "Directly paralyze the vocal cords", "Sedate the patient to reduce airway irritability"]'::jsonb, 0, 'Racemic epinephrine''s alpha-adrenergic vasoconstrictive effect reduces mucosal edema in the upper airway, rapidly improving airflow; effects are temporary, and rebound edema is possible, requiring observation after use.', 'Pre-Council', '🎓', true),
(7629, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Salmeterol, a long-acting beta-2 agonist, is inappropriate for acute bronchospasm rescue because:', '["It has a slower onset of action compared to short-acting agents like salbutamol and is intended for maintenance therapy", "It has no bronchodilator activity at all", "It causes immediate bronchoconstriction", "It cannot be combined with inhaled corticosteroids"]'::jsonb, 0, 'LABAs such as salmeterol have a delayed onset relative to SABAs and are used for maintenance/prevention of bronchospasm, not for acute rescue therapy.', 'Pre-Council', '🎓', true),
(7630, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Beta-2 agonist bronchodilators should be used cautiously in patients with ischemic heart disease because they can cause:', '["Tachyarrhythmias due to some cross-reactivity with beta-1 receptors, increasing myocardial oxygen demand", "Severe bradycardia", "Coronary vasospasm exclusively", "Complete heart block"]'::jsonb, 0, 'Beta-2 agonists have some beta-1 cross-reactivity, particularly at higher doses, which can increase heart rate and myocardial oxygen demand, a concern in patients with underlying cardiac ischemia.', 'Pre-Council', '🎓', true),
(7631, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'In a mechanically ventilated ICU patient, delivering salbutamol via a metered-dose inhaler with an inline spacer/adapter is generally preferred over a small-volume nebulizer because it:', '["Is equally effective when administered correctly, with less risk of ventilator circuit contamination", "Delivers a substantially higher total dose of medication", "Cannot be used safely in ventilated patients", "Requires disconnecting the ventilator circuit for each dose"]'::jsonb, 0, 'When actuated correctly with proper technique and timing, MDIs with an in-line adapter deliver comparable clinical effect to nebulizers in ventilated patients while reducing circuit disconnections and contamination risk.', 'Pre-Council', '🎓', true),
(7632, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Before giving an IV aminophylline loading dose, the nurse/prescriber should confirm whether the patient is already taking oral theophylline, because:', '["Giving a full loading dose on top of existing therapy risks theophylline toxicity", "Oral theophylline has no cross-reactivity with IV aminophylline", "A loading dose is never needed regardless of prior therapy", "Aminophylline cannot be given to any patient on oral theophylline"]'::jsonb, 0, 'Aminophylline is metabolized to theophylline; giving a standard loading dose to a patient already on theophylline therapy can result in supratherapeutic, toxic levels, so the loading dose should be adjusted or omitted.', 'Pre-Council', '🎓', true),
(7633, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Propofol produces sedation and hypnosis primarily through:', '["Potentiation of GABA-A receptor-mediated chloride influx", "NMDA receptor antagonism", "Alpha-2 adrenergic receptor agonism", "Mu-opioid receptor agonism"]'::jsonb, 0, 'Propofol enhances GABA-A receptor activity, increasing chloride channel opening and neuronal hyperpolarization, producing rapid-onset, short-duration sedation/hypnosis due to its high lipophilicity.', 'Pre-Council', '🎓', true),
(7634, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Adverse effects commonly associated with propofol infusion include:', '["Hypotension, pain on injection, and hypertriglyceridemia with prolonged use", "Hypertension and bronchospasm", "QT shortening and hyperglycemia", "Malignant hyperthermia in all patients"]'::jsonb, 0, 'Propofol causes dose-dependent hypotension, injection-site pain, and because it is formulated in a lipid emulsion, hypertriglyceridemia can occur with prolonged infusions requiring triglyceride monitoring.', 'Pre-Council', '🎓', true),
(7635, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Propofol infusion syndrome (PRIS) is a rare but life-threatening complication associated with:', '["High-dose, prolonged infusion, presenting with metabolic acidosis, rhabdomyolysis, hyperkalemia, and cardiac failure", "A single small bolus dose in a healthy adult", "Short-term use for procedural sedation only", "Oral propofol administration"]'::jsonb, 0, 'PRIS typically occurs with high-dose (>4 mg/kg/hr) infusions lasting more than 48 hours, presenting with severe metabolic acidosis, rhabdomyolysis, hyperkalemia, cardiac and renal failure; it carries high mortality if unrecognized.', 'Pre-Council', '🎓', true),
(7636, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Midazolam differs from other benzodiazepines used for ICU sedation in that it:', '["Is lipophilic at physiologic pH with an active metabolite that can accumulate in renal failure, prolonging sedation", "Has no active metabolites of any kind", "Cannot be given by continuous infusion", "Has the longest onset of action of any benzodiazepine"]'::jsonb, 0, 'Midazolam becomes lipophilic at physiologic pH, allowing rapid CNS entry; its active metabolite alpha-hydroxymidazolam is renally cleared and can accumulate in renal impairment, prolonging sedative effect.', 'Pre-Council', '🎓', true),
(7637, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Dexmedetomidine produces sedation through:', '["Selective agonism of central alpha-2 adrenergic receptors, reducing sympathetic outflow", "GABA-A receptor potentiation", "NMDA receptor blockade", "Beta-1 receptor blockade"]'::jsonb, 0, 'Dexmedetomidine is a selective alpha-2 agonist acting in the locus coeruleus to produce sedation resembling natural sleep, with concurrent analgesic and sympatholytic effects, and comparatively little respiratory depression.', 'Pre-Council', '🎓', true),
(7638, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'A key hemodynamic adverse effect to monitor for during dexmedetomidine infusion is:', '["Bradycardia and hypotension", "Severe tachycardia and hypertension", "QT prolongation with torsades de pointes", "Profound respiratory depression"]'::jsonb, 0, 'Dexmedetomidine''s central sympatholytic effect commonly causes dose-related bradycardia and hypotension; rapid bolus administration increases this risk and is generally avoided.', 'Pre-Council', '🎓', true),
(7639, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'A notable advantage of dexmedetomidine over propofol or benzodiazepines for ICU sedation is that it:', '["Allows patients to remain arousable and cooperative with minimal respiratory depression", "Produces the deepest level of sedation available", "Has no cardiovascular effects", "Is the fastest-acting sedative available for rapid sequence intubation"]'::jsonb, 0, 'Dexmedetomidine provides cooperative sedation, where patients can be aroused and interact, with minimal impact on respiratory drive, making it useful for spontaneous breathing trials and lighter sedation goals.', 'Pre-Council', '🎓', true),
(7640, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Using a validated tool such as the Richmond Agitation-Sedation Scale (RASS) with daily sedation interruption in mechanically ventilated patients is associated with:', '["Reduced duration of mechanical ventilation and ICU length of stay", "Increased risk of self-extubation with no other benefit", "No measurable clinical benefit", "Increased need for neuromuscular blockade"]'::jsonb, 0, 'Targeted, lighter sedation guided by RASS with daily interruption reduces oversedation, shortening duration of mechanical ventilation and ICU stay, and lowering delirium risk.', 'Pre-Council', '🎓', true),
(7641, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Prolonged high-dose lorazepam infusion carries a risk of toxicity from its diluent, which can cause:', '["Propylene glycol accumulation leading to metabolic acidosis, acute kidney injury, and a widened osmolar gap", "Cyanide toxicity", "Serotonin syndrome", "Malignant hyperthermia"]'::jsonb, 0, 'Lorazepam (and diazepam) IV formulations are dissolved in propylene glycol; prolonged high-dose infusions can lead to propylene glycol accumulation, causing an elevated osmolar gap, metabolic acidosis, and renal injury.', 'Pre-Council', '🎓', true),
(7642, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Ketamine produces dissociative sedation and analgesia by:', '["Antagonizing NMDA glutamate receptors", "Agonizing GABA-A receptors", "Blocking voltage-gated sodium channels", "Agonizing mu-opioid receptors exclusively"]'::jsonb, 0, 'Ketamine is an NMDA receptor antagonist that produces a dissociative state with both analgesic and sedative properties, while generally preserving airway reflexes, respiratory drive, and hemodynamic stability, making it useful in hemodynamically unstable patients.', 'Pre-Council', '🎓', true),
(7643, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'A well-known adverse effect of ketamine that can be reduced by co-administering a benzodiazepine is:', '["Emergence reaction, characterized by hallucinations or dysphoria on awakening", "Profound hypotension", "Malignant hyperthermia", "Irreversible respiratory arrest"]'::jsonb, 0, 'Ketamine can cause emergence phenomena (vivid dreams, hallucinations, agitation) as its effects wane; co-administering a benzodiazepine can reduce the incidence and severity of this reaction.', 'Pre-Council', '🎓', true),
(7644, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Etomidate is often chosen for rapid sequence induction in hemodynamically unstable patients because of its hemodynamic stability, but a key concern with even a single dose is:', '["Transient adrenal suppression via inhibition of 11-beta-hydroxylase", "Severe, prolonged hypotension", "Malignant hyperthermia", "Irreversible hepatotoxicity"]'::jsonb, 0, 'Etomidate inhibits 11-beta-hydroxylase, an enzyme in cortisol synthesis, causing transient adrenal suppression even after a single induction dose; this is a particular concern in septic patients, where relative adrenal insufficiency may already be present.', 'Pre-Council', '🎓', true),
(7645, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'High-dose barbiturate therapy (e.g., pentobarbital) may be used in refractory intracranial hypertension because it:', '["Reduces cerebral metabolic rate and cerebral blood flow, lowering intracranial pressure", "Increases cerebral metabolic demand to promote healing", "Has no effect on hemodynamics, making it very safe", "Is used specifically to treat malignant hyperthermia"]'::jsonb, 0, 'Barbiturates suppress cerebral metabolic rate for oxygen, reducing cerebral blood flow and intracranial pressure, but carry significant risk of profound hypotension, myocardial depression, and immunosuppression, requiring intensive hemodynamic support.', 'Pre-Council', '🎓', true),
(7646, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Current ICU sedation guidelines generally favor propofol or dexmedetomidine over benzodiazepine infusions for most mechanically ventilated adults primarily because benzodiazepines are associated with:', '["Higher rates of ICU delirium", "Faster awakening times", "Lower cost and easier titration", "Reduced risk of hypotension"]'::jsonb, 0, 'Benzodiazepine-based sedation has been associated with higher rates of ICU delirium and longer time to extubation compared with propofol or dexmedetomidine, leading current guidelines to favor non-benzodiazepine sedation strategies where feasible.', 'Pre-Council', '🎓', true),
(7647, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Abruptly discontinuing a prolonged continuous infusion of midazolam and fentanyl in a critically ill patient risks:', '["A withdrawal syndrome with agitation, tachycardia, and potentially seizures", "No clinical consequence, since these drugs have no dependence potential", "Immediate return of full consciousness with no other effects", "Hypoglycemia"]'::jsonb, 0, 'Prolonged sedative/analgesic infusions can produce physical dependence; abrupt cessation can precipitate withdrawal (agitation, tachycardia, hypertension, tremor, seizures), so gradual tapering is recommended.', 'Pre-Council', '🎓', true),
(7648, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Propofol should be used with particular caution in patients with:', '["Disorders of lipid metabolism or significant hemodynamic instability", "Well-controlled hypertension only", "Mild seasonal allergies", "A history of opioid use disorder"]'::jsonb, 0, 'Because propofol is formulated in a lipid emulsion and causes vasodilation with negative inotropy, caution is warranted in patients with lipid metabolism disorders or those who are hemodynamically unstable, where hypotension could be poorly tolerated.', 'Pre-Council', '🎓', true),
(7649, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Haloperidol, sometimes used for ICU agitation associated with delirium, differs from true sedative-hypnotic agents in that it:', '["Is an antipsychotic that manages symptoms of delirium rather than functioning as a primary sedative, and requires QT interval monitoring", "Is a benzodiazepine derivative used first-line for anxiolysis", "Has no cardiac monitoring requirements", "Is the preferred agent for routine procedural sedation"]'::jsonb, 0, 'Haloperidol is a first-generation antipsychotic used to manage agitation associated with delirium rather than as primary sedation, and it carries a risk of QT prolongation and torsades de pointes, requiring ECG monitoring.', 'Pre-Council', '🎓', true),
(7650, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Succinylcholine produces rapid neuromuscular blockade by:', '["Binding nicotinic acetylcholine receptors and causing sustained depolarization of the motor endplate", "Competitively blocking acetylcholine at nicotinic receptors without depolarizing the membrane", "Inhibiting acetylcholinesterase at the neuromuscular junction", "Blocking presynaptic calcium channels to prevent acetylcholine release"]'::jsonb, 0, 'Succinylcholine is a depolarizing neuromuscular blocker that mimics acetylcholine, binding nicotinic receptors and causing sustained depolarization because it is not rapidly hydrolyzed like endogenous acetylcholine.', 'Pre-Council', '🎓', true),
(7651, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Succinylcholine should be avoided in a patient who is 5 days post-major burn injury primarily because of the risk of:', '["Life-threatening hyperkalemia due to upregulation of extrajunctional acetylcholine receptors", "Malignant hypothermia", "Profound hypoglycemia", "Severe hypotension unrelated to potassium"]'::jsonb, 0, 'Burns, crush injuries, denervation, and prolonged immobilization cause proliferation of extrajunctional nicotinic receptors; succinylcholine-induced depolarization at these receptors can cause massive potassium efflux and life-threatening hyperkalemia.', 'Pre-Council', '🎓', true),
(7652, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'A patient develops rapidly rising temperature, severe muscle rigidity, tachycardia, and hypercarbia shortly after receiving succinylcholine. The priority treatment is:', '["Dantrolene, which reduces calcium release from the sarcoplasmic reticulum", "Naloxone", "Neostigmine", "Flumazenil"]'::jsonb, 0, 'This presentation is consistent with malignant hyperthermia; dantrolene antagonizes ryanodine receptors, reducing calcium release from the sarcoplasmic reticulum and reversing the hypermetabolic state, alongside discontinuing the trigger and active cooling.', 'Pre-Council', '🎓', true),
(7653, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Rocuronium is frequently chosen for rapid sequence intubation because it:', '["Is a nondepolarizing neuromuscular blocker with a relatively fast onset at higher doses, without the hyperkalemia risk of succinylcholine", "Is a depolarizing agent with the fastest onset of any neuromuscular blocker", "Has no reversal agent available", "Produces bronchospasm as its primary therapeutic effect"]'::jsonb, 0, 'Rocuronium is a nondepolarizing (competitive) neuromuscular blocker; at higher intubating doses it achieves onset nearly as fast as succinylcholine while avoiding the hyperkalemia risk, making it useful for RSI when succinylcholine is contraindicated.', 'Pre-Council', '🎓', true),
(7654, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Cisatracurium is often preferred in patients with renal or hepatic failure because it:', '["Undergoes Hofmann elimination, a spontaneous, organ-independent degradation process", "Is exclusively metabolized by the kidneys", "Requires hepatic conjugation for elimination", "Has no metabolism and is excreted unchanged in bile"]'::jsonb, 0, 'Cisatracurium degrades via Hofmann elimination (a pH- and temperature-dependent, non-enzymatic process) independent of renal or hepatic function, making its clearance more predictable in organ failure.', 'Pre-Council', '🎓', true),
(7655, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Traditional reversal of nondepolarizing neuromuscular blockade is achieved with neostigmine combined with glycopyrrolate because:', '["Neostigmine inhibits acetylcholinesterase to increase acetylcholine at the neuromuscular junction, while glycopyrrolate offsets resulting muscarinic side effects like bradycardia and secretions", "Glycopyrrolate directly reverses the neuromuscular blockade", "Neostigmine has no cholinergic side effects requiring co-administration", "The combination is used only to reverse depolarizing blockade"]'::jsonb, 0, 'Neostigmine increases synaptic acetylcholine to competitively overcome nondepolarizing blockade, but this also causes unwanted muscarinic effects; glycopyrrolate is co-administered to blunt these effects.', 'Pre-Council', '🎓', true),
(7656, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Sugammadex reverses neuromuscular blockade from rocuronium or vecuronium by:', '["Encapsulating the steroidal neuromuscular blocking molecule, forming an inactive complex that is renally excreted", "Inhibiting acetylcholinesterase", "Competing with acetylcholine at nicotinic receptors", "Directly stimulating the motor endplate"]'::jsonb, 0, 'Sugammadex is a modified gamma-cyclodextrin that selectively encapsulates rocuronium or vecuronium, rapidly reversing blockade; it is not effective against succinylcholine or benzylisoquinolinium agents such as cisatracurium.', 'Pre-Council', '🎓', true),
(7657, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Train-of-four (TOF) peripheral nerve stimulation is used in ICU patients receiving continuous neuromuscular blockade to:', '["Assess the depth of neuromuscular blockade and guide titration of the paralytic infusion", "Measure the patient''s level of consciousness", "Replace the need for sedation monitoring entirely", "Directly measure serum drug levels"]'::jsonb, 0, 'TOF monitoring quantifies the degree of neuromuscular blockade by counting twitch responses to a series of electrical stimuli, helping avoid over- or under-paralysis and guiding safe titration of the infusion.', 'Pre-Council', '🎓', true),
(7658, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'The most critical nursing safety consideration when a patient is receiving a continuous neuromuscular blocking agent infusion is that:', '["The drug has no sedative or analgesic properties, so adequate concurrent sedation and analgesia must always be ensured", "Neuromuscular blockers eliminate the need for any sedation", "Vital sign monitoring becomes unnecessary once paralysis is achieved", "The patient can be safely left without ventilatory support as blockade wears off"]'::jsonb, 0, 'Neuromuscular blocking agents produce paralysis without any effect on consciousness, pain perception, or anxiety; without adequate concurrent sedation and analgesia, a paralyzed patient could be awake, aware, and in pain while unable to communicate.', 'Pre-Council', '🎓', true),
(7659, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Succinylcholine is contraindicated in a patient with a personal or family history of:', '["Malignant hyperthermia", "Seasonal allergic rhinitis", "Migraine headaches", "Mild intermittent asthma"]'::jsonb, 0, 'Patients with a personal or family history of malignant hyperthermia are at high risk of a life-threatening hypermetabolic reaction if given succinylcholine (or volatile anesthetics), so it is absolutely contraindicated.', 'Pre-Council', '🎓', true),
(7660, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Prolonged use of neuromuscular blocking agents, particularly when combined with high-dose corticosteroids, increases the risk of:', '["ICU-acquired weakness/critical illness myopathy", "Malignant hyperthermia", "Serotonin syndrome", "Red man syndrome"]'::jsonb, 0, 'Prolonged neuromuscular blockade, especially combined with corticosteroids, sepsis, and immobility, is a recognized risk factor for ICU-acquired weakness and critical illness myopathy.', 'Pre-Council', '🎓', true),
(7661, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'A characteristic feature of pancuronium that distinguishes it from other nondepolarizing neuromuscular blockers is its:', '["Vagolytic effect, which can cause tachycardia, along with a longer duration of action", "Extremely short duration of action", "Complete lack of cardiovascular effects", "Metabolism exclusively via Hofmann elimination"]'::jsonb, 0, 'Pancuronium has vagolytic (antimuscarinic) properties that can cause tachycardia and is a long-acting nondepolarizing agent primarily eliminated renally.', 'Pre-Council', '🎓', true),
(7662, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'With repeated or prolonged dosing of succinylcholine, the neuromuscular block can convert from a typical depolarizing (Phase I) block to a:', '["Phase II block that resembles a nondepolarizing block and can be more difficult to manage", "Complete absence of any neuromuscular blockade", "Permanent, irreversible paralysis", "Block that is immediately reversed by additional succinylcholine"]'::jsonb, 0, 'Repeated or prolonged succinylcholine exposure can cause the endplate to become desensitized, producing a Phase II block with characteristics resembling nondepolarizing blockade, which can complicate recovery.', 'Pre-Council', '🎓', true),
(7663, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'A short course of continuous cisatracurium infusion may be used in a patient with severe ARDS and ventilator dyssynchrony because it can:', '["Reduce oxygen consumption and improve ventilator synchrony/lung compliance in carefully selected patients", "Cure the underlying lung injury", "Eliminate the need for any sedation", "Be safely continued indefinitely with no monitoring"]'::jsonb, 0, 'In select patients with severe ARDS, brief neuromuscular blockade can reduce patient-ventilator dyssynchrony and oxygen consumption, potentially improving oxygenation, though it requires close monitoring given the risks of prolonged paralysis.', 'Pre-Council', '🎓', true),
(7664, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Because a deeply paralyzed patient cannot exhibit typical behavioral signs of pain or awareness, the nurse should rely on which additional strategy to help detect inadequate sedation/analgesia?', '["Monitoring trends in heart rate and blood pressure, and considering processed EEG (e.g., BIS) monitoring", "Asking the patient directly and waiting for a verbal response", "Assuming no sedation is needed once paralysis is confirmed", "Relying solely on the neuromuscular blocking agent''s dose as an indicator of comfort"]'::jsonb, 0, 'Since paralyzed patients cannot move or verbally respond, indirect indicators such as rising heart rate/blood pressure or processed EEG monitoring can help detect inadequate sedation or analgesia and reduce the risk of unrecognized patient awareness.', 'Pre-Council', '🎓', true),
(7665, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Benzodiazepines produce anxiolysis, sedation, and anticonvulsant effects by:', '["Increasing the frequency of GABA-A receptor chloride channel opening, enhancing inhibitory neurotransmission", "Directly opening chloride channels independent of GABA", "Blocking GABA-A receptors", "Stimulating alpha-2 adrenergic receptors"]'::jsonb, 0, 'Benzodiazepines bind an allosteric site on the GABA-A receptor, increasing the frequency of chloride channel opening in the presence of GABA, which enhances inhibitory neurotransmission throughout the CNS.', 'Pre-Council', '🎓', true),
(7666, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Compared with lorazepam, diazepam has:', '["Greater lipophilicity and active metabolites that prolong its clinical effect, especially with repeated dosing", "No active metabolites and is preferred in hepatic impairment", "A substantially longer time to onset of action", "No CNS depressant effect"]'::jsonb, 0, 'Diazepam is highly lipophilic with rapid CNS penetration and has active metabolites with long half-lives, leading to prolonged and unpredictable effects, particularly with repeated dosing or hepatic impairment, unlike lorazepam.', 'Pre-Council', '🎓', true),
(7667, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Flumazenil reverses benzodiazepine sedation by:', '["Competitively antagonizing the benzodiazepine binding site on the GABA-A receptor", "Directly stimulating respiratory centers", "Increasing hepatic metabolism of benzodiazepines", "Binding and inactivating circulating benzodiazepine molecules"]'::jsonb, 0, 'Flumazenil is a competitive antagonist at the benzodiazepine binding site of the GABA-A receptor; it has a short half-life (risk of resedation) and can precipitate seizures, particularly in chronic benzodiazepine users or mixed overdoses.', 'Pre-Council', '🎓', true),
(7668, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Buspirone is not useful for acute anxiety management in the ICU primarily because:', '["It has a delayed onset of action (often 1-2 weeks) and lacks acute sedative effects", "It causes profound immediate sedation", "It has a high potential for abuse and dependence", "It cannot be given to patients with any psychiatric history"]'::jsonb, 0, 'Buspirone, a partial 5-HT1A agonist, requires weeks of regular dosing to achieve anxiolytic effect and does not produce acute sedation, making it unsuitable for immediate anxiety relief in critically ill patients.', 'Pre-Council', '🎓', true),
(7669, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Concurrent administration of a benzodiazepine and an opioid in a critically ill patient increases the risk of:', '["Synergistic CNS and respiratory depression, requiring close respiratory monitoring", "Serotonin syndrome exclusively", "Malignant hyperthermia", "Red man syndrome"]'::jsonb, 0, 'Benzodiazepines and opioids both depress the CNS and respiratory drive; combined use has an additive/synergistic effect that significantly increases the risk of respiratory depression, requiring vigilant monitoring.', 'Pre-Council', '🎓', true),
(7670, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Abrupt discontinuation of a benzodiazepine after prolonged high-dose use can precipitate:', '["A withdrawal syndrome including seizures, tremor, agitation, and autonomic instability", "Immediate return to baseline with no adverse effects", "Malignant hyperthermia", "Serotonin syndrome"]'::jsonb, 0, 'Physical dependence can develop with prolonged benzodiazepine use; abrupt cessation risks a withdrawal syndrome that can include life-threatening seizures, so a gradual taper is recommended.', 'Pre-Council', '🎓', true),
(7671, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Benzodiazepines should generally be used cautiously or avoided in elderly ICU patients because of increased risk of:', '["Delirium, falls, and paradoxical agitation", "Improved cognitive clarity", "Decreased fall risk", "Enhanced renal clearance reducing drug effect"]'::jsonb, 0, 'Older adults are more sensitive to benzodiazepine CNS effects and have altered pharmacokinetics, increasing risk of delirium, falls, and paradoxical agitation.', 'Pre-Council', '🎓', true),
(7672, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Lorazepam is often preferred over diazepam as a first-line benzodiazepine for status epilepticus because:', '["It has a longer duration of anticonvulsant CNS effect despite a similar onset of action", "It has no CNS effect at all", "It cannot cause respiratory depression", "It requires no IV access"]'::jsonb, 0, 'Although diazepam has a very rapid onset, lorazepam''s anticonvulsant effect in the CNS lasts longer due to its pharmacokinetic profile, making it a preferred first-line agent for status epilepticus in many protocols.', 'Pre-Council', '🎓', true),
(7673, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Alprazolam, a short-acting, high-potency benzodiazepine, carries a particular risk of:', '["Interdose withdrawal symptoms and a comparatively higher potential for dependence", "No withdrawal potential due to its short half-life", "Being the safest benzodiazepine in hepatic impairment", "Producing no anxiolytic effect"]'::jsonb, 0, 'Alprazolam''s short half-life and high potency are associated with more pronounced interdose withdrawal/rebound anxiety and a comparatively higher risk of dependence than longer-acting benzodiazepines.', 'Pre-Council', '🎓', true),
(7674, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Which benzodiazepines are metabolized primarily by glucuronidation, a phase II pathway less affected by hepatic impairment, making them relatively safer choices in liver disease?', '["Lorazepam, oxazepam, and temazepam", "Diazepam and chlordiazepoxide", "Midazolam and alprazolam", "Clonazepam and flurazepam"]'::jsonb, 0, 'Lorazepam, oxazepam, and temazepam undergo direct hepatic glucuronidation without producing active metabolites, making them comparatively safer in patients with hepatic impairment than benzodiazepines requiring oxidative metabolism.', 'Pre-Council', '🎓', true),
(7675, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'A key goal when using anxiolytics in mechanically ventilated ICU patients is to:', '["Treat anxiety adequately while avoiding oversedation that prolongs mechanical ventilation", "Achieve the deepest sedation level possible at all times", "Avoid all use of sedation scoring tools", "Use only long-acting agents regardless of clinical context"]'::jsonb, 0, 'Current best practice targets light, appropriate sedation using validated scales, treating anxiety and discomfort effectively while minimizing oversedation, which is associated with longer ventilator days and increased delirium risk.', 'Pre-Council', '🎓', true),
(7676, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Zolpidem, a non-benzodiazepine hypnotic, produces sleep induction by:', '["Selectively binding the alpha-1 subunit of the GABA-A receptor", "Antagonizing NMDA receptors", "Agonizing melatonin receptors", "Blocking histamine H1 receptors"]'::jsonb, 0, 'Zolpidem is a Z-drug that selectively binds the alpha-1 subunit of the GABA-A receptor, producing hypnotic effects with relatively less anxiolytic/muscle relaxant activity than traditional benzodiazepines.', 'Pre-Council', '🎓', true),
(7677, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'A notable safety concern with zolpidem, particularly in elderly patients, includes:', '["Complex sleep-related behaviors (e.g., sleepwalking) and next-day sedation increasing fall risk", "Malignant hyperthermia", "Irreversible ototoxicity", "Serotonin syndrome"]'::jsonb, 0, 'Zolpidem has been associated with complex sleep-related behaviors such as sleepwalking or sleep-driving, and residual next-day sedation that increases fall risk, particularly in older adults.', 'Pre-Council', '🎓', true),
(7678, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Chloral hydrate, an older sedative-hypnotic occasionally still encountered, is limited by:', '["GI irritation and risk of cardiac arrhythmias, leading to its replacement by safer agents", "A complete lack of sedative effect", "Being the safest hypnotic for cardiac patients", "Its selective GABA-B receptor activity"]'::jsonb, 0, 'Chloral hydrate can cause significant gastric irritation and cardiac arrhythmias, which along with a narrow therapeutic margin has led to its replacement by safer sedative-hypnotic agents.', 'Pre-Council', '🎓', true),
(7679, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Barbiturates are rarely used as hypnotics for insomnia today primarily because of their:', '["Narrow therapeutic index, high dependence potential, and risk of severe respiratory depression", "Complete lack of sedative effect", "Inability to cross the blood-brain barrier", "Lack of any withdrawal syndrome"]'::jsonb, 0, 'Barbiturates have a narrow therapeutic index with significant risk of fatal respiratory depression in overdose, high potential for tolerance and dependence, and severe withdrawal, leading to their replacement by benzodiazepines and Z-drugs for insomnia.', 'Pre-Council', '🎓', true),
(7680, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Melatonin is sometimes used in the ICU because it may help:', '["Regulate the circadian sleep-wake cycle and potentially reduce the incidence of delirium", "Provide potent analgesia", "Reverse benzodiazepine overdose", "Treat malignant hyperthermia"]'::jsonb, 0, 'Melatonin supports circadian rhythm regulation, and some evidence suggests it may help reduce ICU delirium incidence; it has a favorable safety profile with minimal risk of dependence or respiratory depression.', 'Pre-Council', '🎓', true),
(7681, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Trazodone is sometimes used off-label for ICU insomnia as an alternative to benzodiazepines/Z-drugs because it:', '["Has sedating properties with low abuse potential, though it carries a rare risk of priapism and orthostatic hypotension", "Has no sedative properties whatsoever", "Is a controlled substance with high abuse potential", "Is contraindicated in all patients with depression"]'::jsonb, 0, 'Trazodone, a sedating antidepressant, is used off-label for insomnia due to its low abuse potential compared with benzodiazepines, though nurses should monitor for orthostatic hypotension and counsel about the rare but urgent complication of priapism.', 'Pre-Council', '🎓', true),
(7682, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Ramelteon promotes sleep onset by:', '["Agonizing melatonin MT1/MT2 receptors, without direct GABA-A activity", "Potentiating GABA-A receptor chloride channels", "Blocking orexin receptors", "Antagonizing histamine receptors"]'::jsonb, 0, 'Ramelteon is a selective melatonin receptor agonist that promotes sleep onset through circadian pathways rather than GABAergic mechanisms, giving it a low potential for abuse or dependence.', 'Pre-Council', '🎓', true),
(7683, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'For ICU patients experiencing sleep disturbance, current best practice recommends prioritizing which approach before pharmacologic hypnotics?', '["Non-pharmacologic sleep hygiene measures such as reducing nighttime noise and light and clustering care", "Immediate initiation of a benzodiazepine hypnotic", "Routine use of barbiturates", "Continuous physical restraint"]'::jsonb, 0, 'Given the delirium risk associated with pharmacologic hypnotics in critically ill patients, non-pharmacologic sleep-promoting strategies are recommended as a first-line approach.', 'Pre-Council', '🎓', true),
(7684, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Zopiclone, a cyclopyrrolone-class Z-drug similar to zolpidem, is particularly associated with which distinctive adverse effect?', '["A metallic or bitter taste after use", "Severe hepatotoxicity in most patients", "Malignant hyperthermia", "Serotonin syndrome"]'::jsonb, 0, 'Zopiclone is well known for causing a distinctive metallic or bitter aftertaste, in addition to typical Z-drug effects such as next-day sedation.', 'Pre-Council', '🎓', true),
(7685, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'The fact that a lower dose of a benzodiazepine like lorazepam produces anxiolysis while a higher dose of the same drug produces hypnosis (sleep induction) illustrates:', '["A dose-dependent continuum of CNS depression along the same pharmacologic mechanism", "That anxiolysis and hypnosis involve entirely separate, unrelated receptors", "That benzodiazepines have no dose-response relationship", "That hypnosis only occurs with non-benzodiazepine agents"]'::jsonb, 0, 'Benzodiazepines produce a spectrum of CNS depression that is largely dose-dependent, reflecting increasing GABA-A receptor potentiation at higher doses.', 'Pre-Council', '🎓', true),
(7686, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Z-drug hypnotics such as zolpidem should be used with caution or avoided in patients with:', '["Untreated obstructive sleep apnea or significant respiratory compromise", "Well-controlled hypertension", "Mild seasonal allergies", "Stable, treated hypothyroidism"]'::jsonb, 0, 'Like other CNS depressants, Z-drugs can worsen respiratory drive and upper airway muscle tone, posing increased risk in patients with untreated sleep apnea or significant respiratory compromise.', 'Pre-Council', '🎓', true),
(7687, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Morphine relieves pain primarily by:', '["Agonizing mu-opioid receptors in the central nervous system, inhibiting ascending pain transmission", "Blocking cyclooxygenase enzymes peripherally", "Antagonizing NMDA receptors", "Blocking sodium channels in peripheral nerves"]'::jsonb, 0, 'Morphine is a mu-opioid receptor agonist that inhibits nociceptive signal transmission in the spinal cord and alters pain perception/emotional response in the brain, producing analgesia.', 'Pre-Council', '🎓', true),
(7688, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'A patient with significant renal impairment receiving morphine is at increased risk of prolonged sedation and respiratory depression due to:', '["Accumulation of the active metabolite morphine-6-glucuronide", "Increased hepatic first-pass metabolism", "Reduced protein binding of morphine", "Enhanced renal clearance of morphine"]'::jsonb, 0, 'Morphine''s active metabolite morphine-6-glucuronide is renally eliminated and can accumulate in renal impairment, prolonging opioid effects including sedation and respiratory depression.', 'Pre-Council', '🎓', true),
(7689, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Fentanyl is often preferred over morphine in hemodynamically unstable ICU patients because it:', '["Causes minimal histamine release and has a rapid onset with hemodynamic stability at typical doses", "Has a longer duration of action than morphine after prolonged infusion", "Cannot be given by continuous infusion", "Produces significant peripheral vasodilation via histamine release"]'::jsonb, 0, 'Fentanyl, unlike morphine, causes minimal histamine release and has a rapid onset with a favorable hemodynamic profile, though with prolonged continuous infusion its context-sensitive half-time increases due to accumulation in fat tissue.', 'Pre-Council', '🎓', true),
(7690, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Hydromorphone may be preferred over morphine in a patient with renal impairment because:', '["It lacks a clinically significant accumulating active metabolite like morphine''s M6G", "It has no analgesic potency", "It is not metabolized by the liver at all", "It has no risk of respiratory depression"]'::jsonb, 0, 'Hydromorphone does not have a well-established clinically significant active metabolite that accumulates in renal failure in the way morphine''s M6G does, making it a reasonable alternative in patients with renal impairment.', 'Pre-Council', '🎓', true),
(7691, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Meperidine is largely avoided in ICU practice today primarily because of:', '["Accumulation of its neurotoxic metabolite normeperidine, which can cause seizures, especially in renal impairment", "Its complete lack of analgesic efficacy", "Its inability to be reversed by naloxone", "Its requirement for oral administration only"]'::jsonb, 0, 'Meperidine''s metabolite normeperidine accumulates with repeated dosing or renal impairment and can cause CNS excitation and seizures; meperidine also poses a serotonin syndrome risk with MAO inhibitors.', 'Pre-Council', '🎓', true),
(7692, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Remifentanil''s ultra-short duration of action, regardless of infusion length, is due to its:', '["Metabolism by nonspecific plasma and tissue esterases, independent of hepatic or renal function", "Exclusive renal elimination", "Lack of any active metabolites requiring hepatic clearance", "Extremely high protein binding preventing tissue distribution"]'::jsonb, 0, 'Remifentanil is rapidly hydrolyzed by nonspecific esterases in blood and tissue, giving it a constant, very short context-sensitive half-time regardless of infusion duration, useful when rapid awakening for neurologic assessment is needed.', 'Pre-Council', '🎓', true),
(7693, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'When reversing opioid-induced respiratory depression with naloxone, the nurse should anticipate that:', '["Naloxone''s duration of action may be shorter than that of the causative opioid, risking resedation", "A single dose provides permanent reversal regardless of the opioid involved", "Naloxone has no effect on analgesia and only reverses sedation", "Naloxone is contraindicated in all opioid-dependent patients"]'::jsonb, 0, 'Naloxone is a short-acting competitive mu-opioid antagonist; if the causative opioid has a longer duration of action, respiratory depression can recur as naloxone wears off, requiring repeat dosing or an infusion and close monitoring.', 'Pre-Council', '🎓', true),
(7694, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'When reversing opioid-induced respiratory depression in a chronically opioid-dependent patient, naloxone should be:', '["Titrated in small incremental doses to restore adequate ventilation while avoiding precipitating severe pain or acute withdrawal", "Given as a single large bolus regardless of the clinical situation", "Withheld entirely because reversal is never appropriate in dependent patients", "Given only after the patient has stopped breathing completely"]'::jsonb, 0, 'In opioid-dependent patients, rapid full reversal with naloxone can precipitate acute, severe withdrawal and uncontrolled pain; small titrated doses aimed at restoring adequate ventilation while preserving some analgesia are preferred.', 'Pre-Council', '🎓', true),
(7695, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Which opioid adverse effect does NOT develop meaningful tolerance with continued use, requiring ongoing prophylactic management?', '["Constipation", "Nausea", "Sedation", "Respiratory depression"]'::jsonb, 0, 'While tolerance develops to many opioid effects with continued use, tolerance to opioid-induced constipation is minimal, so a prophylactic bowel regimen should be maintained throughout opioid therapy.', 'Pre-Council', '🎓', true),
(7696, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Tramadol carries a risk of serotonin syndrome, especially when combined with SSRIs, because it:', '["Combines weak mu-opioid agonism with inhibition of serotonin and norepinephrine reuptake", "Is a pure mu-opioid agonist with no serotonergic activity", "Is a monoamine oxidase inhibitor exclusively", "Blocks serotonin receptors entirely"]'::jsonb, 0, 'Tramadol''s dual mechanism, weak mu-opioid agonism plus serotonin-norepinephrine reuptake inhibition, adds serotonergic activity that increases the risk of serotonin syndrome when combined with other serotonergic drugs; it also lowers the seizure threshold.', 'Pre-Council', '🎓', true),
(7697, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Which combination of clinical findings is most consistent with serotonin syndrome in a patient recently started on both tramadol and an SSRI?', '["Altered mental status, hyperthermia, tachycardia, clonus, and hyperreflexia", "Hypothermia, bradycardia, and pinpoint pupils", "Muscle flaccidity with hypothermia and bradypnea", "Isolated dry, flushed skin with dilated pupils and urinary retention only"]'::jsonb, 0, 'Serotonin syndrome classically presents with the triad of altered mental status, autonomic instability, and neuromuscular abnormalities such as clonus, hyperreflexia, and tremor.', 'Pre-Council', '🎓', true),
(7698, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Ketorolac, an injectable NSAID sometimes used for ICU analgesia, should be used cautiously or avoided in patients with:', '["Renal impairment, active bleeding risk, or significant risk for GI bleeding", "Well-controlled type 2 diabetes", "Mild seasonal allergies", "Stable coronary artery disease with no bleeding risk"]'::jsonb, 0, 'NSAIDs like ketorolac inhibit prostaglandin synthesis, which can impair renal blood flow autoregulation and platelet function while increasing GI bleeding risk; use is typically limited to short courses and avoided in patients with renal impairment or significant bleeding risk.', 'Pre-Council', '🎓', true),
(7699, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Compared with NSAIDs, paracetamol (acetaminophen) is characterized by:', '["Analgesic and antipyretic effects with minimal anti-inflammatory, GI, or platelet effects", "Potent peripheral anti-inflammatory activity equal to ibuprofen", "Significant antiplatelet activity similar to aspirin", "Substantial nephrotoxicity at therapeutic doses"]'::jsonb, 0, 'Paracetamol provides analgesia and antipyresis but, unlike NSAIDs, has minimal peripheral anti-inflammatory, GI, or platelet-inhibiting effects; its major toxicity concern is hepatotoxicity in overdose.', 'Pre-Council', '🎓', true),
(7700, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'The recommended maximum daily dose of paracetamol (acetaminophen) in a healthy adult, to reduce the risk of hepatotoxicity, is generally:', '["4 grams per day, with lower limits often recommended in patients with hepatic disease, malnutrition, or chronic alcohol use", "10 grams per day", "500 mg per day", "There is no maximum daily dose since paracetamol has no hepatotoxic potential"]'::jsonb, 0, 'The generally accepted maximum daily dose of paracetamol for a healthy adult is 4 grams/day, often reduced to 2-3 g/day in patients with hepatic impairment, malnutrition, or chronic heavy alcohol use, since exceeding safe thresholds risks NAPQI-mediated hepatotoxicity.', 'Pre-Council', '🎓', true),
(7701, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'A key patient safety principle for patient-controlled analgesia (PCA) is that:', '["Only the patient, not family members or staff, should activate the demand dose button", "Family members should be encouraged to press the button whenever the patient appears uncomfortable", "The lockout interval should be disabled to allow unlimited dosing", "Basal (continuous) rates are always required regardless of patient condition"]'::jsonb, 0, 'PCA is designed so that a sedated patient will not be able to press the button and thus self-limits dosing; PCA by proxy removes this safety mechanism and has been associated with serious oversedation and respiratory depression events.', 'Pre-Council', '🎓', true),
(7702, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'The rationale for multimodal analgesia (combining an opioid with agents like paracetamol, an NSAID, or a regional technique) is that it:', '["Targets different pain pathways simultaneously, allowing lower total opioid doses and fewer opioid-related adverse effects", "Ensures that only opioids are needed for adequate pain control", "Eliminates the need for any pain assessment tools", "Increases the total opioid dose required for analgesia"]'::jsonb, 0, 'Multimodal analgesia leverages complementary mechanisms of action to achieve effective analgesia while reducing total opioid requirements, thereby lowering the incidence of opioid-related adverse effects.', 'Pre-Council', '🎓', true),
(7703, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'A critically ill patient who has received a continuous fentanyl infusion for two weeks now requires escalating doses for the same analgesic effect, and would develop withdrawal symptoms if the infusion were stopped abruptly. This best describes:', '["Physiologic tolerance and physical dependence, not necessarily addiction", "Addiction, defined simply as needing an opioid infusion", "Pseudoaddiction, which never occurs in ICU patients", "Malingering"]'::jsonb, 0, 'Tolerance and physical dependence are expected physiologic adaptations to prolonged opioid exposure and are distinct from addiction, which involves compulsive drug-seeking behavior despite harm.', 'Pre-Council', '🎓', true),
(7704, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'The analgesia-first (analgosedation) approach to ICU sedation management involves:', '["Treating pain with opioids first, which often reduces the additional sedative dose required", "Using sedatives exclusively while withholding analgesics", "Avoiding all opioid use in mechanically ventilated patients", "Providing deep sedation before assessing pain"]'::jsonb, 0, 'Analgosedation prioritizes adequate analgesia as the foundation of comfort management, which frequently reduces the need for additional sedative agents and is associated with improved outcomes such as shorter ventilation duration and less delirium.', 'Pre-Council', '🎓', true),
(7705, 'Classes of Drugs', 'CCN Curriculum — Applied Pharmacology', 'Codeine''s analgesic effect is highly variable between patients because it:', '["Is a prodrug that requires CYP2D6-mediated conversion to morphine, and genetic variability in this enzyme affects efficacy and toxicity risk", "Has no active metabolites and acts directly on opioid receptors", "Is entirely inactive in all patients", "Is metabolized identically in all patients regardless of genotype"]'::jsonb, 0, 'Codeine is a prodrug converted to morphine via CYP2D6; ultra-rapid metabolizers can experience exaggerated/toxic morphine levels even at standard doses, while poor metabolizers may get inadequate pain relief.', 'Pre-Council', '🎓', true),
(7706, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient is prescribed dopamine 5 mcg/kg/min. The patient weighs 70 kg and the infusion is mixed as 400 mg in 250 mL D5W. What is the infusion rate in mL/hr?', '["13.1 mL/hr", "10.5 mL/hr", "21.9 mL/hr", "26.3 mL/hr"]'::jsonb, 0, 'Concentration = 400,000 mcg/250 mL = 1600 mcg/mL. Dose = 5 mcg/kg/min x 70 kg = 350 mcg/min. Rate = 350/1600 = 0.219 mL/min x 60 = 13.1 mL/hr.', 'Pre-Council', '🎓', true),
(7707, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A litre of Normal Saline is ordered to run over 8 hours via a gravity administration set with a drop factor of 15 gtt/mL. What is the correct flow rate in drops per minute?', '["31 gtt/min", "21 gtt/min", "42 gtt/min", "15 gtt/min"]'::jsonb, 0, 'mL/hr = 1000/8 = 125 mL/hr. gtt/min = (125 x 15)/60 = 31.25, rounded to 31 gtt/min.', 'Pre-Council', '🎓', true),
(7708, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A child weighing 18 kg is prescribed an antibiotic at 10 mg/kg/day divided every 8 hours. How many milligrams should be given per dose?', '["60 mg", "180 mg", "90 mg", "30 mg"]'::jsonb, 0, 'Total daily dose = 18 kg x 10 mg/kg = 180 mg/day. Divided every 8 hours = 3 doses/day, so 180/3 = 60 mg/dose.', 'Pre-Council', '🎓', true),
(7709, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A physician orders 0.25 mg of a drug orally. The tablets available are labelled 125 mcg per tablet. How many tablets should the nurse administer?', '["2 tablets", "1 tablet", "4 tablets", "0.5 tablet"]'::jsonb, 0, '0.25 mg = 250 mcg. 250 mcg / 125 mcg per tablet = 2 tablets.', 'Pre-Council', '🎓', true),
(7710, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'The pharmacy needs 500 mL of a 5% dextrose solution but only has 50% dextrose stock solution and sterile water available. How much of the 50% stock solution is needed?', '["50 mL of stock, diluted with 450 mL water", "100 mL of stock, diluted with 400 mL water", "250 mL of stock, diluted with 250 mL water", "5 mL of stock, diluted with 495 mL water"]'::jsonb, 0, 'Using C1V1 = C2V2: 50% x V1 = 5% x 500 mL, so V1 = 2500/50 = 50 mL of stock, topped up with 450 mL diluent to make 500 mL.', 'Pre-Council', '🎓', true),
(7711, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A heparin infusion is prepared as 25,000 units in 250 mL D5W. The physician orders 1000 units/hr. What rate should the infusion pump be set at?', '["10 mL/hr", "25 mL/hr", "100 mL/hr", "4 mL/hr"]'::jsonb, 0, 'Concentration = 25,000 units/250 mL = 100 units/mL. Rate = 1000 units/hr divided by 100 units/mL = 10 mL/hr.', 'Pre-Council', '🎓', true),
(7712, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Glyceryl trinitrate (nitroglycerin) is mixed as 50 mg in 250 mL D5W and ordered to infuse at 20 mcg/min. What rate should the pump deliver, in mL/hr?', '["6 mL/hr", "12 mL/hr", "3 mL/hr", "24 mL/hr"]'::jsonb, 0, 'Concentration = 50,000 mcg/250 mL = 200 mcg/mL. Rate = 20 mcg/min / 200 mcg/mL = 0.1 mL/min x 60 = 6 mL/hr.', 'Pre-Council', '🎓', true),
(7713, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A neonate weighing 4.5 kg requires a drug dosed at 15 mg/kg/dose. What is the correct single dose in milligrams?', '["67.5 mg", "60 mg", "45 mg", "75 mg"]'::jsonb, 0, 'Dose = weight x mg/kg = 4.5 kg x 15 mg/kg = 67.5 mg.', 'Pre-Council', '🎓', true),
(7714, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A nurse must give a 40 mg IV push dose over 4 minutes. The drug is supplied as 40 mg in 4 mL. At what rate, in mL/min, should the nurse push the medication?', '["1 mL/min", "4 mL/min", "10 mL/min", "0.5 mL/min"]'::jsonb, 0, 'Concentration = 40 mg/4 mL = 10 mg/mL. To deliver 40 mg over 4 minutes = 10 mg/min = 1 mL/min.', 'Pre-Council', '🎓', true),
(7715, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Dobutamine is mixed as 250 mg in 250 mL D5W and prescribed at 5 mcg/kg/min for an 80 kg patient. What infusion rate in mL/hr should be set?', '["24 mL/hr", "12 mL/hr", "48 mL/hr", "20 mL/hr"]'::jsonb, 0, 'Concentration = 250,000 mcg/250 mL = 1000 mcg/mL (1 mg/mL). Dose = 5 mcg/kg/min x 80 kg = 400 mcg/min. Rate = 400/1000 = 0.4 mL/min x 60 = 24 mL/hr.', 'Pre-Council', '🎓', true),
(7716, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'One litre of IV fluid is to infuse over 10 hours using a macrodrip set with a drop factor of 10 gtt/mL. What is the correct rate in drops per minute?', '["17 gtt/min", "10 gtt/min", "25 gtt/min", "100 gtt/min"]'::jsonb, 0, 'mL/hr = 1000/10 = 100 mL/hr. gtt/min = (100 x 10)/60 = 16.7, rounded to 17 gtt/min.', 'Pre-Council', '🎓', true),
(7717, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient weighs 154 lb. What is this weight in kilograms, for the purpose of a weight-based drug calculation?', '["70 kg", "154 kg", "77 kg", "63 kg"]'::jsonb, 0, 'To convert pounds to kilograms, divide by 2.2: 154 / 2.2 = 70 kg.', 'Pre-Council', '🎓', true),
(7718, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Dopamine is ordered at 10 mcg/kg/min for a 60 kg patient. What is this dose expressed in mg/hr?', '["36 mg/hr", "6 mg/hr", "60 mg/hr", "3.6 mg/hr"]'::jsonb, 0, 'Dose = 10 mcg/kg/min x 60 kg = 600 mcg/min. Per hour = 600 x 60 = 36,000 mcg/hr = 36 mg/hr.', 'Pre-Council', '🎓', true),
(7719, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'How many grams of dextrose are contained in 1 litre of 5% dextrose in water (D5W)?', '["50 g", "5 g", "500 g", "100 g"]'::jsonb, 0, 'A 5% solution contains 5 g per 100 mL. For 1000 mL: (5 g/100 mL) x 1000 mL = 50 g.', 'Pre-Council', '🎓', true),
(7720, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'An IV bag containing 1000 mL is infusing at 125 mL/hr. How many hours will it take for the bag to empty?', '["8 hours", "10 hours", "12.5 hours", "6 hours"]'::jsonb, 0, 'Time = total volume / rate = 1000 mL / 125 mL/hr = 8 hours.', 'Pre-Council', '🎓', true),
(7721, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A loading dose of phenytoin at 18 mg/kg is ordered for a 70 kg patient. What is the total loading dose in milligrams?', '["1260 mg", "1400 mg", "980 mg", "700 mg"]'::jsonb, 0, 'Dose = 18 mg/kg x 70 kg = 1260 mg.', 'Pre-Council', '🎓', true),
(7722, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Norepinephrine is mixed as 4 mg in 250 mL D5W and ordered at 8 mcg/min. What infusion rate in mL/hr should be programmed on the pump?', '["30 mL/hr", "15 mL/hr", "60 mL/hr", "8 mL/hr"]'::jsonb, 0, 'Concentration = 4000 mcg/250 mL = 16 mcg/mL. Rate = 8 mcg/min / 16 mcg/mL = 0.5 mL/min x 60 = 30 mL/hr.', 'Pre-Council', '🎓', true),
(7723, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Using the Holliday-Segar method, what is the daily maintenance IV fluid requirement for a 22 kg child?', '["1540 mL/day", "1100 mL/day", "2200 mL/day", "1000 mL/day"]'::jsonb, 0, 'First 10 kg = 100 mL/kg = 1000 mL; next 10 kg = 50 mL/kg = 500 mL; remaining 2 kg = 20 mL/kg = 40 mL. Total = 1000 + 500 + 40 = 1540 mL/day.', 'Pre-Council', '🎓', true),
(7724, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'An infusion is being given via a microdrip set, where the drop factor is 60 gtt/mL, at a pump-set rate of 45 mL/hr. If the pump failed and this had to be run by gravity, what would the drop rate be in gtt/min?', '["45 gtt/min", "60 gtt/min", "15 gtt/min", "75 gtt/min"]'::jsonb, 0, 'With a 60 gtt/mL microdrip set, mL/hr and gtt/min are numerically equal, so 45 mL/hr = 45 gtt/min.', 'Pre-Council', '🎓', true),
(7725, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Vancomycin is prescribed at 15 mg/kg every 12 hours for a patient weighing 65 kg. What is the correct dose per administration?', '["975 mg", "900 mg", "1080 mg", "650 mg"]'::jsonb, 0, 'Dose = 15 mg/kg x 65 kg = 975 mg per dose.', 'Pre-Council', '🎓', true),
(7726, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A nurse adds 2 g of a drug to 500 mL of diluent. What is the resulting concentration in mg/mL?', '["4 mg/mL", "2 mg/mL", "0.4 mg/mL", "40 mg/mL"]'::jsonb, 0, '2 g = 2000 mg. Concentration = 2000 mg / 500 mL = 4 mg/mL.', 'Pre-Council', '🎓', true),
(7727, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'An IV antibiotic bag of 1000 mL is set to infuse at 42 mL/hr. Approximately how long will the infusion take to complete?', '["Approximately 24 hours", "Approximately 12 hours", "Approximately 18 hours", "Approximately 30 hours"]'::jsonb, 0, 'Time = 1000 mL / 42 mL/hr = 23.8 hours, approximately 24 hours.', 'Pre-Council', '🎓', true),
(7728, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Amiodarone is given as a 150 mg IV bolus over 10 minutes, followed by a maintenance infusion of 1 mg/min for 6 hours, then 0.5 mg/min for the next 18 hours. What is the total dose of amiodarone infused over the full 24-hour period (including the bolus)?', '["1050 mg", "900 mg", "1200 mg", "660 mg"]'::jsonb, 0, 'Bolus = 150 mg. First phase = 1 mg/min x 360 min = 360 mg. Second phase = 0.5 mg/min x 1080 min = 540 mg. Total = 150 + 360 + 540 = 1050 mg.', 'Pre-Council', '🎓', true),
(7729, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A child weighs 26.4 lb. Paracetamol is ordered at 15 mg/kg/dose. What is the correct single dose in milligrams?', '["180 mg", "396 mg", "120 mg", "264 mg"]'::jsonb, 0, '26.4 lb / 2.2 = 12 kg. Dose = 12 kg x 15 mg/kg = 180 mg.', 'Pre-Council', '🎓', true),
(7730, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Digoxin loading (digitalizing) dose is calculated as 10 mcg/kg for a 68 kg patient, with 50% given as the first dose and the remainder split into two further doses. What is the total loading dose, and what is the first dose given?', '["Total 680 mcg; first dose 340 mcg", "Total 680 mcg; first dose 170 mcg", "Total 340 mcg; first dose 170 mcg", "Total 680 mcg; first dose 680 mcg"]'::jsonb, 0, 'Total loading dose = 10 mcg/kg x 68 kg = 680 mcg. The first dose (50%) = 340 mcg, with the remaining 340 mcg split into two doses of 170 mcg each.', 'Pre-Council', '🎓', true),
(7731, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A potassium chloride infusion of 40 mEq is ordered in 500 mL of NS to run over 4 hours via a peripheral line. What is the resulting rate of potassium delivery in mEq/hr, and is this within the generally accepted peripheral IV limit of 10 mEq/hr?', '["10 mEq/hr; at the upper safe peripheral limit", "20 mEq/hr; exceeds the peripheral limit", "5 mEq/hr; well within the peripheral limit", "40 mEq/hr; grossly exceeds the peripheral limit"]'::jsonb, 0, '40 mEq over 4 hours = 10 mEq/hr, which is at the commonly accepted maximum peripheral infusion limit and should be given on a monitored line with cardiac monitoring.', 'Pre-Council', '🎓', true),
(7732, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Amoxicillin suspension is labelled 250 mg/5 mL. A dose of 375 mg is ordered. How many millilitres should the nurse administer?', '["7.5 mL", "5 mL", "10 mL", "6 mL"]'::jsonb, 0, '375 mg / 250 mg x 5 mL = 7.5 mL.', 'Pre-Council', '🎓', true),
(7733, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A fentanyl infusion is prepared at a concentration of 50 mcg/mL. The order is for 100 mcg/hr. What rate should the pump be set at, in mL/hr?', '["2 mL/hr", "5 mL/hr", "0.5 mL/hr", "20 mL/hr"]'::jsonb, 0, 'Rate = dose/concentration = 100 mcg/hr / 50 mcg/mL = 2 mL/hr.', 'Pre-Council', '🎓', true),
(7734, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Propofol (10 mg/mL) is ordered at 30 mcg/kg/min for an 80 kg patient. What infusion rate in mL/hr should be programmed?', '["14.4 mL/hr", "24 mL/hr", "7.2 mL/hr", "28.8 mL/hr"]'::jsonb, 0, 'Dose = 30 mcg/kg/min x 80 kg = 2400 mcg/min = 2.4 mg/min = 144 mg/hr. Rate = 144 mg/hr / 10 mg/mL = 14.4 mL/hr.', 'Pre-Council', '🎓', true),
(7735, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Magnesium sulfate is available as 40 g in 1000 mL. A loading dose of 4 g is ordered to be infused over 20 minutes. How many millilitres are needed, and at what pump rate (mL/hr)?', '["100 mL needed, at a rate of 300 mL/hr", "40 mL needed, at a rate of 120 mL/hr", "100 mL needed, at a rate of 200 mL/hr", "400 mL needed, at a rate of 1200 mL/hr"]'::jsonb, 0, 'Concentration = 40 g/1000 mL = 40 mg/mL. Volume for 4 g (4000 mg) = 4000/40 = 100 mL. To infuse 100 mL in 20 minutes (1/3 hour): rate = 100 / (20/60) = 300 mL/hr.', 'Pre-Council', '🎓', true),
(7736, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A child weighs 33 lb. What is this weight in kilograms?', '["15 kg", "33 kg", "66 kg", "7.5 kg"]'::jsonb, 0, '33 lb / 2.2 = 15 kg.', 'Pre-Council', '🎓', true),
(7737, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'An ampule contains 400 mcg/mL of a drug. The order is for 0.4 mg IV. How many millilitres should the nurse draw up?', '["1 mL", "0.4 mL", "4 mL", "0.1 mL"]'::jsonb, 0, '0.4 mg = 400 mcg. 400 mcg / 400 mcg per mL = 1 mL.', 'Pre-Council', '🎓', true),
(7738, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Normal saline is prescribed to infuse at 150 mL/hr for 6 hours. What total volume will the patient receive?', '["900 mL", "750 mL", "1000 mL", "600 mL"]'::jsonb, 0, 'Total volume = rate x time = 150 mL/hr x 6 hr = 900 mL.', 'Pre-Council', '🎓', true),
(7739, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A nurse is asked to prepare an infusion so that a patient weighing 90 kg receives dopamine at 3 mcg/kg/min. The available bag is 800 mg in 500 mL D5W. What is the required infusion rate in mL/hr?', '["10.1 mL/hr", "16.9 mL/hr", "8.4 mL/hr", "20.3 mL/hr"]'::jsonb, 0, 'Concentration = 800,000 mcg/500 mL = 1600 mcg/mL. Dose = 3 mcg/kg/min x 90 kg = 270 mcg/min. Rate = 270/1600 = 0.169 mL/min x 60 = 10.1 mL/hr.', 'Pre-Council', '🎓', true),
(7740, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A nurse mistakenly calculates a dopamine infusion using the patient''s weight in pounds (80 lb) instead of converting to kilograms (36.4 kg) first. If the ordered dose is 5 mcg/kg/min with a concentration of 1600 mcg/mL, by roughly what factor will the error inflate the calculated rate compared to the correct rate?', '["Approximately 2.2 times too high", "Approximately half the correct rate", "Approximately 10 times too high", "No difference, the rate is unaffected"]'::jsonb, 0, 'Using pounds instead of kilograms without conversion means the ''weight'' value used is 2.2 times larger than the true kilogram value, so the calculated mcg/min dose (and resulting rate) becomes approximately 2.2 times too high — a dangerous overdose.', 'Pre-Council', '🎓', true),
(7741, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A syringe driver is delivering morphine at a concentration of 1 mg/mL, prescribed at 2 mg/hr. After 3 hours, how many millilitres will have infused?', '["6 mL", "2 mL", "3 mL", "9 mL"]'::jsonb, 0, 'Rate = 2 mg/hr / 1 mg/mL = 2 mL/hr. Over 3 hours = 2 x 3 = 6 mL.', 'Pre-Council', '🎓', true),
(7742, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Insulin is infusing via a standard concentration of 1 unit/mL (100 units in 100 mL NS), and the order is for 6 units/hr. What rate should the pump be set to, in mL/hr?', '["6 mL/hr", "0.6 mL/hr", "60 mL/hr", "16.7 mL/hr"]'::jsonb, 0, 'At a 1 unit/mL concentration, the mL/hr rate equals the units/hr dose, so 6 units/hr = 6 mL/hr.', 'Pre-Council', '🎓', true),
(7743, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient requires 2 litres of Ringer''s Lactate over 24 hours, using a set with a drop factor of 20 gtt/mL. What is the required rate in drops per minute?', '["28 gtt/min", "83 gtt/min", "14 gtt/min", "42 gtt/min"]'::jsonb, 0, 'mL/hr = 2000/24 = 83.3 mL/hr. gtt/min = (83.3 x 20)/60 = 27.8, rounded to 28 gtt/min.', 'Pre-Council', '🎓', true),
(7744, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'An adrenaline (epinephrine) infusion is mixed as 4 mg in 500 mL D5W and ordered to run at 0.1 mcg/kg/min for a 75 kg patient. What is the correct infusion rate in mL/hr?', '["56.25 mL/hr", "28.1 mL/hr", "112.5 mL/hr", "7.5 mL/hr"]'::jsonb, 0, 'Concentration = 4,000,000 mcg/500 mL = 8 mcg/mL. Dose = 0.1 mcg/kg/min x 75 kg = 7.5 mcg/min. Rate = 7.5/8 = 0.9375 mL/min x 60 = 56.25 mL/hr.', 'Pre-Council', '🎓', true),
(7745, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A neonate requires an IV fluid bolus of 10 mL/kg of normal saline. The infant weighs 3.2 kg. What total volume should be given?', '["32 mL", "10 mL", "16 mL", "48 mL"]'::jsonb, 0, 'Volume = 10 mL/kg x 3.2 kg = 32 mL.', 'Pre-Council', '🎓', true),
(7746, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Aminophylline is ordered as a loading dose of 5 mg/kg over 30 minutes for a 60 kg patient, supplied as 250 mg in 100 mL. What volume should be given, and at what rate over the 30 minutes?', '["120 mL total, at a rate of 240 mL/hr", "60 mL total, at a rate of 120 mL/hr", "300 mL total, at a rate of 600 mL/hr", "120 mL total, at a rate of 60 mL/hr"]'::jsonb, 0, 'Total dose = 5 mg/kg x 60 kg = 300 mg. Volume = 300 mg / 250 mg x 100 mL = 120 mL. To give over 30 min (0.5 hr): rate = 120/0.5 = 240 mL/hr.', 'Pre-Council', '🎓', true),
(7747, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A drug is available as a 1:1000 solution. How many milligrams are contained in 1 mL of this solution?', '["1 mg", "10 mg", "0.1 mg", "100 mg"]'::jsonb, 0, 'A 1:1000 solution contains 1 g in 1000 mL, which is equivalent to 1 mg per mL.', 'Pre-Council', '🎓', true),
(7748, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A drug is available as a 1:10,000 solution, commonly used for cardiac arrest adrenaline. How many milligrams are in a 10 mL prefilled syringe of this solution?', '["1 mg", "10 mg", "0.1 mg", "100 mg"]'::jsonb, 0, 'A 1:10,000 solution = 1 g in 10,000 mL = 0.1 mg/mL. 10 mL x 0.1 mg/mL = 1 mg, the standard cardiac arrest dose.', 'Pre-Council', '🎓', true),
(7749, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Which formula correctly converts an IV flow rate from mL/hr to drops per minute (gtt/min)?', '["(Volume in mL x drop factor) / time in minutes", "(Volume in mL x time in minutes) / drop factor", "Drop factor / (volume in mL x time in minutes)", "Volume in mL / drop factor"]'::jsonb, 0, 'The standard formula is gtt/min = (Volume to be infused in mL x drop factor in gtt/mL) / time in minutes.', 'Pre-Council', '🎓', true),
(7750, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A microdrip administration set is defined by which characteristic?', '["A drop factor of 60 gtt/mL, used for precise low-volume infusions", "A drop factor of 10 gtt/mL, used for routine adult maintenance fluids", "A drop factor of 20 gtt/mL, used only for blood products", "A drop factor that varies depending on the fluid being infused"]'::jsonb, 0, 'Microdrip (minidrip) sets deliver 60 gtt/mL, allowing precise control of small volumes and slow rates, commonly used in paediatric and critical care infusions.', 'Pre-Council', '🎓', true),
(7751, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'When calculating a weight-based drug dose for a critically ill patient, which practice is safest?', '["Use the most recently measured actual body weight in kilograms, and have a second nurse independently verify the calculation for high-alert drugs", "Always use the weight documented at the time of admission, regardless of how long ago that was", "Estimate the patient''s weight visually to save time in an emergency", "Use the patient''s stated weight in pounds directly in a mg/kg formula without conversion"]'::jsonb, 0, 'Accurate, current, correctly-converted body weight and independent double-checking of high-alert drug calculations are core medication safety practices in critical care.', 'Pre-Council', '🎓', true),
(7752, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'In the formula Dose ordered / Dose on hand x Quantity = Amount to give, what is the primary purpose of this calculation?', '["To determine the volume or number of dosage units needed to deliver a prescribed dose from the available stock strength", "To determine the total daily dose of a medication", "To calculate the correct drop factor for an IV set", "To determine a patient''s weight-based dose"]'::jsonb, 0, 'This is the standard dosage calculation (desired-over-have) formula used to convert a prescribed dose into the volume, tablets, or units the nurse must actually administer from the strength available.', 'Pre-Council', '🎓', true),
(7753, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Before programming a smart infusion pump for a high-alert continuous infusion such as an inotrope, what is the most important nursing safety step?', '["Independently calculate the rate manually and have a second qualified nurse verify the calculation and pump settings before starting the infusion", "Trust the pump''s drug library default settings without further calculation", "Set the pump to the nearest round number for convenience", "Ask the patient to confirm the dose is correct"]'::jsonb, 0, 'Independent double-checking of calculations and pump settings by two qualified nurses is a critical safeguard against fatal errors with high-alert medications.', 'Pre-Council', '🎓', true),
(7754, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A nurse notes an order for a paediatric infusion in mcg/kg/min but the pump only accepts mL/hr. What is the correct sequence of steps to safely programme the pump?', '["Convert the ordered dose to a total dose per unit time using the patient''s weight, then convert to mL/hr using the prepared concentration, then verify with a second nurse", "Enter the mcg/kg/min value directly into the pump''s mL/hr field", "Estimate a reasonable mL/hr rate based on similar adult infusions", "Round the child''s weight to the nearest 10 kg before calculating"]'::jsonb, 0, 'Safe practice requires calculating the actual dose per minute or hour using the patient''s exact weight, converting to a volume rate using the known drug concentration, and having an independent check before infusing.', 'Pre-Council', '🎓', true),
(7755, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'What is the correct method to convert a dose from milligrams to micrograms?', '["Multiply the milligram value by 1000", "Divide the milligram value by 1000", "Multiply the milligram value by 100", "Divide the milligram value by 100"]'::jsonb, 0, 'There are 1000 micrograms in 1 milligram, so converting mg to mcg requires multiplying by 1000.', 'Pre-Council', '🎓', true),
(7756, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A nurse is converting a dose from micrograms per kilogram per minute to milligrams per hour for documentation purposes. Which conversion factor is required in addition to the patient''s weight?', '["Multiply mcg/min by 60 to get mcg/hr, then divide by 1000 to get mg/hr", "Divide mcg/min by 60, then multiply by 1000", "Multiply mcg/min by 1000, then divide by 60", "Divide mcg/min by 1000, then divide by 60"]'::jsonb, 0, 'To move from a per-minute micrograms rate to a per-hour milligrams rate, multiply by 60 (minutes to hours) and divide by 1000 (mcg to mg).', 'Pre-Council', '🎓', true),
(7757, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Why is it important for a critical care nurse to always double-check the concentration (mg/mL or units/mL) of a prepared infusion bag before calculating a pump rate?', '["Different batches or standard concentrations may vary, and using an incorrect concentration in the calculation will result in the wrong infusion rate and dose delivered", "The concentration never affects the pump rate calculation", "Only the total volume of the bag matters for calculating the rate", "Concentration only matters for oral medications, not infusions"]'::jsonb, 0, 'The infusion rate calculation directly depends on the concentration of drug in the bag; using an incorrect concentration value will produce a rate that delivers the wrong dose, which is a common source of serious medication error.', 'Pre-Council', '🎓', true),
(7758, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Which statement about calculating body surface area (BSA)-based dosing is correct?', '["BSA-based dosing is used for certain drugs, such as some chemotherapeutic agents, and is generally more accurate than weight-based dosing for those drugs because it better reflects metabolic rate", "BSA-based dosing is only ever used in neonates", "BSA is calculated using weight alone, without height", "BSA-based dosing and weight-based dosing always give an identical dose"]'::jsonb, 0, 'Body surface area correlates more closely with metabolic rate and organ function for some drugs (notably chemotherapy agents), and is calculated using both height and weight via a nomogram or formula such as the Mosteller formula.', 'Pre-Council', '🎓', true),
(7759, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient presents with pinpoint pupils, respiratory rate of 6 breaths/min, decreased level of consciousness, and bradycardia. Which toxidrome does this most likely represent?', '["Opioid toxidrome", "Anticholinergic toxidrome", "Sympathomimetic toxidrome", "Cholinergic toxidrome"]'::jsonb, 0, 'Miosis (pinpoint pupils), respiratory depression, and CNS depression are the classic triad of opioid toxicity.', 'Pre-Council', '🎓', true),
(7760, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'What is the first-line antidote for suspected opioid overdose causing respiratory depression?', '["Naloxone", "Flumazenil", "Atropine", "N-acetylcysteine"]'::jsonb, 0, 'Naloxone is a competitive opioid receptor antagonist that rapidly reverses opioid-induced respiratory and CNS depression.', 'Pre-Council', '🎓', true),
(7761, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient who received naloxone for heroin overdose initially improves but becomes drowsy and hypoventilating again 45 minutes later. What is the most likely explanation?', '["Naloxone has a shorter half-life than most opioids, so re-sedation occurs as the antidote wears off before the opioid does", "The patient has developed an allergic reaction to naloxone", "The initial dose of naloxone was too high", "This indicates the patient never had an opioid overdose"]'::jsonb, 0, 'Naloxone''s duration of action (roughly 30-90 minutes) is often shorter than that of the causative opioid, so repeat doses or an infusion may be needed and close monitoring is essential.', 'Pre-Council', '🎓', true),
(7762, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient with a suspected benzodiazepine overdose is being considered for flumazenil administration. Which condition makes flumazenil relatively contraindicated?', '["Chronic benzodiazepine use or co-ingestion with a pro-convulsant drug such as a tricyclic antidepressant, due to seizure risk", "Mild drowsiness without respiratory compromise", "Known allergy to opioids", "Normal renal function"]'::jsonb, 0, 'In patients who are benzodiazepine-dependent or who have co-ingested a proconvulsant (e.g., TCAs), abruptly reversing GABA-mediated sedation with flumazenil can precipitate seizures that may be difficult to treat.', 'Pre-Council', '🎓', true),
(7763, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient presents with dry flushed skin, dilated pupils, urinary retention, hyperthermia, tachycardia, and confusion after ingesting an unknown substance. This presentation is most consistent with which toxidrome?', '["Anticholinergic toxidrome", "Cholinergic toxidrome", "Opioid toxidrome", "Sedative-hypnotic toxidrome"]'::jsonb, 0, 'The mnemonic ''red as a beet, dry as a bone, blind as a bat, mad as a hatter, hot as a hare'' describes the anticholinergic toxidrome: flushed dry skin, mydriasis, urinary retention, hyperthermia, and delirium.', 'Pre-Council', '🎓', true),
(7764, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A farm worker presents with excessive salivation, lacrimation, urination, diarrhoea, GI cramps, emesis (SLUDGE), miosis, bradycardia, and muscle fasciculations after exposure to a crop spray. Which class of toxin is most likely responsible?', '["Organophosphate (cholinergic) poisoning", "Anticholinergic poisoning", "Opioid overdose", "Sympathomimetic overdose"]'::jsonb, 0, 'SLUDGE symptoms plus miosis, bradycardia, and fasciculations reflect excess acetylcholine at muscarinic and nicotinic receptors, the hallmark of organophosphate/cholinergic toxicity.', 'Pre-Council', '🎓', true),
(7765, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'What are the two key pharmacological antidotes used in the management of organophosphate poisoning?', '["Atropine and pralidoxime", "Naloxone and flumazenil", "Atropine and naloxone", "Pralidoxime and N-acetylcysteine"]'::jsonb, 0, 'Atropine blocks the muscarinic effects of excess acetylcholine, while pralidoxime reactivates acetylcholinesterase if given early, before the enzyme-organophosphate bond becomes irreversible (''ageing'').', 'Pre-Council', '🎓', true),
(7766, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'In organophosphate poisoning, atropine is titrated primarily against which clinical sign, rather than a fixed maximum dose?', '["Drying of bronchial secretions and resolution of bronchospasm/bradycardia", "Pupil size returning to pinpoint", "Return of bowel sounds", "Normalisation of blood glucose"]'::jsonb, 0, 'Atropine is titrated to effect — drying of respiratory secretions and reversal of bronchoconstriction/bradycardia — since organophosphate poisoning may require very large cumulative atropine doses well beyond usual limits.', 'Pre-Council', '🎓', true),
(7767, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient presents with agitation, dilated pupils, tachycardia, hypertension, hyperthermia, and diaphoresis after suspected cocaine or amphetamine use. Which toxidrome is this?', '["Sympathomimetic toxidrome", "Anticholinergic toxidrome", "Opioid toxidrome", "Cholinergic toxidrome"]'::jsonb, 0, 'Sympathomimetic toxicity produces CNS and cardiovascular stimulation: agitation, mydriasis, tachycardia, hypertension, hyperthermia, and sweating (diaphoresis distinguishes it from anticholinergic toxicity, which causes dry skin).', 'Pre-Council', '🎓', true),
(7768, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'What is the key clinical feature that helps distinguish sympathomimetic toxidrome from anticholinergic toxidrome, since both cause tachycardia, hyperthermia, and agitation?', '["Diaphoresis (sweating) is present in sympathomimetic toxicity, whereas skin is hot and dry in anticholinergic toxicity", "Pupils are constricted in sympathomimetic toxicity", "Bowel sounds are increased in anticholinergic toxicity", "Respiratory rate is decreased in sympathomimetic toxicity"]'::jsonb, 0, 'Both cause mydriasis, tachycardia, and hyperthermia, but sympathomimetic toxicity typically produces sweaty, moist skin, while anticholinergic toxicity causes dry, flushed skin due to blocked sweat gland activity.', 'Pre-Council', '🎓', true),
(7769, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient with sedative-hypnotic (e.g., barbiturate or benzodiazepine) overdose typically presents with which combination of findings?', '["CNS depression, respiratory depression, and hypotension, often with normal or slightly constricted pupils", "Agitation, hyperthermia, and dilated pupils", "Excessive salivation and muscle fasciculations", "Hypertension and tachyarrhythmia"]'::jsonb, 0, 'Sedative-hypnotic toxicity causes generalized CNS and respiratory depression, hypotension, and often normal-to-small pupils, distinguishing it from stimulant or anticholinergic toxidromes.', 'Pre-Council', '🎓', true),
(7770, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient is admitted 8 hours after a large intentional paracetamol (acetaminophen) overdose. Which investigation is essential to guide treatment decisions?', '["A serum paracetamol level plotted on the treatment nomogram against time since ingestion", "A random blood glucose only", "A chest X-ray", "A urine drug screen for opioids"]'::jsonb, 0, 'Serum paracetamol concentration plotted against time post-ingestion on the paracetamol treatment nomogram determines whether N-acetylcysteine therapy is indicated.', 'Pre-Council', '🎓', true),
(7771, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'What is the mechanism by which N-acetylcysteine (NAC) protects the liver in paracetamol overdose?', '["It replenishes hepatic glutathione stores, which detoxify the toxic metabolite NAPQI", "It directly binds and inactivates paracetamol in the stomach", "It increases renal excretion of paracetamol", "It induces vomiting to remove unabsorbed paracetamol"]'::jsonb, 0, 'NAC restores depleted glutathione, allowing conjugation and detoxification of N-acetyl-p-benzoquinone imine (NAPQI), the hepatotoxic metabolite of paracetamol that accumulates when glutathione is exhausted.', 'Pre-Council', '🎓', true),
(7772, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'In paracetamol overdose, why is treatment with N-acetylcysteine most effective when started early?', '["NAC is most effective when given within 8-10 hours of ingestion, before glutathione depletion leads to significant hepatocyte injury from NAPQI accumulation", "NAC only works if given within the first hour and is useless afterward", "NAC has no time-dependent efficacy and can be given at any point with equal benefit", "Early NAC prevents absorption of paracetamol from the gut"]'::jsonb, 0, 'The risk of hepatotoxicity rises sharply with delay; NAC is most protective when started within 8-10 hours of ingestion, though it is still given later as some benefit persists even in established liver injury.', 'Pre-Council', '🎓', true),
(7773, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient with digoxin toxicity presents with nausea, visual disturbances (yellow-green halos), and life-threatening arrhythmias. What is the specific antidote for severe digoxin toxicity?', '["Digoxin-specific antibody fragments (digoxin immune Fab)", "Atropine", "Naloxone", "Flumazenil"]'::jsonb, 0, 'Digoxin immune Fab binds free digoxin molecules, rendering them inactive and allowing renal excretion of the complex, and is indicated in life-threatening digoxin toxicity.', 'Pre-Council', '🎓', true),
(7774, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient with digoxin toxicity develops hyperkalaemia. What is the significance of this finding?', '["Hyperkalaemia in acute digoxin toxicity reflects the degree of Na+/K+-ATPase pump inhibition and is a marker of toxicity severity", "Hyperkalaemia is unrelated to digoxin toxicity and is coincidental", "Digoxin toxicity always causes hypokalaemia, never hyperkalaemia", "Hyperkalaemia only occurs in chronic, not acute, digoxin toxicity"]'::jsonb, 0, 'Digoxin inhibits the Na+/K+-ATPase pump; in acute overdose this causes potassium to shift out of cells, and the degree of hyperkalaemia correlates with toxicity severity and mortality risk.', 'Pre-Council', '🎓', true),
(7775, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient presents with widened QRS complex, hypotension, and seizures after a tricyclic antidepressant (TCA) overdose. Which treatment is indicated to counteract the cardiotoxic sodium-channel blocking effect?', '["IV sodium bicarbonate", "Flumazenil", "Naloxone", "Activated charcoal alone, with no other treatment"]'::jsonb, 0, 'Sodium bicarbonate increases extracellular sodium and alkalinises the blood, which helps overcome TCA-induced fast sodium channel blockade in the myocardium, narrowing the QRS and reducing arrhythmia risk.', 'Pre-Council', '🎓', true),
(7776, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Why is flumazenil generally avoided in a patient with mixed overdose that may include a tricyclic antidepressant?', '["Reversing benzodiazepine sedation can unmask or precipitate TCA-induced seizures and arrhythmias", "Flumazenil has no effect when benzodiazepines are involved", "Flumazenil worsens respiratory depression", "Flumazenil is only administered orally, so it cannot be used in emergencies"]'::jsonb, 0, 'In mixed overdoses involving proconvulsant drugs like TCAs, removing the benzodiazepine''s protective sedative/anticonvulsant effect with flumazenil can precipitate life-threatening seizures.', 'Pre-Council', '🎓', true),
(7777, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient presents with tinnitus, hyperventilation, nausea, vomiting, and a mixed respiratory alkalosis/metabolic acidosis on ABG after ingesting a large number of tablets. Which overdose is most consistent with this picture?', '["Salicylate (aspirin) overdose", "Opioid overdose", "Beta-blocker overdose", "Benzodiazepine overdose"]'::jsonb, 0, 'Salicylate toxicity classically causes early respiratory alkalosis (direct respiratory centre stimulation) followed by a high anion-gap metabolic acidosis, along with tinnitus, hyperventilation, and vomiting.', 'Pre-Council', '🎓', true),
(7778, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'What is a key management strategy for moderate-to-severe salicylate poisoning to enhance elimination of the drug?', '["Urinary alkalinisation with IV sodium bicarbonate to ion-trap salicylate in the urine and promote excretion", "Urinary acidification with ammonium chloride", "Induced hypothermia", "Administration of flumazenil"]'::jsonb, 0, 'Alkalinising the urine with sodium bicarbonate ionises salicylate, preventing its reabsorption in the renal tubules and enhancing urinary excretion; severe cases may require haemodialysis.', 'Pre-Council', '🎓', true),
(7779, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient with beta-blocker overdose presents with severe bradycardia and hypotension refractory to atropine. Which agent is most appropriate as a specific treatment?', '["High-dose insulin with glucose (hyperinsulinaemia-euglycaemia therapy) and/or glucagon", "Naloxone", "Flumazenil", "Activated charcoal given IV"]'::jsonb, 0, 'Glucagon bypasses the blocked beta-receptor to increase intracellular cAMP, improving heart rate and contractility, and high-dose insulin/glucose therapy improves myocardial energy utilisation in severe beta-blocker toxicity.', 'Pre-Council', '🎓', true),
(7780, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Which finding helps clinically distinguish severe beta-blocker overdose from severe calcium channel blocker overdose, since both cause bradycardia and hypotension?', '["Hyperglycaemia is more typical of calcium channel blocker overdose, while beta-blocker overdose is more likely to cause hypoglycaemia", "Calcium channel blocker overdose never causes hypotension", "Beta-blocker overdose always causes hyperthermia", "Only calcium channel blocker overdose causes bradycardia"]'::jsonb, 0, 'Calcium channel blockers impair pancreatic insulin release, often causing hyperglycaemia, while beta-blockers can cause hypoglycaemia by blocking hepatic glycogenolysis; both are important clinical clues in an undifferentiated overdose.', 'Pre-Council', '🎓', true),
(7781, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'IV calcium is a specific therapy for which type of overdose?', '["Calcium channel blocker overdose", "Opioid overdose", "Benzodiazepine overdose", "Salicylate overdose"]'::jsonb, 0, 'IV calcium chloride or calcium gluconate can help overcome the calcium channel blockade, improving myocardial contractility and vascular tone in calcium channel blocker toxicity.', 'Pre-Council', '🎓', true),
(7782, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient with chronic lithium therapy presents with coarse tremor, ataxia, confusion, and hyperreflexia. Serum lithium is significantly elevated. What is the definitive treatment for severe lithium toxicity?', '["Haemodialysis", "Activated charcoal", "N-acetylcysteine", "Flumazenil"]'::jsonb, 0, 'Lithium is not bound by activated charcoal and has a small molecular size and volume of distribution favourable for dialysis; haemodialysis is the definitive treatment for severe or renal-impaired lithium toxicity.', 'Pre-Council', '🎓', true),
(7783, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Why is activated charcoal not useful in lithium overdose?', '["Lithium is a small ionised element that is not adsorbed by activated charcoal", "Lithium overdose never requires any decontamination", "Activated charcoal is contraindicated in all metal poisonings", "Lithium is too large a molecule to reach the gut"]'::jsonb, 0, 'Activated charcoal works by adsorbing organic compounds onto its surface; lithium is a small inorganic ion that is not effectively bound by charcoal, so alternative measures such as whole bowel irrigation or dialysis are used instead.', 'Pre-Council', '🎓', true),
(7784, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient with iron tablet overdose is being assessed. Which statement about activated charcoal in this scenario is correct?', '["Activated charcoal does not effectively bind iron, so it is not recommended for iron overdose", "Activated charcoal is the first-line treatment for iron overdose", "Activated charcoal should be given regardless of the poison ingested", "Activated charcoal is only contraindicated for paracetamol overdose"]'::jsonb, 0, 'Iron is a metal ion and, like lithium, is poorly adsorbed by activated charcoal; whole bowel irrigation and deferoxamine chelation are used instead when indicated.', 'Pre-Council', '🎓', true),
(7785, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'What is the specific chelating agent used in severe iron poisoning?', '["Deferoxamine", "Naloxone", "Pralidoxime", "N-acetylcysteine"]'::jsonb, 0, 'Deferoxamine binds free iron to form ferrioxamine, which is water-soluble and renally excreted, and is used in severe iron toxicity with systemic symptoms or high serum iron levels.', 'Pre-Council', '🎓', true),
(7786, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient presents with a decreased level of consciousness, and the treating team suspects a mixed sedative overdose. Which initial assessment priority takes precedence over identifying the specific substance ingested?', '["Airway, breathing, and circulation (ABCs) with immediate stabilisation of any compromise", "Obtaining a detailed history of exactly what was ingested and when", "Sending blood for a full toxicology screen before any intervention", "Contacting the patient''s next of kin for consent"]'::jsonb, 0, 'In any overdose or poisoning, securing and supporting the airway, breathing, and circulation always takes priority over identifying the specific toxin, as untreated ABC compromise is the most immediate threat to life.', 'Pre-Council', '🎓', true),
(7787, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Which assessment tool is most useful at the bedside for rapidly estimating the severity of CNS depression in a patient with a suspected sedative or opioid overdose?', '["Glasgow Coma Scale (GCS)", "Body mass index", "Braden scale", "APGAR score"]'::jsonb, 0, 'The Glasgow Coma Scale provides a rapid, reproducible measure of level of consciousness, guiding decisions about airway protection and the urgency of intervention in overdose.', 'Pre-Council', '🎓', true),
(7788, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient with a suspected overdose of unknown substance is unconscious with a GCS of 6 and shallow, slow respirations. What is the most immediate nursing priority?', '["Prepare for airway protection (e.g., positioning, suction, possible intubation) and provide ventilatory support", "Administer activated charcoal orally", "Obtain a detailed medication history from family", "Send the patient for an urgent CT scan of the head"]'::jsonb, 0, 'A GCS of 8 or less generally indicates the patient cannot protect their own airway; securing the airway and supporting ventilation is the immediate life-saving priority before any decontamination or diagnostic procedure.', 'Pre-Council', '🎓', true),
(7789, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Why should naloxone be given cautiously, in small titrated doses, to a patient who is a known chronic opioid user presenting with overdose?', '["Rapid, full-dose reversal can precipitate acute opioid withdrawal, agitation, and severe pain", "Naloxone has no effect in chronic opioid users", "Small doses of naloxone are always ineffective", "Naloxone causes permanent respiratory depression in chronic users"]'::jsonb, 0, 'In opioid-tolerant patients, giving a full reversal dose abruptly can precipitate acute withdrawal syndrome, severe agitation, vomiting, and cardiovascular stress; titrating to adequate respiration while avoiding full arousal is preferred.', 'Pre-Council', '🎓', true),
(7790, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient with methanol or ethylene glycol poisoning is being managed. Which agent competitively inhibits alcohol dehydrogenase and is used as an antidote?', '["Fomepizole (or ethanol as an alternative)", "Naloxone", "Atropine", "Flumazenil"]'::jsonb, 0, 'Fomepizole blocks alcohol dehydrogenase, preventing the metabolism of methanol/ethylene glycol into their toxic metabolites (formic acid / glycolic and oxalic acid); ethanol can be used similarly where fomepizole is unavailable.', 'Pre-Council', '🎓', true),
(7791, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'What is the rationale for administering IV ethanol (when fomepizole is unavailable) in methanol poisoning?', '["Ethanol has a higher affinity for alcohol dehydrogenase than methanol, blocking the formation of toxic formic acid", "Ethanol directly neutralises methanol chemically", "Ethanol increases renal excretion of methanol", "Ethanol reduces gastric absorption of methanol"]'::jsonb, 0, 'Ethanol competes with methanol for alcohol dehydrogenase; because it is preferentially metabolised, it slows conversion of methanol into toxic formic acid, buying time for elimination or dialysis.', 'Pre-Council', '🎓', true),
(7792, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient with carbon monoxide poisoning has a normal-appearing SpO2 reading on pulse oximetry despite clinical signs of hypoxia. Why is pulse oximetry unreliable in this situation?', '["Standard pulse oximetry cannot distinguish carboxyhaemoglobin from oxyhaemoglobin, so it gives a falsely normal or high reading", "Pulse oximetry is never accurate in any critically ill patient", "Carbon monoxide destroys the pulse oximeter probe", "Carbon monoxide poisoning always causes cyanosis, which is visible without oximetry"]'::jsonb, 0, 'Standard two-wavelength pulse oximeters cannot differentiate carboxyhaemoglobin from oxyhaemoglobin, so SpO2 remains falsely reassuring; co-oximetry or arterial blood gas measurement of carboxyhaemoglobin is required for accurate assessment.', 'Pre-Council', '🎓', true),
(7793, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'What is the first-line treatment for significant carbon monoxide poisoning?', '["High-flow 100% oxygen via non-rebreather mask (or hyperbaric oxygen in severe cases)", "IV naloxone", "Activated charcoal", "IV flumazenil"]'::jsonb, 0, 'High-flow 100% oxygen dramatically shortens the half-life of carboxyhaemoglobin, displacing carbon monoxide from haemoglobin; hyperbaric oxygen is reserved for severe cases (e.g., loss of consciousness, pregnancy, cardiac ischaemia).', 'Pre-Council', '🎓', true),
(7794, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient with severe cyanide poisoning is being treated. Which of the following is used as part of cyanide antidote therapy?', '["Hydroxocobalamin", "Naloxone", "Atropine", "Deferoxamine"]'::jsonb, 0, 'Hydroxocobalamin binds cyanide ions to form cyanocobalamin (vitamin B12), which is renally excreted, and is a first-line antidote for cyanide toxicity.', 'Pre-Council', '🎓', true),
(7795, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient develops serotonin syndrome after combining an SSRI with another serotonergic drug, presenting with agitation, hyperreflexia, clonus, hyperthermia, and autonomic instability. What is a key element of management?', '["Discontinue all serotonergic agents, provide supportive cooling and sedation with benzodiazepines, and consider cyproheptadine in severe cases", "Administer more of the same serotonergic drug to allow tolerance to develop", "Administer naloxone as the first-line antidote", "Restrict fluids to prevent worsening hyperthermia"]'::jsonb, 0, 'Management of serotonin syndrome centres on stopping causative agents, supportive care (cooling, IV fluids, benzodiazepines for agitation/rigidity), and cyproheptadine (a serotonin antagonist) for moderate-to-severe cases.', 'Pre-Council', '🎓', true),
(7796, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'How can serotonin syndrome be distinguished clinically from neuroleptic malignant syndrome (NMS), given both cause hyperthermia and altered mental status?', '["Serotonin syndrome typically has hyperreflexia and clonus with rapid onset, while NMS features ''lead-pipe'' rigidity and bradyreflexia with a slower onset over days", "NMS always occurs faster, within minutes of drug exposure", "Serotonin syndrome causes muscle flaccidity rather than increased tone", "There is no clinically useful way to distinguish the two conditions"]'::jsonb, 0, 'Serotonin syndrome tends to develop rapidly (within 24 hours) with hyperreflexia, clonus, and tremor, whereas NMS evolves more slowly (days) after antipsychotic exposure with severe ''lead-pipe'' rigidity and reduced reflexes.', 'Pre-Council', '🎓', true),
(7797, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient with an unknown overdose has a widened anion gap metabolic acidosis on blood gas analysis. Which mnemonic-based category of toxins should be considered as a potential cause?', '["Toxins such as methanol, ethylene glycol, salicylates, and metformin (causing lactic acidosis)", "Only opioids can cause a raised anion gap", "Benzodiazepines are the most common cause of raised anion gap acidosis", "A raised anion gap always indicates renal failure and never toxic ingestion"]'::jsonb, 0, 'The mnemonic ''MUDPILES'' (methanol, uraemia, DKA, propylene glycol/paraldehyde, isoniazid/iron, lactic acidosis, ethylene glycol, salicylates) reminds clinicians of toxic and metabolic causes of a raised anion gap acidosis.', 'Pre-Council', '🎓', true),
(7798, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient who took a large overdose of a sustained-release calcium channel blocker several hours ago remains asymptomatic on arrival. What is the most appropriate nursing action?', '["Admit for prolonged cardiac monitoring, as sustained-release preparations can cause delayed and prolonged toxicity", "Discharge immediately since the patient is currently asymptomatic", "No monitoring is required if the initial ECG is normal", "Administer flumazenil prophylactically"]'::jsonb, 0, 'Sustained-release formulations can have delayed absorption and prolonged toxic effects; patients require extended observation and cardiac monitoring even if initially asymptomatic, as life-threatening bradycardia and hypotension can develop hours later.', 'Pre-Council', '🎓', true),
(7799, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'What is the correct first step in the general management of any poisoned patient, regardless of the substance involved?', '["Assess and stabilise airway, breathing, and circulation (ABCs)", "Identify the exact poison ingested", "Administer activated charcoal immediately", "Induce vomiting to remove the poison"]'::jsonb, 0, 'As with all emergencies, securing and stabilising the airway, breathing, and circulation takes priority over decontamination or specific antidote administration in poisoning management.', 'Pre-Council', '🎓', true),
(7800, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Why is inducing vomiting (e.g., with syrup of ipecac) no longer recommended in most cases of poisoning?', '["It has not been shown to improve outcomes, delays more effective treatments, and risks aspiration, especially with reduced consciousness", "It is the most effective way to remove all types of poison from the body", "It works well even in unconscious patients", "It is recommended for all poisonings regardless of the substance"]'::jsonb, 0, 'Current poison management guidelines have largely abandoned induced emesis because of lack of proven outcome benefit, delay of definitive care, and significant risk of pulmonary aspiration, particularly in patients with reduced consciousness.', 'Pre-Council', '🎓', true),
(7801, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'In which situation is inducing vomiting absolutely contraindicated?', '["After ingestion of a corrosive substance (acid or alkali) or a hydrocarbon, or in a patient with reduced level of consciousness", "In a fully conscious patient who ingested a small dose of a non-corrosive tablet", "When the ingestion occurred less than one hour ago", "When the patient is a healthy young adult"]'::jsonb, 0, 'Inducing vomiting after caustic or hydrocarbon ingestion risks further oesophageal/airway injury or aspiration pneumonitis, and in a patient with reduced consciousness it risks aspiration of gastric contents; these are absolute contraindications.', 'Pre-Council', '🎓', true),
(7802, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient has ingested a corrosive alkali substance (e.g., drain cleaner). What is the appropriate immediate management?', '["Do not induce vomiting or attempt neutralisation; assess airway for burns and provide supportive care with early surgical/GI referral", "Give large volumes of water to dilute followed by induced vomiting", "Give vinegar to neutralise the alkali", "Insert a nasogastric tube and perform gastric lavage immediately"]'::jsonb, 0, 'Corrosive ingestions should not be treated with induced vomiting (risk of re-exposing the oesophagus) or chemical neutralisation (exothermic reaction risk); careful airway assessment and early endoscopy/surgical input guide safe management.', 'Pre-Council', '🎓', true),
(7803, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Which of the following is the most widely used method of gut decontamination in modern poisoning management, when indicated?', '["Single-dose activated charcoal", "Induced vomiting with ipecac", "Gastric lavage as routine for all poisonings", "Whole bowel irrigation for all ingestions"]'::jsonb, 0, 'Single-dose activated charcoal, given early after ingestion of an appropriate toxin, is the most commonly used and best-evidenced gut decontamination method in current poisoning management.', 'Pre-Council', '🎓', true),
(7804, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Activated charcoal works by which mechanism to reduce systemic absorption of an ingested poison?', '["It adsorbs the toxin onto its large surface area within the gastrointestinal tract, preventing systemic absorption", "It chemically neutralises acids and alkalis", "It induces vomiting to expel the toxin", "It increases intestinal motility to speed transit"]'::jsonb, 0, 'Activated charcoal has an enormous surface area that binds many drugs and toxins within the gut lumen, preventing or reducing their absorption into the systemic circulation.', 'Pre-Council', '🎓', true),
(7805, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Which of the following substances is NOT effectively adsorbed by activated charcoal?', '["Iron, lithium, and alcohols", "Aspirin (salicylates)", "Tricyclic antidepressants", "Paracetamol"]'::jsonb, 0, 'Activated charcoal poorly adsorbs small, highly ionised or hydrophilic substances such as metals (iron, lithium), alcohols, cyanide, and strong acids/alkalis; it is effective for many organic drugs including salicylates, TCAs, and paracetamol.', 'Pre-Council', '🎓', true),
(7806, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'What is the ideal time window after ingestion for activated charcoal to be most effective?', '["Within 1 hour of ingestion", "Within 24 hours of ingestion", "Only after 6 hours have passed", "Activated charcoal has no time-dependent efficacy"]'::jsonb, 0, 'Activated charcoal is most effective when given within 1 hour of ingestion, before significant absorption of the toxin has occurred, although it may still have benefit later for drugs that delay gastric emptying or have enterohepatic recirculation.', 'Pre-Council', '🎓', true),
(7807, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'In which clinical situation is activated charcoal contraindicated?', '["A patient with an unprotected airway and reduced level of consciousness, due to aspiration risk", "A conscious, cooperative patient who ingested a toxic dose of paracetamol 30 minutes ago", "A patient who ingested a large dose of aspirin 45 minutes ago", "A patient with a normal GCS and intact gag reflex"]'::jsonb, 0, 'Activated charcoal should not be given to a patient with a compromised airway or depressed consciousness unless the airway is first protected (e.g., by intubation), because of the high risk of aspiration.', 'Pre-Council', '🎓', true),
(7808, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Why is activated charcoal generally avoided after ingestion of a hydrocarbon (e.g., kerosene or petrol)?', '["It does not effectively adsorb hydrocarbons and increases the risk of vomiting and subsequent aspiration pneumonitis", "It reacts explosively with hydrocarbons", "It is the treatment of choice for all hydrocarbon ingestions", "Hydrocarbons are not toxic, so no treatment is needed"]'::jsonb, 0, 'Hydrocarbons are poorly adsorbed by charcoal, and the low viscosity of these substances combined with charcoal-induced vomiting significantly raises the risk of aspiration and chemical pneumonitis.', 'Pre-Council', '🎓', true),
(7809, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Multiple-dose activated charcoal (repeated doses) is particularly useful for enhancing elimination of which type of drug overdose?', '["Drugs with enterohepatic recirculation or sustained-release preparations, such as carbamazepine, theophylline, or phenobarbital", "Iron overdose", "Lithium overdose", "Ethylene glycol poisoning"]'::jsonb, 0, 'Multiple-dose activated charcoal creates a concentration gradient that continues to draw drug from the bloodstream into the gut (''gut dialysis''), which is particularly useful for drugs undergoing enterohepatic recirculation or sustained-release formulations.', 'Pre-Council', '🎓', true),
(7810, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Gastric lavage (stomach pumping) is now reserved for which limited scenario in poisoning management?', '["Rarely used; may be considered within 1 hour of ingestion of a life-threatening amount of poison, with airway protection, when no better alternative exists", "As routine first-line treatment for all poisonings", "For any patient regardless of the substance or time since ingestion", "As a replacement for activated charcoal in every case"]'::jsonb, 0, 'Gastric lavage carries significant risks (aspiration, oesophageal injury, vagal stimulation) and has not been shown to improve outcomes routinely; it is now rarely used, reserved for select cases of very recent, potentially life-threatening ingestion.', 'Pre-Council', '🎓', true),
(7811, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Whole bowel irrigation using a polyethylene glycol solution is particularly indicated for which type of poisoning?', '["Ingestion of substances poorly bound by charcoal, such as iron, lithium, or sustained-release/enteric-coated tablets, or in body packers", "All paracetamol overdoses", "All benzodiazepine overdoses", "Opioid overdose with respiratory depression"]'::jsonb, 0, 'Whole bowel irrigation mechanically flushes the entire GI tract and is most useful for toxins poorly adsorbed by charcoal (iron, lithium), sustained-release preparations, or in patients who have ingested packets of illicit drugs (''body packers'').', 'Pre-Council', '🎓', true),
(7812, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient arrives after ingesting an unknown quantity of tablets. Which piece of history-taking information is most critical for guiding immediate management?', '["What substance(s) were taken, the estimated amount, and the time of ingestion", "The patient''s favourite type of beverage", "The patient''s occupation", "The patient''s marital status"]'::jsonb, 0, 'Knowing what was taken, how much, and when directly determines the urgency and type of decontamination, the need for specific antidotes, and the expected time course of toxicity.', 'Pre-Council', '🎓', true),
(7813, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'In the initial assessment of a poisoned patient, why is blood glucose measurement considered an essential rapid bedside test?', '["Hypoglycaemia can cause or mimic altered consciousness and is rapidly correctable; many toxins also affect glucose metabolism", "Blood glucose has no relevance to poisoning management", "Only diabetic patients need glucose checked", "Glucose testing replaces the need for a full assessment"]'::jsonb, 0, 'Hypoglycaemia is a rapidly reversible cause of altered mental status that must be excluded in any patient with reduced consciousness, and several toxins (e.g., insulin, sulfonylureas, beta-blockers) directly affect glucose levels.', 'Pre-Council', '🎓', true),
(7814, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A poison information centre or toxicology reference (e.g., TOXBASE) is best used for which purpose in critical care?', '["To obtain up-to-date, substance-specific guidance on management, expected toxicity, and antidote dosing for a specific poisoning case", "To replace clinical assessment and vital sign monitoring entirely", "Only for paediatric poisonings", "Only when the patient is unconscious"]'::jsonb, 0, 'Poison information services provide current, evidence-based guidance tailored to a specific substance and exposure, supporting clinical decision-making alongside, not instead of, ongoing assessment and monitoring.', 'Pre-Council', '🎓', true),
(7815, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Which vital principle applies to decontamination of a patient exposed to a poison via the skin, such as an organophosphate pesticide?', '["Remove contaminated clothing and thoroughly irrigate the skin with water, while protecting staff from secondary contamination", "No skin decontamination is necessary if the patient is asymptomatic", "Rubbing the skin vigorously with a dry cloth is sufficient", "Skin decontamination should be delayed until after IV access is obtained"]'::jsonb, 0, 'Prompt removal of contaminated clothing and irrigation with water reduces ongoing dermal absorption of the toxin, and staff must wear appropriate personal protective equipment to prevent secondary exposure themselves.', 'Pre-Council', '🎓', true),
(7816, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient with suspected snake envenomation presents with local swelling, bleeding gums, and prolonged clotting times. What is the priority definitive treatment?', '["Appropriate antivenom, guided by the type of snake and clinical/laboratory features of envenomation", "Application of a tight arterial tourniquet above the bite", "Incision and suction of the bite site", "Immediate amputation of the affected limb"]'::jsonb, 0, 'Antivenom is the definitive treatment for significant envenomation; outdated first-aid measures such as tourniquets, incision, and suction are now discouraged as they can worsen local tissue damage without preventing systemic toxicity.', 'Pre-Council', '🎓', true),
(7817, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'What is the recommended first-aid measure for a bite from a neurotoxic elapid snake (e.g., cobra) prior to reaching definitive care?', '["Pressure immobilisation bandaging of the bitten limb with splinting, keeping the patient still", "Application of ice directly to the bite site", "Cutting the wound and sucking out venom", "Applying a tight arterial tourniquet"]'::jsonb, 0, 'Pressure immobilisation bandaging slows lymphatic spread of neurotoxic venom without cutting off arterial blood flow, and is currently recommended first aid while arranging transport to a facility with antivenom.', 'Pre-Council', '🎓', true),
(7818, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient with suspected food poisoning from Clostridium botulinum presents with descending paralysis, diplopia, and dysphagia, with a clear sensorium. What is the priority nursing concern?', '["Close monitoring of respiratory function, as respiratory muscle paralysis can develop and require ventilatory support", "Administering activated charcoal, since this is the priority treatment", "Restricting fluids to prevent worsening symptoms", "Reassuring the patient that no monitoring is required since consciousness is preserved"]'::jsonb, 0, 'Botulinum toxin causes a descending flaccid paralysis that can progress to respiratory failure; vigilant monitoring of respiratory effort and vital capacity is essential, with early consideration of ventilatory support.', 'Pre-Council', '🎓', true),
(7819, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient presents with poisoning from ingestion of a substance containing methanol found in illicitly distilled alcohol (''moonshine''). Which clinical feature is a classic warning sign of methanol toxicity?', '["Visual disturbances or blindness due to optic nerve toxicity from formic acid accumulation", "Bright red skin discolouration", "Excessive salivation and lacrimation", "Pinpoint pupils"]'::jsonb, 0, 'Methanol is metabolised to formic acid, which is particularly toxic to the retina and optic nerve, classically causing blurred vision, blindness, and a metabolic acidosis with a raised anion and osmolar gap.', 'Pre-Council', '🎓', true),
(7820, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'In mass-casualty or unclear poisoning scenarios, what is the value of calculating the osmolar gap?', '["An elevated osmolar gap suggests the presence of unmeasured osmotically active substances such as methanol, ethylene glycol, or ethanol", "The osmolar gap is only useful in diabetic ketoacidosis", "The osmolar gap has no role in toxicology", "A normal osmolar gap rules out all types of poisoning"]'::jsonb, 0, 'The osmolar gap (measured minus calculated osmolality) rises in the presence of unmeasured low-molecular-weight substances like toxic alcohols, providing an early clue to their ingestion before specific levels are available.', 'Pre-Council', '🎓', true),
(7821, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient with suspected mushroom poisoning develops severe gastroenteritis 6-24 hours after ingestion, followed by signs of liver failure over the next several days. Which type of mushroom toxin is most likely responsible?', '["Amatoxin-containing mushrooms (e.g., Amanita phalloides)", "Muscarine-containing mushrooms", "Psilocybin-containing mushrooms", "Ibotenic acid-containing mushrooms"]'::jsonb, 0, 'Amatoxins cause a delayed onset of severe gastroenteritis followed by progressive hepatotoxicity and potential fulminant liver failure over several days, a pattern distinct from the rapid-onset toxidromes of other mushroom toxins.', 'Pre-Council', '🎓', true),
(7822, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient presents with poisoning after ingesting rodenticide containing a long-acting anticoagulant (superwarfarin). What is the appropriate treatment if bleeding or a significantly elevated INR develops?', '["Vitamin K1, with prolonged (potentially weeks-long) therapy due to the long half-life of superwarfarins", "A single dose of naloxone", "Immediate whole blood transfusion regardless of INR", "Activated charcoal alone, with no other treatment"]'::jsonb, 0, 'Superwarfarin rodenticides have a very long half-life and can cause prolonged coagulopathy; vitamin K1 is the antidote, often required for weeks with close INR monitoring after significant ingestion.', 'Pre-Council', '🎓', true),
(7823, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient poisoned with an unknown substance develops methaemoglobinaemia, evidenced by cyanosis unresponsive to supplemental oxygen and chocolate-brown blood. What is the specific antidote?', '["Methylene blue", "Naloxone", "Atropine", "Flumazenil"]'::jsonb, 0, 'Methylene blue acts as an electron donor that helps reduce methaemoglobin back to functional haemoglobin via the NADPH-methaemoglobin reductase pathway, and is the specific antidote for symptomatic methaemoglobinaemia.', 'Pre-Council', '🎓', true),
(7824, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Why does pulse oximetry give an unreliable reading in a patient with significant methaemoglobinaemia?', '["Methaemoglobin absorbs light at both wavelengths used by standard pulse oximeters, driving the SpO2 reading toward approximately 85% regardless of true oxygen saturation", "Methaemoglobinaemia has no effect on pulse oximetry readings", "Pulse oximetry always reads falsely low in methaemoglobinaemia", "Methaemoglobin destroys the pulse oximeter sensor"]'::jsonb, 0, 'Methaemoglobin absorbs light differently from oxyhaemoglobin and deoxyhaemoglobin, causing standard two-wavelength pulse oximeters to trend toward a falsely fixed reading around 85%, regardless of the true saturation; co-oximetry is needed for an accurate value.', 'Pre-Council', '🎓', true),
(7825, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Which statement best describes the role of haemodialysis in poisoning management?', '["It is useful for toxins that are small, water-soluble, have low protein binding, and a small volume of distribution, such as salicylates, lithium, methanol, and ethylene glycol", "Haemodialysis is effective for removing all types of poisons regardless of their properties", "Haemodialysis is never used in toxicology", "Haemodialysis is only used for opioid overdose"]'::jsonb, 0, 'Drugs amenable to dialysis typically have low molecular weight, low protein binding, small volume of distribution, and high water solubility; classic examples include salicylates, lithium, methanol, ethylene glycol, and severe metformin-associated lactic acidosis.', 'Pre-Council', '🎓', true),
(7826, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient with severe theophylline toxicity develops refractory seizures and life-threatening arrhythmias. Beyond supportive care and multiple-dose activated charcoal, which additional treatment may be indicated in severe cases?', '["Haemodialysis or haemoperfusion", "Oral rehydration therapy alone", "Discontinuation of all monitoring", "Induced vomiting"]'::jsonb, 0, 'In severe, life-threatening theophylline toxicity with seizures or arrhythmias refractory to supportive measures, extracorporeal removal via haemodialysis or haemoperfusion may be necessary.', 'Pre-Council', '🎓', true),
(7827, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient has ingested button (disc) batteries. What is the priority concern that necessitates urgent action?', '["Risk of oesophageal impaction causing electrical burns and perforation, requiring urgent imaging and endoscopic removal if lodged in the oesophagus", "Button batteries are inert and require no specific action", "The main risk is only from battery leakage of heavy metals, not mechanical injury", "Batteries should be removed by inducing vomiting"]'::jsonb, 0, 'A button battery lodged in the oesophagus can generate a local electrical current causing rapid tissue necrosis and perforation within hours; urgent X-ray localisation and endoscopic removal is a time-critical emergency.', 'Pre-Council', '🎓', true),
(7828, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'During the primary survey of a poisoned patient, why is temperature (core body temperature) an important vital sign to assess early?', '["Many toxins cause hyperthermia or hypothermia, both of which require prompt correction and can indicate specific toxidromes", "Temperature is only relevant in infectious disease, not toxicology", "Hypothermia never occurs in poisoning", "Temperature monitoring can safely be deferred until after discharge"]'::jsonb, 0, 'Hyperthermia (e.g., sympathomimetics, anticholinergics, serotonin syndrome, salicylates) and hypothermia (e.g., sedative-hypnotic or opioid overdose with prolonged exposure) both require prompt recognition and active correction, and help narrow the differential diagnosis.', 'Pre-Council', '🎓', true),
(7829, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A nurse is caring for a patient after a deliberate self-poisoning episode. Once the patient is medically stable, what is an essential next step in holistic care?', '["Psychiatric assessment to evaluate suicide risk and underlying mental health needs before discharge", "Immediate discharge home without further assessment once vital signs normalise", "No further assessment is needed if the overdose was small", "Referral is only necessary if the patient requests it"]'::jsonb, 0, 'All patients presenting after deliberate self-poisoning require a formal psychiatric/risk assessment prior to discharge, as medical stabilisation addresses only the physical consequences, not the underlying risk of repeat self-harm.', 'Pre-Council', '🎓', true),
(7830, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'What distinguishes ''decontamination'' from ''enhanced elimination'' in the management of poisoning?', '["Decontamination prevents further absorption of a toxin already in or on the body (e.g., charcoal, skin irrigation), while enhanced elimination actively removes absorbed toxin from the circulation (e.g., dialysis, urinary alkalinisation)", "The two terms mean exactly the same thing", "Decontamination refers only to hospital cleaning procedures", "Enhanced elimination refers only to inducing vomiting"]'::jsonb, 0, 'Decontamination (gut, skin, or eye) limits further absorption of unabsorbed toxin, whereas enhanced elimination techniques (haemodialysis, urinary alkalinisation, multiple-dose charcoal) increase clearance of toxin that has already entered the systemic circulation.', 'Pre-Council', '🎓', true),
(7831, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient poisoned with an organophosphate develops copious respiratory secretions and bronchospasm. In addition to atropine, what other supportive measure is critical?', '["Frequent suctioning and airway management, as secretions can rapidly compromise the airway", "Restricting oxygen administration", "Withholding all fluids", "Positioning the patient supine without airway support"]'::jsonb, 0, 'Organophosphate poisoning causes profuse bronchorrhoea and bronchospasm that can rapidly obstruct the airway; alongside atropine to reduce secretions, vigilant suctioning and airway/ventilatory support are essential.', 'Pre-Council', '🎓', true),
(7832, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Which statement about the use of ipecac syrup in modern hospital-based poisoning management is correct?', '["It is no longer routinely recommended by most poison control and toxicology guidelines due to lack of proven benefit and safety concerns", "It remains the first-line treatment for all poisonings in hospital", "It should be given routinely to all paediatric ingestions", "It is safe to use even in patients with a depressed level of consciousness"]'::jsonb, 0, 'Ipecac-induced emesis has fallen out of favour because it has not been shown to improve clinical outcomes, can delay more effective treatments like activated charcoal, and carries aspiration risk.', 'Pre-Council', '🎓', true),
(7833, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A toddler is brought to the emergency department after suspected ingestion of a caregiver''s iron supplement tablets. Which laboratory or clinical clue would raise concern for significant iron toxicity requiring chelation?', '["Elevated serum iron level with signs of GI bleeding, metabolic acidosis, and shock", "A normal serum iron level with no symptoms", "Mild constipation only", "Elevated haemoglobin level"]'::jsonb, 0, 'Significant iron toxicity presents with GI haemorrhage, hypotension/shock, and a high anion-gap metabolic acidosis due to mitochondrial toxicity; serum iron levels above the total iron-binding capacity indicate free circulating iron requiring deferoxamine chelation.', 'Pre-Council', '🎓', true),
(7834, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'Why is early consultation with a poison control centre or clinical toxicologist particularly valuable in paediatric poisoning cases?', '["Children can be exquisitely sensitive to even small doses of certain substances, and thresholds for toxicity, monitoring, and treatment often differ significantly from adults", "Children are always less susceptible to poisoning than adults", "Poison control centres only manage adult cases", "Paediatric poisoning never requires specialist input"]'::jsonb, 0, 'Paediatric toxicology has unique dosing thresholds, physiological vulnerabilities, and monitoring requirements; specialist poison information services provide crucial substance- and weight-specific guidance to avoid under- or over-treatment.', 'Pre-Council', '🎓', true),
(7835, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A patient with suspected poisoning is due to have activated charcoal, but has vomited twice and has a reduced gag reflex. What should the nurse do?', '["Withhold charcoal and reassess airway protection needs, seeking senior/medical input before proceeding", "Administer the charcoal via nasogastric tube regardless of airway status", "Give the charcoal orally in smaller sips", "Delay all care until the toxicology screen result is available"]'::jsonb, 0, 'A reduced gag reflex and active vomiting indicate a significant aspiration risk; charcoal should not be given until the airway is adequately protected, and escalation for senior assessment (possible intubation) is warranted.', 'Pre-Council', '🎓', true),
(7836, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'In caring for a patient who has ingested a caustic substance, why is passing a nasogastric tube generally avoided in the acute phase?', '["It risks perforating a chemically weakened and friable oesophagus", "It is required to confirm the diagnosis in all cases", "It has no associated risks in caustic ingestion", "It is the standard method of decontamination for caustics"]'::jsonb, 0, 'Corrosive injury can severely weaken the oesophageal wall, and blind passage of a nasogastric tube risks perforation; endoscopic assessment by a specialist is preferred to evaluate the extent of injury safely.', 'Pre-Council', '🎓', true),
(7837, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'What is the significance of obtaining serial ECGs in a patient with an unknown or mixed drug overdose?', '["Many toxins cause characteristic ECG changes (e.g., QRS or QT prolongation) that can help identify the toxin class and detect evolving cardiotoxicity", "ECGs have no diagnostic value in toxicology", "A single normal ECG on arrival excludes all cardiotoxicity for the rest of the admission", "ECG changes only matter in patients with pre-existing heart disease"]'::jsonb, 0, 'Serial ECGs can reveal evolving toxin-induced conduction abnormalities (e.g., TCA-induced QRS widening, sotalol/citalopram-induced QT prolongation), which may develop or worsen over time and guide the need for specific therapy.', 'Pre-Council', '🎓', true),
(7838, 'Principles of Drug Administration', 'CCN Curriculum — Applied Pharmacology', 'A conscious adult presents 20 minutes after ingesting a toxic dose of a drug known to be well-adsorbed by charcoal. Which of the following best supports giving activated charcoal in this case?', '["The patient is within the optimal early time window, is conscious with an intact airway, and has ingested a charcoal-responsive substance", "The patient ingested the drug more than 12 hours ago", "The substance ingested is a corrosive acid", "The patient has a reduced level of consciousness with no airway protection"]'::jsonb, 0, 'Activated charcoal is most beneficial when given soon after ingestion (ideally within an hour) of a charcoal-responsive toxin in a patient who can safely protect their airway — all criteria met in this scenario.', 'Pre-Council', '🎓', true),
(7839, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Which of the following is an absolute indication for initiating invasive mechanical ventilation?', '["Apnea with respiratory arrest", "Mild hypoxemia responsive to nasal cannula oxygen", "Chronic stable COPD with SpO2 90%", "Post-operative sedation for 1 hour"]'::jsonb, 0, 'Apnea/respiratory arrest is an absolute, unequivocal indication for immediate intubation and mechanical ventilation.', 'Pre-Council', '🎓', true),
(7840, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'In assist-control (AC) ventilation, what happens if the patient initiates a spontaneous breath above the set rate?', '["The breath is unsupported and the patient breathes room air", "The ventilator delivers the full preset tidal volume/pressure for that breath", "The ventilator ignores the effort until the next set breath", "The machine automatically switches to SIMV"]'::jsonb, 1, 'In AC mode every patient-triggered breath receives full ventilator support, which can lead to hyperventilation and breath-stacking in tachypneic patients.', 'Pre-Council', '🎓', true),
(7841, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'A patient in SIMV mode breathes spontaneously between mandatory breaths. What determines the tidal volume of these spontaneous breaths?', '["The set tidal volume on the ventilator", "The set PEEP level", "The patient''s own effort, with support only from pressure support if added", "The inspiratory flow rate alone"]'::jsonb, 2, 'Spontaneous breaths between SIMV mandatory breaths are generated by the patient''s own effort; volume depends on patient effort and lung mechanics unless pressure support is added.', 'Pre-Council', '🎓', true),
(7842, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Which parameter setting is primarily responsible for oxygenation rather than ventilation (CO2 removal)?', '["Respiratory rate", "Tidal volume", "I:E ratio", "FiO2 and PEEP"]'::jsonb, 3, 'Oxygenation is governed mainly by FiO2 and mean airway pressure/PEEP, whereas ventilation (CO2 clearance) is governed by minute ventilation (rate x tidal volume).', 'Pre-Council', '🎓', true),
(7843, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'A patient''s minute ventilation is inadequate and PaCO2 is rising. Which ventilator adjustment would most directly improve CO2 clearance?', '["Increase FiO2", "Increase respiratory rate or tidal volume", "Increase PEEP", "Increase inspiratory pressure limit only"]'::jsonb, 1, 'CO2 clearance depends on minute ventilation; increasing rate or tidal volume raises minute ventilation and lowers PaCO2.', 'Pre-Council', '🎓', true),
(7844, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'What is the normal recommended tidal volume range for lung-protective ventilation in ARDS, based on predicted body weight?', '["10-12 mL/kg", "15-18 mL/kg", "2-4 mL/kg", "6-8 mL/kg"]'::jsonb, 3, 'Lung-protective ventilation strategies (ARDSNet) use low tidal volumes of about 6-8 mL/kg predicted body weight to minimize volutrauma.', 'Pre-Council', '🎓', true),
(7845, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'What does PEEP (positive end-expiratory pressure) primarily achieve?', '["Keeps alveoli open at end-expiration, preventing collapse and improving oxygenation", "Increases the tidal volume delivered", "Shortens inspiratory time", "Decreases FiO2 requirement to zero"]'::jsonb, 0, 'PEEP maintains alveolar recruitment at end-expiration, preventing atelectasis and improving functional residual capacity and oxygenation.', 'Pre-Council', '🎓', true),
(7846, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'A normal I:E ratio for a patient without obstructive lung disease is approximately:', '["2:1", "1:4", "1:2", "4:1"]'::jsonb, 2, 'A normal I:E ratio is about 1:2, meaning expiration is roughly twice as long as inspiration, mimicking normal spontaneous breathing.', 'Pre-Council', '🎓', true),
(7847, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'In a patient with severe air-trapping from status asthmaticus, which ventilator strategy helps reduce auto-PEEP?', '["Prolong inspiratory time", "Increase PEEP above intrinsic level", "Prolong expiratory time (lower rate, higher inspiratory flow)", "Increase respiratory rate"]'::jsonb, 2, 'Prolonging expiratory time via a lower rate and higher inspiratory flow allows more complete exhalation, reducing breath-stacking and auto-PEEP.', 'Pre-Council', '🎓', true),
(7848, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Pressure support ventilation (PSV) requires which patient characteristic to function safely?', '["Intact spontaneous respiratory drive", "Complete absence of spontaneous breathing", "Presence of a tracheostomy only", "Paralysis from neuromuscular blockade"]'::jsonb, 0, 'PSV augments each spontaneous breath but provides no guaranteed mandatory breaths, so the patient must have a reliable spontaneous respiratory drive.', 'Pre-Council', '🎓', true),
(7849, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Which type of ventilator generates a negative pressure around the thorax to draw air into the lungs, historically exemplified by the "iron lung"?', '["Positive pressure ventilator", "High-frequency oscillatory ventilator", "Pressure-cycled ventilator", "Negative pressure ventilator"]'::jsonb, 3, 'Negative pressure ventilators, such as the historical iron lung, create subatmospheric pressure around the chest wall to draw air into the lungs, unlike modern positive pressure ventilators.', 'Pre-Council', '🎓', true),
(7850, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'What is the primary determinant of tidal volume delivered in volume-controlled ventilation (VCV)?', '["Lung compliance alone", "The clinician-set tidal volume, delivered regardless of lung compliance changes", "The set inspiratory pressure", "Patient effort"]'::jsonb, 1, 'In VCV, a fixed tidal volume is delivered each breath; as compliance worsens, peak/plateau pressures rise rather than the delivered volume changing.', 'Pre-Council', '🎓', true),
(7851, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'In pressure-controlled ventilation (PCV), what happens to tidal volume if lung compliance suddenly worsens (e.g., worsening pulmonary edema)?', '["Tidal volume increases automatically", "Tidal volume stays exactly the same", "Peak pressure rises uncontrollably", "Tidal volume decreases because pressure is fixed"]'::jsonb, 3, 'PCV delivers a fixed pressure; if compliance worsens, less volume is achieved for that pressure, so delivered tidal volume falls and must be monitored closely.', 'Pre-Council', '🎓', true),
(7852, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Which mode combines a set mandatory volume-targeted breath with a decelerating pressure waveform, aiming to guarantee tidal volume while limiting peak pressure?', '["Standard SIMV", "CPAP", "Pressure-regulated volume control (PRVC)", "High-frequency jet ventilation"]'::jsonb, 2, 'PRVC uses a decelerating flow/pressure pattern that the ventilator auto-adjusts breath-to-breath to guarantee a target tidal volume at the lowest possible pressure.', 'Pre-Council', '🎓', true),
(7853, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'The "trigger sensitivity" setting on a ventilator refers to:', '["The maximum pressure the ventilator will deliver", "The effort (flow or pressure change) required from the patient to initiate a ventilator-assisted breath", "The volume of gas delivered per breath", "The ratio of inspiration to expiration"]'::jsonb, 1, 'Trigger sensitivity determines how much patient effort (flow or pressure change) is needed for the ventilator to sense and respond to a spontaneous breath.', 'Pre-Council', '🎓', true),
(7854, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'A trigger sensitivity set too insensitive (requiring excessive patient effort) can result in:', '["Increased work of breathing and patient-ventilator asynchrony", "Auto-triggering of breaths", "Hyperventilation", "Excessive tidal volumes"]'::jsonb, 0, 'An overly insensitive trigger forces the patient to generate excessive effort before the ventilator responds, increasing work of breathing and causing asynchrony.', 'Pre-Council', '🎓', true),
(7855, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Continuous positive airway pressure (CPAP) mode on a ventilator provides:', '["A constant baseline pressure throughout the respiratory cycle with no mandatory breaths, above which the patient breathes spontaneously", "Mandatory breaths at a fixed rate", "Pressure support that varies with each breath", "Negative pressure during expiration"]'::jsonb, 0, 'CPAP delivers a fixed baseline pressure with no mandatory ventilator breaths; the patient does all the work of breathing above that pressure level.', 'Pre-Council', '🎓', true),
(7856, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Which ventilator mode is characterized by an extended time at a high continuous positive pressure (P-high) with brief releases to a lower pressure (P-low), used in severe ARDS to recruit alveoli?', '["SIMV", "Airway pressure release ventilation (APRV)", "Pressure support ventilation", "Assist control volume ventilation"]'::jsonb, 1, 'APRV maintains a high continuous airway pressure with brief timed releases, promoting alveolar recruitment while allowing spontaneous breathing throughout the cycle.', 'Pre-Council', '🎓', true),
(7857, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'What does "compliance" describe in respiratory mechanics?', '["The resistance to airflow in the airways", "The ratio of dead space to tidal volume", "The change in lung volume per unit change in pressure (distensibility of the lungs/chest wall)", "The maximum inspiratory pressure a patient can generate"]'::jsonb, 2, 'Compliance is the change in volume per unit change in pressure, reflecting how easily the lungs and chest wall expand.', 'Pre-Council', '🎓', true),
(7858, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Decreased lung compliance (e.g., ARDS, pulmonary fibrosis) on a volume-controlled ventilator will manifest as:', '["Decreased peak airway pressure", "No change in airway pressures", "Increased exhaled tidal volume", "Increased peak and plateau airway pressures"]'::jsonb, 3, 'Stiffer, less compliant lungs require higher pressure to deliver the same fixed tidal volume, raising both peak and plateau pressures.', 'Pre-Council', '🎓', true),
(7859, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Increased airway resistance (e.g., bronchospasm, secretions) on a volume-controlled ventilator characteristically causes:', '["A rise in plateau pressure only", "A rise in peak airway pressure with plateau pressure remaining relatively normal", "Decreased peak pressure", "No change in the pressure-volume relationship"]'::jsonb, 1, 'Resistance affects peak pressure while plateau pressure (measured with no flow) reflects alveolar/compliance status; a widened peak-plateau gradient signals a resistance problem such as secretions or bronchospasm.', 'Pre-Council', '🎓', true),
(7860, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'What is the purpose of measuring plateau pressure via an inspiratory hold maneuver?', '["To measure airway resistance directly", "To calculate the respiratory rate", "To determine FiO2 requirements", "To estimate alveolar distending pressure and assess risk of barotrauma, independent of airway resistance"]'::jsonb, 3, 'Plateau pressure, measured with no gas flow during an inspiratory hold, estimates alveolar distending pressure and helps assess risk of ventilator-induced lung injury.', 'Pre-Council', '🎓', true),
(7861, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'A patient requires mechanical ventilation for airway protection due to a decreased level of consciousness (GCS 6) after a head injury. This is an example of which broad indication for ventilation?', '["Primary oxygenation failure", "Inability to protect the airway", "Primary ventilatory (CO2) failure", "Post-anesthesia recovery only"]'::jsonb, 1, 'A markedly depressed level of consciousness compromises airway reflexes, making inability to protect the airway a key indication for intubation and ventilation.', 'Pre-Council', '🎓', true),
(7862, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Which arterial blood gas finding most strongly supports the need for mechanical ventilation due to ventilatory failure?', '["PaCO2 rising with respiratory acidosis (pH <7.25) despite maximal noninvasive support", "PaO2 of 90 mmHg on room air", "PaCO2 of 38 mmHg", "pH of 7.40"]'::jsonb, 0, 'Progressive hypercapnia with worsening respiratory acidosis despite maximal support indicates ventilatory pump failure requiring mechanical ventilation.', 'Pre-Council', '🎓', true),
(7863, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'High-frequency oscillatory ventilation (HFOV) delivers:', '["Large tidal volumes at low respiratory rates", "Negative pressure ventilation only", "Very small tidal volumes at very high rates (often several hundred breaths/min)", "Standard tidal volumes with prolonged inspiratory pause"]'::jsonb, 2, 'HFOV uses very small (often sub-dead-space) tidal volumes delivered at extremely high rates to maintain oxygenation and ventilation while minimizing volutrauma.', 'Pre-Council', '🎓', true),
(7864, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'The inspiratory flow rate on a ventilator affects:', '["How quickly the set tidal volume is delivered, influencing inspiratory time and patient comfort", "Only the FiO2 delivered", "The PEEP level", "The alarm threshold for low pressure"]'::jsonb, 0, 'Inspiratory flow rate determines the speed of gas delivery, which affects inspiratory time, peak pressure, and patient-ventilator synchrony/comfort.', 'Pre-Council', '🎓', true),
(7865, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'A ventilator''s "sensitivity" can be set to trigger by flow or by pressure change. Flow triggering is generally preferred because it:', '["Always delivers a larger tidal volume", "Eliminates the need for PEEP", "Prevents all forms of asynchrony", "Requires less patient work of breathing to initiate a breath than pressure triggering"]'::jsonb, 3, 'Flow triggering generally responds faster and requires less patient effort to initiate a breath compared with pressure triggering, reducing work of breathing.', 'Pre-Council', '🎓', true),
(7866, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'A patient with COPD exacerbation and cardiogenic pulmonary edema who is alert, cooperative, and hemodynamically stable may first be tried on which form of ventilatory support before invasive intubation?', '["Immediate invasive mechanical ventilation", "Noninvasive positive pressure ventilation (BiPAP)", "High-frequency oscillatory ventilation", "Negative pressure ventilation"]'::jsonb, 1, 'Alert, cooperative, hemodynamically stable patients with COPD exacerbation or cardiogenic pulmonary edema are appropriate candidates for a trial of noninvasive positive pressure ventilation before invasive intubation.', 'Pre-Council', '🎓', true),
(7867, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'How often should ventilator circuit tubing be routinely changed to reduce infection risk, according to current VAP-prevention guidance?', '["Every 24 hours routinely", "Every 48 hours routinely", "Every 4 hours routinely", "Only when visibly soiled or malfunctioning, not on a fixed schedule"]'::jsonb, 3, 'Current evidence shows routine scheduled circuit changes do not reduce VAP and may increase risk; circuits should be changed only when visibly soiled, contaminated, or malfunctioning.', 'Pre-Council', '🎓', true),
(7868, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Condensation ("rainout") that collects in the ventilator tubing should be:', '["Allowed to drain back into the patient''s airway", "Ignored as it poses no risk", "Drained away from the patient into a collection trap, never allowed to flow back toward the patient", "Removed only at the end of the shift"]'::jsonb, 2, 'Condensate can become colonized with bacteria; draining it away from the patient rather than back toward the ETT prevents aspiration of contaminated fluid.', 'Pre-Council', '🎓', true),
(7869, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Before use, ventilator alarms should be:', '["Turned off to avoid alarm fatigue", "Tested and set to appropriate limits for the individual patient, and never disabled during active use", "Set to the widest possible range for all patients", "Left at factory default regardless of patient condition"]'::jsonb, 1, 'Alarms must be individualized to the patient''s parameters, tested, and kept active at all times to ensure timely detection of deterioration or equipment problems.', 'Pre-Council', '🎓', true),
(7870, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'The humidifier/heated humidification system on a ventilator circuit serves to:', '["Warm and humidify inspired gas to prevent mucosal drying and thick secretions", "Filter bacteria from expired gas only", "Measure tidal volume", "Regulate FiO2 automatically"]'::jsonb, 0, 'Heated humidification warms and moistens inspired gas, preventing airway mucosal drying and thickened, obstructive secretions.', 'Pre-Council', '🎓', true),
(7871, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'A heat-moisture exchanger (HME, "artificial nose") should be avoided or used cautiously in which patient?', '["A patient with thick, copious secretions", "A patient requiring short-term transport ventilation", "A patient with normal thin secretions", "A patient on a closed suction system"]'::jsonb, 0, 'HMEs can become occluded by thick secretions and provide less effective heat/moisture than active heated humidifiers, increasing the risk of ETT obstruction in patients with copious secretions.', 'Pre-Council', '🎓', true),
(7872, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Water in the ventilator circuit tubing collection trap should be emptied:', '["Only at the start of each new shift", "Regularly throughout the shift as it accumulates, using standard precautions", "Never, to preserve humidification", "Directly back into the humidifier reservoir"]'::jsonb, 1, 'Condensate traps should be emptied regularly to prevent pooling that can obstruct flow or be aspirated, using standard precautions given the risk of contamination.', 'Pre-Council', '🎓', true),
(7873, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Daily ventilator checks by the critical care nurse should include verification of:', '["Only the power cord connection", "The patient''s code status", "Set parameters match the physician''s order, alarm limits, and circuit integrity", "The room temperature"]'::jsonb, 2, 'Routine ventilator checks confirm that settings match ordered parameters, alarms are appropriately set, and the circuit is intact and free of leaks or contamination.', 'Pre-Council', '🎓', true),
(7874, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Which practice reduces the risk of ventilator-associated pneumonia related to the humidification system?', '["Refilling the reservoir by opening it to add tap water as needed", "Allowing the reservoir to run dry between refills", "Sharing humidifier reservoirs between patients after rinsing", "Using sterile water in the humidifier reservoir and maintaining a closed continuous-feed system"]'::jsonb, 3, 'Sterile water with a closed, continuous-feed humidifier system minimizes microbial contamination of inspired gas compared with open systems refilled with tap water.', 'Pre-Council', '🎓', true),
(7875, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'A high-pressure alarm on the ventilator suddenly begins sounding intermittently and then resolves. The nurse should first:', '["Silence the alarm permanently", "Assess the patient and check the circuit for cause (secretions, biting, kinking, coughing)", "Immediately disconnect the patient from the ventilator", "Increase the high-pressure alarm limit"]'::jsonb, 1, 'Intermittent high-pressure alarms usually reflect transient causes like coughing, biting, or secretions; the nurse should assess the patient and circuit before any other action.', 'Pre-Council', '🎓', true),
(7876, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Backup battery power on a mechanical ventilator is important because it:', '["Eliminates the need for alarm testing", "Reduces circuit condensation", "Increases tidal volume delivery capacity", "Allows continued ventilation during transport or power failure"]'::jsonb, 3, 'Battery backup ensures uninterrupted ventilatory support during intrahospital transport or unexpected loss of mains power.', 'Pre-Council', '🎓', true),
(7877, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'A bag-valve-mask (manual resuscitator) connected to oxygen should be kept at the bedside of every intubated patient primarily to:', '["Allow immediate manual ventilation if the ventilator malfunctions or the patient requires emergency management", "Warm inspired gases", "Measure exhaled tidal volume", "Replace the need for suctioning equipment"]'::jsonb, 0, 'A bedside manual resuscitation bag allows immediate manual ventilation in the event of ventilator failure, circuit problems, or emergent patient deterioration.', 'Pre-Council', '🎓', true),
(7878, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Ventilator circuit connections (e.g., at the ETT, humidifier, filters) should be checked periodically for:', '["Excess PEEP delivery", "Increased FiO2 delivery", "Leaks or disconnections that could cause a low-pressure/low minute-ventilation alarm", "Decreased trigger sensitivity"]'::jsonb, 2, 'Loose or disconnected circuit connections cause air leaks, which typically trigger low-pressure or low minute-ventilation alarms and can cause hypoventilation.', 'Pre-Council', '🎓', true),
(7879, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'An inline bacterial/viral filter is typically placed:', '["Only on the oxygen source tubing", "Inside the humidifier reservoir", "At the expiratory limb of the circuit to protect the ventilator and reduce environmental contamination", "On the suction catheter only"]'::jsonb, 2, 'Expiratory limb filters trap microorganisms and secretions before gas returns to the ventilator, protecting internal components and reducing environmental spread.', 'Pre-Council', '🎓', true),
(7880, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'When a mechanically ventilated patient is being transported within the hospital, the nurse must ensure:', '["A portable ventilator or manual resuscitation bag with adequate oxygen supply, monitoring, and emergency airway equipment accompany the patient", "Only the primary ventilator settings are documented before leaving", "The patient is disconnected from all monitoring to save time", "Sedation is discontinued entirely for transport"]'::jsonb, 0, 'Safe intrahospital transport of a ventilated patient requires portable ventilatory support or a manual resuscitator, adequate oxygen, continuous monitoring, and airway emergency equipment.', 'Pre-Council', '🎓', true),
(7881, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Prior to placing a patient on a ventilator, the machine should undergo a self-test/check to verify:', '["That the patient''s diagnosis is documented", "The patient''s code status", "Proper function of the internal circuitry, alarms, and delivery systems", "The room''s electrical outlet voltage only"]'::jsonb, 2, 'A pre-use self-test confirms the ventilator''s internal systems, alarms, and gas delivery function correctly before it is connected to a patient.', 'Pre-Council', '🎓', true),
(7882, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Ventilator tubing should be positioned to:', '["Hang directly from the patient''s chin for stability", "Prevent dependent loops that trap condensate and avoid tension/traction on the ETT", "Be taped tightly to the bed rail", "Run beneath the patient''s body"]'::jsonb, 1, 'Proper circuit positioning avoids dependent loops where condensate pools and avoids traction on the ETT that could cause displacement or mucosal injury.', 'Pre-Council', '🎓', true),
(7883, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Closed (in-line) suction systems, compared to open suction systems, offer the advantage of:', '["Requiring more frequent circuit changes", "Eliminating the need for sterile technique entirely", "Delivering higher tidal volumes", "Maintaining PEEP and oxygenation during suctioning while reducing environmental contamination"]'::jsonb, 3, 'Closed in-line suction allows suctioning without disconnecting the patient from the ventilator, preserving PEEP and oxygenation while limiting environmental exposure to secretions.', 'Pre-Council', '🎓', true),
(7884, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'The head of bed for a mechanically ventilated patient should be maintained at what elevation to reduce aspiration and VAP risk, absent contraindications?', '["0-10 degrees", "Flat (supine) at all times", "30-45 degrees", "Trendelenburg position"]'::jsonb, 2, 'Semi-recumbent positioning at 30-45 degrees reduces gastric reflux and aspiration risk, a core element of VAP prevention bundles.', 'Pre-Council', '🎓', true),
(7885, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Oral care with chlorhexidine and regular oral hygiene in ventilated patients is performed primarily to:', '["Improve patient comfort only", "Reduce oral bacterial colonization and the risk of ventilator-associated pneumonia", "Replace the need for suctioning", "Reduce ETT cuff pressure"]'::jsonb, 1, 'Regular oral care with an antiseptic such as chlorhexidine reduces oral microbial colonization, lowering the risk that organisms are aspirated and cause VAP.', 'Pre-Council', '🎓', true),
(7886, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Endotracheal tube cuff pressure should be maintained within which typical range to prevent both aspiration and tracheal mucosal ischemia?', '["20-30 cm H2O", "5-10 cm H2O", "40-50 cm H2O", "60-70 cm H2O"]'::jsonb, 0, 'Cuff pressures of 20-30 cm H2O provide an adequate seal to prevent aspiration around the cuff while remaining below tracheal capillary perfusion pressure, minimizing ischemic mucosal injury.', 'Pre-Council', '🎓', true),
(7887, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Subglottic secretion drainage (using a specialized ETT with a dorsal lumen above the cuff) helps prevent VAP by:', '["Removing pooled secretions that accumulate above the cuff before they can leak into the lower airway", "Increasing cuff pressure automatically", "Replacing the need for oral care", "Measuring end-tidal CO2"]'::jsonb, 0, 'Continuous or intermittent aspiration of secretions pooling above the cuff prevents their microaspiration into the lower airway, reducing VAP incidence.', 'Pre-Council', '🎓', true),
(7888, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Which sedation practice is recommended in current evidence-based ventilator bundles to reduce duration of mechanical ventilation?', '["Continuous deep sedation without interruption for the duration of ventilation", "Daily sedation interruption/spontaneous awakening trials paired with spontaneous breathing trials", "Avoiding all sedation scoring tools", "Using paralytics routinely for comfort"]'::jsonb, 1, 'Pairing daily sedation interruption (spontaneous awakening trials) with spontaneous breathing trials shortens duration of mechanical ventilation and ICU length of stay.', 'Pre-Council', '🎓', true),
(7889, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Suctioning an intubated patient should be performed:', '["Every 15 minutes regardless of secretions", "Only once per shift regardless of need", "Only when clinically indicated (e.g., visible secretions, coarse breath sounds, rising peak pressures), not on a fixed routine schedule", "Continuously throughout the shift"]'::jsonb, 2, 'Suctioning should be based on clinical assessment findings rather than a fixed schedule, since unnecessary suctioning causes mucosal trauma and hypoxemia.', 'Pre-Council', '🎓', true),
(7890, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Prior to and after endotracheal suctioning, the nurse should:', '["Increase sedation to the maximum level", "Deflate the ETT cuff completely", "Decrease the FiO2 to room air", "Preoxygenate/hyperoxygenate the patient to prevent suction-induced hypoxemia"]'::jsonb, 3, 'Preoxygenation before and after suctioning helps offset the transient hypoxemia caused by interrupting ventilation and removing gas along with secretions.', 'Pre-Council', '🎓', true),
(7891, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'The maximum recommended duration for a single suction pass in an adult is approximately:', '["45-60 seconds", "10-15 seconds", "2 minutes", "5 minutes"]'::jsonb, 1, 'Prolonged suction passes cause hypoxemia and mucosal trauma; passes should be limited to roughly 10-15 seconds with adequate pre- and post-oxygenation.', 'Pre-Council', '🎓', true),
(7892, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'A key element of the "ventilator bundle" (VAP prevention bundle) includes all of the following EXCEPT:', '["Head-of-bed elevation 30-45 degrees", "Daily sedation vacation and readiness-to-wean assessment", "Peptic ulcer disease and deep vein thrombosis prophylaxis", "Routine daily scheduled ventilator circuit changes"]'::jsonb, 3, 'Routine scheduled circuit changes are not part of current VAP prevention bundles; evidence shows they do not reduce, and may increase, VAP risk, so circuits are changed only when soiled or malfunctioning.', 'Pre-Council', '🎓', true),
(7893, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'A ventilated patient becomes agitated and is pulling at the endotracheal tube. The nurse''s priority assessment is to:', '["Immediately extubate the patient", "Apply four-point restraints without further assessment", "Increase the ventilator rate", "Assess for a treatable cause of agitation such as hypoxia, pain, or ventilator asynchrony before increasing restraint or sedation alone"]'::jsonb, 3, 'Agitation in a ventilated patient often has a reversible cause (hypoxia, pain, asynchrony, full bladder); this should be assessed before escalating restraint or sedation.', 'Pre-Council', '🎓', true),
(7894, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Which nutritional consideration is important for a mechanically ventilated patient?', '["Total parenteral nutrition should always be first-line", "Feeding should be withheld entirely until extubation", "Early enteral nutrition is preferred over parenteral nutrition when the gut is functional, to reduce infection risk", "Only IV dextrose is appropriate"]'::jsonb, 2, 'Early enteral nutrition, when the gastrointestinal tract is functional, is preferred over parenteral nutrition because it lowers infectious complications and supports gut integrity.', 'Pre-Council', '🎓', true),
(7895, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Continuous monitoring of a ventilated patient should include which of the following to detect early deterioration?', '["Only hourly manual vital signs with no continuous monitoring", "Daily chest x-ray only", "SpO2, capnography (EtCO2), and ventilator waveform/alarm monitoring", "Weekly arterial blood gas only"]'::jsonb, 2, 'Continuous pulse oximetry, capnography, and attention to ventilator waveforms and alarms allow early detection of deterioration between intermittent assessments.', 'Pre-Council', '🎓', true),
(7896, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'ETT position (depth at the lip/teeth) should be documented and rechecked regularly to prevent:', '["Increased cuff pressure", "Decreased FiO2 delivery", "Ventilator circuit leaks", "Accidental extubation or migration into a mainstem bronchus"]'::jsonb, 3, 'Regular documentation and verification of ETT depth at the lip/teeth helps detect tube migration inward (mainstem intubation) or outward (risk of extubation).', 'Pre-Council', '🎓', true),
(7897, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Communication strategies for an alert, ventilated patient who cannot speak include:', '["Sedating the patient to prevent attempts at communication", "Removing family visitation to reduce agitation", "Avoiding explanations of procedures", "Communication boards, writing materials, or eye-gaze devices"]'::jsonb, 3, 'Alternative communication methods such as boards, writing, or eye-gaze devices allow alert intubated patients to express needs and reduce distress.', 'Pre-Council', '🎓', true),
(7898, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Passive range-of-motion exercises and early mobility in ventilated ICU patients help prevent:', '["Ventilator-associated pneumonia directly", "Endotracheal tube cuff leaks", "Auto-PEEP", "ICU-acquired weakness and venous thromboembolism"]'::jsonb, 3, 'Early mobilization and range-of-motion exercises reduce ICU-acquired weakness, contractures, and venous thromboembolism risk associated with prolonged immobility.', 'Pre-Council', '🎓', true),
(7899, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Restraints may be indicated for a mechanically ventilated patient primarily to:', '["Replace the need for sedation entirely", "Substitute for one-to-one nursing observation", "Improve patient comfort", "Prevent self-extubation or removal of essential lines/tubes when less restrictive measures have failed"]'::jsonb, 3, 'Restraints are a last-resort measure to prevent self-extubation or removal of critical lines/tubes after less restrictive interventions have been tried and failed, and require ongoing reassessment.', 'Pre-Council', '🎓', true),
(7900, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Which skin care consideration is important in ventilated patients with an oral ETT?', '["Leaving the tube position and securing device unchanged for the entire admission", "Applying the securing tape as tightly as possible", "Avoiding all mouth care to prevent tube dislodgement", "Repositioning the tube and tape/holder periodically to prevent pressure injury at the lips and oral mucosa"]'::jsonb, 3, 'Periodic repositioning of the ETT and securing device (with two staff members, per protocol) reduces the risk of pressure injury to the lips and oral mucosa while maintaining tube security.', 'Pre-Council', '🎓', true),
(7901, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'A mechanically ventilated patient''s arterial blood gas shows respiratory alkalosis (low PaCO2, high pH). This most likely indicates:', '["Underventilation", "Hyperventilation from excessive minute ventilation (rate/tidal volume too high) or patient-driven tachypnea", "Metabolic acidosis compensation", "Correct ventilator settings requiring no change"]'::jsonb, 1, 'A low PaCO2 with elevated pH indicates the patient is being overventilated, whether from excessive ventilator settings or the patient''s own tachypnea, and settings should be reassessed.', 'Pre-Council', '🎓', true),
(7902, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Eye care for sedated, ventilated patients with an incomplete blink reflex should include:', '["No specific eye care is needed", "Only cleaning the eyes once a week", "Applying ice packs to the eyes", "Lubricating drops/ointment and taping eyelids closed to prevent corneal drying and abrasion"]'::jsonb, 3, 'Sedated patients often lose protective blink reflexes, so lubricating drops or ointment and gentle eyelid closure prevent corneal exposure keratopathy.', 'Pre-Council', '🎓', true),
(7903, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Bladder and bowel care in a sedated ventilated patient typically requires:', '["No specific interventions since the patient is unconscious", "Fluid restriction to avoid catheter use", "Daily enemas regardless of bowel pattern", "Indwelling urinary catheter care and a bowel regimen to prevent complications of immobility"]'::jsonb, 3, 'Sedated, immobile ventilated patients require structured urinary catheter care and a bowel regimen to prevent complications such as catheter-associated infection and constipation/ileus.', 'Pre-Council', '🎓', true),
(7904, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'A ventilated patient''s peak airway pressure alarm sounds and the nurse notes the patient coughing forcefully against the tube. The appropriate INITIAL action is to:', '["Immediately increase sedation to a deep level without assessment", "Disconnect the ventilator circuit", "Silence the alarm and leave the room", "Assess the patient, consider suctioning if secretions are the cause, and reassure/coach as appropriate"]'::jsonb, 3, 'Coughing against the tube often reflects secretions or airway irritation; the nurse should assess, suction if indicated, and reassure the patient rather than jumping to sedation or disconnection.', 'Pre-Council', '🎓', true),
(7905, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Which sedation assessment tool is commonly used to titrate sedation in mechanically ventilated ICU patients?', '["Glasgow Coma Scale exclusively", "APACHE II score", "Richmond Agitation-Sedation Scale (RASS)", "Braden Scale"]'::jsonb, 2, 'RASS is a validated scale specifically designed to assess and titrate level of sedation/agitation in ICU patients, guiding a light, goal-directed sedation approach.', 'Pre-Council', '🎓', true),
(7906, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Assessment of a ventilated patient''s pain, even when sedated, is important because:', '["Ventilated patients cannot feel pain due to sedation", "Pain assessment is unnecessary once intubated", "Analgesia should be avoided to allow neurological assessment at all times", "Untreated pain increases agitation, ventilator asynchrony, and physiologic stress response"]'::jsonb, 3, 'Sedation does not guarantee adequate analgesia; untreated pain contributes to agitation, asynchrony with the ventilator, and an exaggerated stress response, so regular pain assessment is essential.', 'Pre-Council', '🎓', true),
(7907, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'A key documentation responsibility for the critical care nurse caring for a ventilated patient includes:', '["Documentation of ventilator settings only once per admission", "Only documenting when a problem occurs", "Recording ventilator brand and serial number only", "Hourly/shift ventilator settings, alarm parameters, ETT depth, cuff pressure, and patient response"]'::jsonb, 3, 'Regular documentation of ventilator settings, alarms, ETT depth, cuff pressure, and the patient''s response provides an ongoing record for trend recognition and continuity of care.', 'Pre-Council', '🎓', true),
(7908, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'A patient on mechanical ventilation develops sudden increased work of breathing, tachycardia, and diaphoresis but the ventilator is not alarming. The nurse should:', '["Assume the ventilator is malfunctioning and disconnect it", "Wait for an alarm to sound before intervening", "Increase the FiO2 without further assessment", "Immediately assess the patient directly rather than relying solely on the ventilator display, since clinical status can deteriorate before alarms trigger"]'::jsonb, 3, 'Ventilator alarms do not capture every form of clinical deterioration; direct patient assessment takes priority over reliance on machine alarms alone.', 'Pre-Council', '🎓', true),
(7909, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Ventilator-associated pneumonia (VAP) is defined as pneumonia developing:', '["More than 48 hours after endotracheal intubation and initiation of mechanical ventilation", "Within the first 24 hours of intubation", "Only after extubation", "Exclusively in patients with tracheostomy"]'::jsonb, 0, 'VAP is classically defined as pneumonia occurring more than 48 hours after intubation and initiation of mechanical ventilation, distinguishing it from pre-existing or community-acquired pneumonia.', 'Pre-Council', '🎓', true),
(7910, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Barotrauma from mechanical ventilation refers to lung injury caused by:', '["Excessive tidal volume causing alveolar overdistension", "Excessive FiO2 causing oxygen toxicity", "Excessive airway pressure causing alveolar rupture (e.g., pneumothorax, pneumomediastinum)", "Excessive PEEP causing hemodynamic compromise only"]'::jsonb, 2, 'Barotrauma specifically refers to pressure-related alveolar rupture leading to air leak syndromes such as pneumothorax or pneumomediastinum, distinct from volume-related volutrauma.', 'Pre-Council', '🎓', true),
(7911, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Volutrauma refers to ventilator-induced lung injury caused primarily by:', '["High airway pressure alone regardless of volume", "Alveolar overdistension from excessive tidal volume", "Oxygen toxicity from high FiO2", "Biotrauma from inflammatory mediators only"]'::jsonb, 1, 'Volutrauma results from alveolar overdistension due to excessive tidal volume, which is why lung-protective low tidal volume strategies are used in at-risk patients.', 'Pre-Council', '🎓', true),
(7912, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Positive pressure ventilation, especially with high levels of PEEP, can cause which hemodynamic effect?', '["Decreased venous return and cardiac output due to increased intrathoracic pressure", "Increased venous return and cardiac output", "No effect on hemodynamics", "Immediate hypertension in all patients"]'::jsonb, 0, 'Positive intrathoracic pressure impedes venous return to the right heart, which can reduce preload, cardiac output, and blood pressure, particularly in hypovolemic patients.', 'Pre-Council', '🎓', true),
(7913, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'A patient on high PEEP develops hypotension shortly after PEEP is increased. The most likely mechanism is:', '["Increased cardiac contractility", "Vasodilation from hypoxia", "Increased plasma volume", "Decreased venous return from increased intrathoracic pressure reducing cardiac preload"]'::jsonb, 3, 'Higher PEEP raises intrathoracic pressure, which impedes venous return, reduces preload, and can precipitate hypotension, especially in volume-depleted patients.', 'Pre-Council', '🎓', true),
(7914, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Oxygen toxicity as a complication of mechanical ventilation is most associated with:', '["Low FiO2 delivery over time", "High PEEP alone", "Low tidal volume ventilation", "Prolonged exposure to high FiO2 (typically >0.6) leading to absorption atelectasis and free radical lung injury"]'::jsonb, 3, 'Sustained high FiO2 generates reactive oxygen species and promotes absorption atelectasis, causing oxygen toxicity; clinicians aim to use the lowest FiO2 that achieves adequate oxygenation.', 'Pre-Council', '🎓', true),
(7915, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Which complication describes progressive lung injury from repeated opening and closing of unstable alveoli during mechanical ventilation?', '["Barotrauma", "Volutrauma", "Atelectrauma", "Oxygen toxicity"]'::jsonb, 2, 'Atelectrauma results from cyclic alveolar collapse and reopening (shear stress) in under-recruited lungs; adequate PEEP helps prevent it.', 'Pre-Council', '🎓', true),
(7916, 'Ventilators', 'CCN Curriculum — Anaesthesia', '"Biotrauma" in the context of ventilator-induced lung injury refers to:', '["Bacterial colonization of the ventilator circuit", "Biofilm formation on the endotracheal tube", "Release of inflammatory cytokines from mechanically stressed lung tissue, potentially contributing to systemic multi-organ dysfunction", "Direct bacterial invasion of the alveoli"]'::jsonb, 2, 'Biotrauma describes the release of inflammatory mediators from mechanically stressed lung tissue, which can enter the systemic circulation and contribute to multi-organ dysfunction.', 'Pre-Council', '🎓', true),
(7917, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'A common complication of prolonged translaryngeal (oral or nasal) endotracheal intubation is:', '["Permanent loss of gag reflex in all patients", "Laryngeal/tracheal injury including edema, ulceration, or stenosis", "Immediate need for cricothyroidotomy", "Complete resolution of all airway reflexes"]'::jsonb, 1, 'Prolonged translaryngeal intubation can cause laryngeal or tracheal mucosal injury, edema, ulceration, and, over time, stenosis at the cuff or tube-tip site.', 'Pre-Council', '🎓', true),
(7918, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Prolonged mechanical ventilation with high tidal volumes and inadequate sedation increases risk of:', '["Patient-ventilator asynchrony and worsening lung injury", "Improved gas exchange with no added risk", "Decreased work of breathing only", "Spontaneous extubation prevention"]'::jsonb, 0, 'Inadequate sedation with high, poorly matched ventilator settings increases patient-ventilator asynchrony, which can worsen lung injury and patient distress.', 'Pre-Council', '🎓', true),
(7919, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Deep vein thrombosis (DVT) risk is elevated in mechanically ventilated ICU patients primarily due to:', '["Excessive ambulation", "High cardiac output states", "Frequent position changes", "Immobility, sedation, and critical illness-associated hypercoagulability"]'::jsonb, 3, 'Sedated, immobile, critically ill patients are at elevated risk of venous thromboembolism due to venous stasis and the hypercoagulable state of critical illness, warranting routine DVT prophylaxis.', 'Pre-Council', '🎓', true),
(7920, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Stress ulcer (gastrointestinal) prophylaxis is routinely recommended for mechanically ventilated patients because:', '["Ventilated patients are at no increased GI bleeding risk", "Critical illness and mechanical ventilation increase risk of stress-related mucosal bleeding", "It prevents ventilator-associated pneumonia directly", "It replaces the need for enteral nutrition"]'::jsonb, 1, 'Mechanical ventilation beyond 48 hours (and coagulopathy) are recognized risk factors for stress-related mucosal disease, making stress ulcer prophylaxis a standard part of ICU care bundles.', 'Pre-Council', '🎓', true),
(7921, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Ventilator-induced diaphragmatic dysfunction (diaphragm atrophy/weakness) can result from:', '["Excessive spontaneous breathing trials", "Underuse of sedation", "Low FiO2 ventilation", "Prolonged full ventilatory support suppressing the diaphragm''s own contractile activity"]'::jsonb, 3, 'When the ventilator does most or all of the work of breathing for a prolonged period, the diaphragm undergoes disuse atrophy, contributing to weaning difficulty.', 'Pre-Council', '🎓', true),
(7922, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'A tension pneumothorax developing during mechanical ventilation is a life-threatening complication characterized by:', '["Bilateral wheezing with normal vital signs", "Improved oxygenation and stable hemodynamics", "Decreased peak airway pressure", "Absent breath sounds on the affected side, tracheal deviation, hypotension, and sudden high peak pressures"]'::jsonb, 3, 'Tension pneumothorax presents with unilateral absent breath sounds, tracheal deviation away from the affected side, hypotension, and a sudden rise in peak airway pressure, requiring emergent needle/chest tube decompression.', 'Pre-Council', '🎓', true),
(7923, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Auto-PEEP (intrinsic PEEP) develops when:', '["PEEP is deliberately set too low", "Incomplete exhalation occurs before the next breath is delivered, trapping air and increasing end-expiratory pressure", "The patient is disconnected from the ventilator", "Tidal volume is reduced excessively"]'::jsonb, 1, 'Auto-PEEP occurs when the next breath is delivered before the previous breath has fully exhaled, trapping gas and raising end-expiratory alveolar pressure above set PEEP.', 'Pre-Council', '🎓', true),
(7924, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Auto-PEEP is a particular risk in patients with which underlying condition?', '["Restrictive lung disease such as pulmonary fibrosis", "Normal healthy lungs", "Neuromuscular disease without airway obstruction", "Obstructive airway disease such as COPD or severe asthma"]'::jsonb, 3, 'Obstructive diseases like COPD and asthma slow expiratory airflow, predisposing to incomplete exhalation and air trapping (auto-PEEP), especially at higher respiratory rates.', 'Pre-Council', '🎓', true),
(7925, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Consequences of significant auto-PEEP include all of the following EXCEPT:', '["Improved venous return and cardiac output", "Barotrauma", "Hemodynamic compromise from increased intrathoracic pressure", "Increased work of breathing and triggering difficulty"]'::jsonb, 0, 'Auto-PEEP increases intrathoracic pressure similarly to (or more than) extrinsic PEEP, which impairs rather than improves venous return and cardiac output.', 'Pre-Council', '🎓', true),
(7926, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Which laboratory/clinical finding suggests early ventilator-associated pneumonia in an intubated patient?', '["Clear chest x-ray with normal WBC", "Decreased secretions and improved oxygenation", "New or worsening infiltrate on chest x-ray with fever, leukocytosis, and purulent secretions", "Bradycardia with hypothermia only"]'::jsonb, 2, 'VAP is suggested clinically by a new/worsening infiltrate accompanied by fever, leukocytosis, and purulent tracheal secretions, prompting further diagnostic evaluation.', 'Pre-Council', '🎓', true),
(7927, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Mechanical ventilation-associated sinusitis is more common with which route of intubation?', '["Orotracheal intubation", "Nasotracheal intubation", "Tracheostomy", "Supraglottic airway devices"]'::jsonb, 1, 'Nasotracheal tubes can obstruct sinus drainage ostia, increasing the risk of nosocomial sinusitis compared with the oral route.', 'Pre-Council', '🎓', true),
(7928, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Silent aspiration around the ETT cuff, contributing to VAP, is best minimized by:', '["Deflating the cuff periodically to relieve tracheal pressure", "Keeping the head of bed flat", "Increasing sedation depth", "Maintaining adequate cuff pressure (20-30 cm H2O) and using subglottic secretion drainage where available"]'::jsonb, 3, 'An adequately inflated cuff (20-30 cm H2O) combined with subglottic secretion drainage minimizes leakage of pooled oropharyngeal secretions past the cuff into the lower airway.', 'Pre-Council', '🎓', true),
(7929, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'A complication specifically associated with high inspired oxygen concentrations delivered via mechanical ventilation over days is:', '["Immediate pneumothorax", "Bradycardia", "Hypercapnia", "Absorption atelectasis and hyperoxic acute lung injury"]'::jsonb, 3, 'Prolonged high FiO2 washes out alveolar nitrogen (promoting absorption atelectasis) and generates reactive oxygen species that can cause hyperoxic lung injury.', 'Pre-Council', '🎓', true),
(7930, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Renal effects of positive pressure ventilation can include decreased urine output due to:', '["Direct nephrotoxicity of oxygen", "Reduced cardiac output and renal perfusion, and neurohormonal changes (e.g., increased ADH)", "Increased renal blood flow from elevated cardiac output", "Diuresis from increased ANP release only"]'::jsonb, 1, 'Positive pressure ventilation can reduce cardiac output and renal perfusion, and triggers neurohormonal responses including increased ADH and decreased atrial natriuretic peptide, promoting fluid retention and decreased urine output.', 'Pre-Council', '🎓', true),
(7931, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Which of the following best describes "ventilator-induced lung injury" (VILI) as a unifying concept?', '["Injury caused only by infection acquired from the ventilator circuit", "Damage limited to the upper airway from the ETT", "A condition unrelated to ventilator settings", "Lung damage caused by the mechanical forces of ventilation itself, encompassing barotrauma, volutrauma, atelectrauma, and biotrauma"]'::jsonb, 3, 'VILI is the umbrella term for lung injury from the mechanical stresses of ventilation, including pressure (barotrauma), volume (volutrauma), cyclic alveolar opening/closing (atelectrauma), and the resulting inflammatory response (biotrauma).', 'Pre-Council', '🎓', true),
(7932, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Increased intracranial pressure can be a concern with mechanical ventilation, particularly when:', '["Low tidal volumes are used", "FiO2 is reduced to 21%", "High PEEP or high intrathoracic pressure impairs cerebral venous outflow", "The patient is extubated"]'::jsonb, 2, 'High intrathoracic pressure from elevated PEEP can impede jugular venous outflow from the brain, potentially raising intracranial pressure in susceptible patients.', 'Pre-Council', '🎓', true),
(7933, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Long-term complications of prolonged intubation/ventilation can include tracheal stenosis, which results from:', '["Excessive humidification of inspired gases", "Ischemic injury and scarring of the tracheal mucosa from prolonged cuff pressure", "Low cuff pressures maintained throughout intubation", "Frequent repositioning of the ETT"]'::jsonb, 1, 'Sustained excessive cuff pressure compresses the tracheal mucosal capillaries, causing ischemia, ulceration, and eventual fibrotic scarring that can narrow the trachea (stenosis).', 'Pre-Council', '🎓', true),
(7934, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'The DOPE mnemonic used to rapidly assess a deteriorating ventilated patient stands for:', '["Displacement, Obstruction, Pneumothorax, Equipment failure", "Dislodgement, Oxygen, Pressure, Extubation", "Distress, Obstruction, Pain, Emergency", "Displacement, Overventilation, Pneumonia, Edema"]'::jsonb, 0, 'DOPE is a structured mnemonic for the most common reversible causes of sudden deterioration in a ventilated patient: Displacement, Obstruction, Pneumothorax, and Equipment failure.', 'Pre-Council', '🎓', true),
(7935, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'A sudden high-pressure alarm accompanied by absent chest rise, difficulty bagging, and inability to pass a suction catheter most strongly suggests:', '["Endotracheal tube obstruction (e.g., mucus plug, kinking, biting)", "Ventilator circuit disconnection", "Tension pneumothorax with hyperresonance", "Correct tube placement with normal function"]'::jsonb, 0, 'Absent chest rise with high resistance to bagging and inability to pass a suction catheter through the tube are classic signs of complete or near-complete ETT obstruction.', 'Pre-Council', '🎓', true),
(7936, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'If a suction catheter cannot be passed easily through the ETT and the patient shows signs of respiratory distress, the immediate priority is to:', '["Continue attempting to force the catheter through repeatedly", "Suspect complete or partial tube obstruction and prepare for emergency tube change or removal", "Increase the ventilator''s high-pressure alarm limit", "Increase sedation and wait"]'::jsonb, 1, 'Inability to pass a suction catheter in a distressed patient signals possible tube obstruction, requiring urgent evaluation and preparation for emergency tube change or removal rather than repeated forceful attempts.', 'Pre-Council', '🎓', true),
(7937, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'A blocked or obstructed ETT typically causes which ventilator alarm pattern?', '["Low-pressure alarm with normal exhaled tidal volume", "No alarm activation at all", "High-pressure alarm with decreased or absent exhaled tidal volume", "Low FiO2 alarm only"]'::jsonb, 2, 'Obstruction increases resistance to gas flow, triggering a high-pressure alarm while the delivered/exhaled tidal volume falls because gas cannot reach the lungs.', 'Pre-Council', '🎓', true),
(7938, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Which action can help clear a partially obstructed ETT caused by thick secretions?', '["Increasing the tidal volume setting", "Deflating the cuff and leaving it deflated", "Decreasing suction pressure to zero", "Instilling a small amount of saline (per protocol) followed by suctioning, and ensuring adequate humidification"]'::jsonb, 3, 'Where institutional protocol supports it, small-volume saline instillation followed by suctioning can help loosen thick secretions, alongside ensuring adequate ongoing humidification to prevent recurrence.', 'Pre-Council', '🎓', true),
(7939, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Biting on the endotracheal tube by an inadequately sedated patient can cause acute obstruction. An appropriate intervention includes:', '["Immediately extubating the patient", "Inserting a bite block and reassessing sedation/analgesia level", "Deflating the ETT cuff", "Increasing the ventilator rate"]'::jsonb, 1, 'A bite block protects the tube lumen from occlusion, and reassessing sedation/analgesia addresses the underlying cause of the biting behavior.', 'Pre-Council', '🎓', true),
(7940, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Kinking of the endotracheal tube, another cause of obstruction, is most likely to occur:', '["Only inside the ventilator circuit", "In the trachea below the carina", "Only with tracheostomy tubes", "At the point where the tube exits the mouth or nose if not properly secured, or if the patient''s head is turned sharply"]'::jsonb, 3, 'ETT kinking commonly occurs externally at the mouth/nose exit point or with sharp head turning if the tube is inadequately secured or positioned.', 'Pre-Council', '🎓', true),
(7941, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'When using the DOPE mnemonic for a "D" (displacement) cause of sudden deterioration, the nurse should assess for:', '["Accidental extubation or migration of the tube into a mainstem bronchus", "Pneumothorax on chest x-ray", "Ventilator power failure", "Increased secretions in the tubing"]'::jsonb, 0, '"Displacement" in DOPE refers to the tube moving out of correct position, either accidental extubation or advancement into a mainstem bronchus, both of which cause acute deterioration.', 'Pre-Council', '🎓', true),
(7942, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'To assess for "E" (equipment failure) in the DOPE mnemonic, the nurse should:', '["Increase the ventilator''s tidal volume setting", "Assume the ETT is dislodged", "Order a stat chest x-ray before any other action", "Disconnect the patient from the ventilator and manually ventilate with a bag-valve device connected to 100% oxygen"]'::jsonb, 3, 'Manually bagging the patient with 100% oxygen both rules out ventilator/circuit equipment failure as the cause and provides immediate ventilation while the underlying cause is identified.', 'Pre-Council', '🎓', true),
(7943, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'End-tidal CO2 (capnography) waveform loss or a sudden flat waveform in an intubated patient most urgently suggests:', '["Normal ventilator function", "Improved lung compliance", "Tube displacement/dislodgement (e.g., esophageal intubation or extubation) or complete obstruction", "Adequate ventilation"]'::jsonb, 2, 'A sudden loss of the capnography waveform strongly suggests the tube is no longer delivering gas to the lungs, as with esophageal placement, extubation, or complete obstruction.', 'Pre-Council', '🎓', true),
(7944, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'A key nursing intervention to prevent ETT obstruction from dried secretions is:', '["Ensuring adequate airway humidification", "Withholding humidification to reduce condensate", "Deflating the cuff routinely", "Limiting suctioning to once daily"]'::jsonb, 0, 'Adequate humidification of inspired gas keeps secretions thin and easier to clear, reducing the risk that dried, thickened mucus obstructs the tube.', 'Pre-Council', '🎓', true),
(7945, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'If manual bagging of a patient with a suspected blocked ETT meets high resistance and chest rise is absent despite confirmed tube position, the appropriate next step is:', '["Increase bagging force and continue indefinitely", "Administer a bronchodilator via metered-dose inhaler through the tube", "Wait for the physician without further action", "Prepare to remove/change the endotracheal tube emergently"]'::jsonb, 3, 'When bagging shows high resistance and no chest rise despite a tube confirmed to be positioned correctly, the tube itself is likely obstructed and should be emergently removed/changed rather than forcing further ventilation attempts.', 'Pre-Council', '🎓', true),
(7946, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'A ventilated patient develops sudden respiratory distress, high-pressure alarm, and coarse rhonchi audible without a stethoscope. The most appropriate first nursing action is:', '["Immediately call for tube reintubation without assessment", "Attempt suctioning to clear the airway", "Increase the FiO2 only", "Sedate the patient more deeply"]'::jsonb, 1, 'Audible coarse rhonchi with a high-pressure alarm strongly suggests secretions are the cause; suctioning is the appropriate initial intervention before more invasive measures.', 'Pre-Council', '🎓', true),
(7947, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Which of the following is NOT a typical cause of acute ETT obstruction?', '["Mucus plugging", "Herniated/overinflated cuff prolapsing over the tube tip", "Kinking from external compression", "Well-secured tube with confirmed bilateral breath sounds and easy catheter passage"]'::jsonb, 3, 'A well-secured tube with confirmed bilateral breath sounds and easy suction catheter passage indicates a patent airway, not a cause of obstruction.', 'Pre-Council', '🎓', true),
(7948, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'An overinflated ETT cuff can occasionally herniate over the distal tip of the tube, causing:', '["Cuff pressure to fall to zero automatically", "Improved seal with no risk", "Partial or complete airway obstruction", "Decreased peak airway pressures"]'::jsonb, 2, 'Cuff herniation over the tube''s distal opening can partially or completely occlude the lumen, causing sudden airway obstruction.', 'Pre-Council', '🎓', true),
(7949, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'In the DOPE mnemonic, ruling out "P" (pneumothorax) as a cause of sudden deterioration involves assessing for:', '["Bilateral clear breath sounds with normal chest excursion", "Unilateral decreased breath sounds, tracheal deviation, and hyperresonance to percussion", "Increased exhaled tidal volume", "Low peak airway pressures"]'::jsonb, 1, 'Unilateral decreased breath sounds, tracheal deviation, and hyperresonance to percussion are classic findings of pneumothorax, particularly tension pneumothorax.', 'Pre-Council', '🎓', true),
(7950, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'A capnography waveform showing a gradual upsloping/prolonged expiratory phase (shark-fin pattern) in a ventilated patient suggests:', '["Bronchospasm/airway narrowing causing delayed expiratory airflow", "Complete ETT obstruction", "Esophageal intubation", "Normal airway function"]'::jsonb, 0, 'A shark-fin capnography waveform with a prolonged upsloping expiratory phase reflects delayed, uneven expiratory airflow typical of bronchospasm or airway narrowing.', 'Pre-Council', '🎓', true),
(7951, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'The most reliable immediate bedside method to differentiate ETT obstruction/displacement from a ventilator malfunction is:', '["Change the ventilator alarm settings", "Call radiology for a stat portable film before any bedside action", "Increase the FiO2 and wait five minutes", "Disconnect from the ventilator and ventilate manually with a bag-valve device; if resistance/absent chest rise persists, the problem is with the tube/patient, not the machine"]'::jsonb, 3, 'Manually bagging the patient isolates the ventilator as a variable; if resistance and absent chest rise persist during manual bagging, the problem lies with the tube or patient (obstruction/displacement/pneumothorax) rather than ventilator equipment failure.', 'Pre-Council', '🎓', true),
(7952, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Which of the following is a standard readiness criterion for initiating a spontaneous breathing trial (SBT)?', '["PaO2/FiO2 ratio <100", "Requirement for vasopressor support at high doses", "Ongoing need for deep sedation", "PaO2/FiO2 ratio >150-200 with PEEP \u22645-8 cm H2O and FiO2 \u22640.4-0.5"]'::jsonb, 3, 'Standard SBT readiness criteria include adequate oxygenation (P/F ratio >150-200) on low PEEP and FiO2, hemodynamic stability, and an adequate level of consciousness.', 'Pre-Council', '🎓', true),
(7953, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'The Rapid Shallow Breathing Index (RSBI) is calculated as:', '["Tidal volume divided by respiratory rate", "Respiratory rate divided by tidal volume (in liters)", "Minute ventilation divided by respiratory rate", "PaO2 divided by FiO2"]'::jsonb, 1, 'RSBI (f/VT) is calculated by dividing respiratory rate (breaths/min) by tidal volume in liters, producing a value used to predict weaning success.', 'Pre-Council', '🎓', true),
(7954, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'An RSBI (f/VT) value generally considered predictive of successful weaning is:', '["Greater than 105 breaths/min/L", "Greater than 200 breaths/min/L", "Exactly 0", "Less than 105 breaths/min/L"]'::jsonb, 3, 'An RSBI below 105 breaths/min/L is a widely used threshold suggesting a higher likelihood of successful extubation, while higher values suggest greater risk of weaning failure.', 'Pre-Council', '🎓', true),
(7955, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Before performing a spontaneous breathing trial, which of the following should generally be true of the patient?', '["Requiring high-dose vasopressors", "Actively seizing", "Deeply sedated with no respiratory effort", "Hemodynamically stable, adequately oxygenated, and able to initiate spontaneous breaths"]'::jsonb, 3, 'SBT candidates should be hemodynamically stable, adequately oxygenated, and able to initiate spontaneous respiratory effort, without ongoing acute issues like seizures or high-dose vasopressor requirements.', 'Pre-Council', '🎓', true),
(7956, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'A spontaneous breathing trial is typically conducted using which method(s)?', '["High-frequency oscillatory ventilation", "Full assist-control ventilation at high rate", "Sedation to RASS -5", "T-piece trial or low levels of pressure support/CPAP for a defined period (commonly 30-120 minutes)"]'::jsonb, 3, 'SBTs are commonly conducted via a T-piece or low-level pressure support/CPAP for a defined observation period, typically 30 minutes to 2 hours, while the patient is monitored closely.', 'Pre-Council', '🎓', true),
(7957, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'During a spontaneous breathing trial, which sign indicates the trial should be stopped (trial failure)?', '["Respiratory rate of 18/min with stable vitals", "Mild patient anxiety that resolves with reassurance", "SpO2 maintained at 96%", "Respiratory rate >35/min sustained, significant desaturation, or hemodynamic instability"]'::jsonb, 3, 'Sustained tachypnea (>35/min), significant desaturation, or hemodynamic instability during an SBT indicate trial failure and the need to return to full ventilatory support.', 'Pre-Council', '🎓', true),
(7958, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Which weaning parameter reflects a patient''s inspiratory muscle strength and ability to generate adequate negative pressure?', '["Positive end-expiratory pressure", "FiO2", "Negative inspiratory force (NIF)/maximal inspiratory pressure (MIP)", "I:E ratio"]'::jsonb, 2, 'NIF/MIP measures the maximal negative pressure a patient can generate during a forced inspiratory effort, reflecting respiratory muscle strength relevant to weaning capacity.', 'Pre-Council', '🎓', true),
(7959, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'A negative inspiratory force (NIF) more negative than -20 to -25 cm H2O is generally considered:', '["Predictive of weaning failure", "Irrelevant to weaning decisions", "Favorable for weaning readiness", "Only used in pediatric patients"]'::jsonb, 2, 'A NIF more negative than approximately -20 to -25 cm H2O reflects adequate inspiratory muscle strength and is generally considered favorable for weaning readiness.', 'Pre-Council', '🎓', true),
(7960, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Gradual reduction of ventilator support (e.g., progressively decreasing SIMV rate or pressure support level) as a weaning method is known as:', '["Gradual/incremental weaning", "Immediate extubation", "T-piece trial", "Terminal weaning"]'::jsonb, 0, 'Gradual/incremental weaning progressively reduces ventilator support (mandatory rate or pressure support level) over time as the patient''s own respiratory effort and endurance improve.', 'Pre-Council', '🎓', true),
(7961, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Prior to a planned extubation, the nurse should confirm the patient can:', '["Remain deeply sedated", "Tolerate FiO2 of 100% only", "Require continuous paralysis", "Protect the airway (adequate cough/gag reflex) and follow simple commands"]'::jsonb, 3, 'Successful extubation requires the patient to be able to protect the airway with an adequate cough/gag reflex and to follow simple commands, indicating sufficient neurological status.', 'Pre-Council', '🎓', true),
(7962, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'A "cuff leak test" performed prior to extubation assesses for:', '["Adequacy of tidal volume delivery", "ETT cuff manufacturing defects", "Ventilator circuit integrity", "Risk of post-extubation upper airway edema/obstruction"]'::jsonb, 3, 'The cuff leak test evaluates whether air can pass around the deflated cuff, helping predict the risk of significant laryngeal/upper airway edema causing post-extubation stridor or obstruction.', 'Pre-Council', '🎓', true),
(7963, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Which factor is most likely to contribute to weaning failure?', '["Adequate nutritional status", "Resolved underlying illness", "Normal electrolytes", "Respiratory muscle weakness/fatigue"]'::jsonb, 3, 'Respiratory muscle weakness or fatigue, from disuse, critical illness myopathy, or metabolic derangements, is a leading contributor to failure to wean from mechanical ventilation.', 'Pre-Council', '🎓', true),
(7964, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Correcting which of the following metabolic/nutritional factors is important before attempting to wean a patient from mechanical ventilation?', '["Serum glucose above 300 mg/dL is acceptable", "Anemia is irrelevant to weaning", "Overfeeding is preferred to build strength", "Electrolyte imbalances (e.g., hypophosphatemia, hypokalemia, hypomagnesemia) that impair respiratory muscle function"]'::jsonb, 3, 'Electrolyte disturbances such as hypophosphatemia, hypokalemia, and hypomagnesemia impair respiratory muscle contractility and should be corrected before attempting weaning.', 'Pre-Council', '🎓', true),
(7965, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Overfeeding (excessive caloric/carbohydrate intake) in a ventilated patient can hinder weaning because it:', '["Decreases respiratory muscle strength directly", "Increases CO2 production, raising ventilatory demand", "Causes immediate hypoglycemia", "Has no effect on ventilation"]'::jsonb, 1, 'Excess carbohydrate/caloric intake increases CO2 production through metabolism, raising ventilatory demand and making weaning more difficult.', 'Pre-Council', '🎓', true),
(7966, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'A patient fails a spontaneous breathing trial for the third time over several days. The most appropriate approach is to:', '["Investigate and correct underlying causes of failure (e.g., fluid overload, weakness, secretions, psychological factors) before reattempting", "Proceed with immediate extubation regardless", "Discontinue all further weaning attempts permanently", "Increase sedation to prevent further trials"]'::jsonb, 0, 'Repeated SBT failure warrants systematic evaluation for correctable contributing factors, such as fluid overload, respiratory muscle weakness, secretions, or anxiety, before reattempting weaning.', 'Pre-Council', '🎓', true),
(7967, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Which of the following best describes "terminal weaning" in the context of end-of-life care?', '["Gradual or immediate withdrawal of ventilatory support in a patient for whom further aggressive treatment is not desired, consistent with goals of care", "A routine daily weaning trial", "A method to accelerate extubation in patients expected to recover", "A trial of pressure support ventilation"]'::jsonb, 0, 'Terminal weaning refers to the compassionate withdrawal of ventilatory support, gradually or by extubation, for a patient with a goal-of-care decision to forgo further life-sustaining treatment.', 'Pre-Council', '🎓', true),
(7968, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Pressure support ventilation (PSV) used as a weaning mode works by:', '["Maintaining a fixed high level of support throughout weaning", "Progressively decreasing the level of inspiratory pressure assistance as the patient''s own respiratory effort improves", "Eliminating the need for spontaneous effort", "Increasing tidal volume automatically regardless of patient effort"]'::jsonb, 1, 'As a weaning mode, PSV support is gradually decreased as the patient''s spontaneous respiratory strength and endurance improve, transferring more of the work of breathing to the patient.', 'Pre-Council', '🎓', true),
(7969, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Signs of weaning intolerance during a trial include all of the following EXCEPT:', '["Use of accessory muscles and paradoxical (abdominal) breathing", "Diaphoresis and anxiety", "Improved mentation and stable heart rate", "Significant increase in heart rate or blood pressure"]'::jsonb, 2, 'Improved mentation and a stable heart rate are reassuring findings, not signs of intolerance; accessory muscle use, paradoxical breathing, diaphoresis, anxiety, and significant hemodynamic changes indicate the trial should be stopped.', 'Pre-Council', '🎓', true),
(7970, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'After successful extubation, the nurse should closely monitor the patient for signs of:', '["Immediate discharge readiness", "Resolution of all critical illness", "No further need for oxygen therapy", "Post-extubation stridor, respiratory distress, and need for reintubation"]'::jsonb, 3, 'Close monitoring after extubation is essential to detect early signs of post-extubation stridor, respiratory distress, or failure that may require reintubation.', 'Pre-Council', '🎓', true),
(7971, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'A patient who requires prolonged mechanical ventilation (>2-3 weeks) with failed weaning attempts is often considered for:', '["Immediate discontinuation of all support", "Permanent sedation without further weaning attempts", "Continuous paralysis to reduce oxygen consumption", "Tracheostomy to facilitate ongoing weaning and improve comfort/mobility"]'::jsonb, 3, 'Tracheostomy is often considered for patients with prolonged ventilator dependence, as it improves comfort, reduces sedation needs, facilitates oral care and mobility, and can ease the weaning process.', 'Pre-Council', '🎓', true),
(7972, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'Which psychological/behavioral factor can impair a patient''s ability to wean successfully?', '["Excessive physical strength", "Normal sleep patterns", "Family presence at bedside", "Anxiety and fear of breathing without the ventilator (\"ventilator dependence\")"]'::jsonb, 3, 'Psychological ventilator dependence, driven by anxiety and fear of being unable to breathe independently, can impede weaning progress even when physiologic readiness criteria are met.', 'Pre-Council', '🎓', true),
(7973, 'Ventilators', 'CCN Curriculum — Anaesthesia', 'The primary purpose of a spontaneous breathing trial is to:', '["Permanently wean the patient without further monitoring", "Replace the need for arterial blood gas analysis", "Increase sedation depth prior to extubation", "Assess the patient''s ability to sustain adequate spontaneous ventilation with minimal or no ventilatory support before extubation"]'::jsonb, 3, 'The SBT is a diagnostic trial to determine whether a patient can sustain adequate spontaneous ventilation with minimal support, guiding the decision about readiness for extubation.', 'Pre-Council', '🎓', true),
(7974, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Which inhalational anaesthetic agent has the lowest blood-gas partition coefficient among the following, resulting in the most rapid induction and emergence?', '["Halothane", "Isoflurane", "Desflurane", "Sevoflurane"]'::jsonb, 2, 'Desflurane has a blood:gas partition coefficient of about 0.42, the lowest of the common volatile agents, giving it the fastest onset and offset of action.', 'Pre-Council', '🎓', true),
(7975, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Minimum alveolar concentration (MAC) of an inhalational anaesthetic is defined as the alveolar concentration at 1 atmosphere that:', '["Produces complete loss of consciousness in 95% of patients", "Prevents purposeful movement in response to surgical skin incision in 50% of patients", "Causes apnoea in 50% of patients", "Produces amnesia in 95% of patients"]'::jsonb, 1, 'MAC is the alveolar concentration that prevents movement to a standard surgical stimulus in 50% of subjects; it is a measure of anaesthetic potency, not amnesia or loss of consciousness.', 'Pre-Council', '🎓', true),
(7976, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Which volatile anaesthetic agent has the highest blood-gas partition coefficient, giving it the slowest onset and offset among modern agents?', '["Desflurane", "Sevoflurane", "Halothane", "Nitrous oxide"]'::jsonb, 2, 'Halothane has a blood:gas partition coefficient of about 2.4, making its uptake and elimination the slowest of the commonly compared volatile agents.', 'Pre-Council', '🎓', true),
(7977, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Nitrous oxide cannot be used as a sole general anaesthetic agent mainly because:', '["It has a MAC greater than 100%, so surgical anaesthesia cannot be achieved at 1 atmosphere without hypoxia", "It causes severe myocardial depression", "It is too expensive for routine use", "It has an unacceptably slow onset of action"]'::jsonb, 0, 'Nitrous oxide''s MAC exceeds 100%, meaning concentrations required for surgical anaesthesia would require an anoxic gas mixture; it is therefore used only as an adjunct, not as a sole agent.', 'Pre-Council', '🎓', true),
(7978, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'A key advantage of nitrous oxide as an adjunct anaesthetic gas is its:', '["Potent muscle relaxant property", "Strong analgesic effect with low blood solubility for rapid onset", "Ability to trigger malignant hyperthermia less than other agents", "Hepatotoxic metabolite profile"]'::jsonb, 1, 'Nitrous oxide provides useful analgesia and, due to its low blood solubility, has a rapid onset and offset, though it must be combined with other agents to achieve surgical anaesthesia.', 'Pre-Council', '🎓', true),
(7979, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Sevoflurane is the preferred agent for inhalational induction, particularly in children, mainly because it:', '["Is pungent and speeds airway reflex suppression", "Is non-irritating to the airway, allowing smooth mask induction", "Has the highest blood-gas solubility of all volatile agents", "Requires a heated pressurized vaporizer"]'::jsonb, 1, 'Sevoflurane has a pleasant, non-pungent odour and does not irritate the airway, making it well tolerated for mask induction, especially in paediatric patients.', 'Pre-Council', '🎓', true),
(7980, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Desflurane requires a specially heated, pressurized vaporizer because it:', '["Is highly flammable at room temperature", "Has a boiling point close to room temperature and a high vapour pressure", "Is supplied only as a liquid under high pressure", "Reacts with standard vaporizer metals"]'::jsonb, 1, 'Desflurane boils at about 22.8°C, near room temperature, and has a very high vapour pressure, so it requires an electrically heated, pressurized vaporizer to deliver a controlled concentration.', 'Pre-Council', '🎓', true),
(7981, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'The concentration of inhalational anaesthetic at which a patient responds purposefully to verbal command during emergence is referred to as:', '["MAC-BAR", "MAC-awake", "MAC95", "Blood-gas MAC"]'::jsonb, 1, 'MAC-awake, typically about 0.3-0.5 of standard MAC, is the concentration at which patients begin to respond to verbal commands as anaesthesia lightens.', 'Pre-Council', '🎓', true),
(7982, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'The predominant haemodynamic effect of isoflurane is:', '["Marked myocardial depression with preserved vascular tone", "Dose-dependent peripheral vasodilation with relatively preserved cardiac output", "Severe bradycardia from vagal stimulation", "Coronary vasoconstriction"]'::jsonb, 1, 'Isoflurane causes dose-dependent systemic vasodilation, reducing systemic vascular resistance while largely preserving cardiac output, unlike halothane which more directly depresses contractility.', 'Pre-Council', '🎓', true),
(7983, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Which of the following agents is most likely to cause airway irritation, coughing, and breath-holding, making it unsuitable for inhalational induction?', '["Sevoflurane", "Desflurane", "Nitrous oxide", "Propofol"]'::jsonb, 1, 'Desflurane is pungent and irritates the airway, commonly causing coughing, breath-holding, and laryngospasm if used for induction, so it is reserved for maintenance after the airway is secured.', 'Pre-Council', '🎓', true),
(7984, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'The oxygen flush valve on an anaesthesia machine delivers pure oxygen directly to the common gas outlet, bypassing the vaporizer, at a flow rate of approximately:', '["1-2 L/min", "5-10 L/min", "35-75 L/min", "100-150 L/min"]'::jsonb, 2, 'The oxygen flush valve delivers oxygen at roughly 35-75 L/min directly from the oxygen supply, bypassing the vaporizers, and should never be activated while the patient is connected to the circuit under positive pressure to avoid barotrauma.', 'Pre-Council', '🎓', true),
(7985, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'The "second gas effect" seen with concurrent nitrous oxide administration refers to the phenomenon where:', '["Rapid uptake of nitrous oxide concentrates the co-administered volatile agent and oxygen in the alveoli, speeding their onset", "Nitrous oxide slows the uptake of volatile agents", "Oxygen displaces nitrous oxide from the alveoli", "Volatile agents reduce nitrous oxide solubility"]'::jsonb, 0, 'Because large volumes of nitrous oxide are rapidly taken up into blood, the remaining alveolar gases (including the volatile agent and oxygen) become relatively concentrated, accelerating their rate of rise in alveolar partial pressure.', 'Pre-Council', '🎓', true),
(7986, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Which breathing circuit design is most efficient for spontaneously breathing patients, requiring the lowest fresh gas flow to prevent rebreathing of carbon dioxide?', '["Mapleson A (Magill circuit)", "Mapleson D (Bain circuit)", "Circle system with exhausted absorbent", "Open-drop ether technique"]'::jsonb, 0, 'The Mapleson A configuration is most efficient during spontaneous ventilation, needing fresh gas flow only slightly above minute ventilation to prevent rebreathing, whereas Mapleson D is more efficient for controlled ventilation.', 'Pre-Council', '🎓', true),
(7987, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Total intravenous anaesthesia (TIVA) commonly pairs a propofol infusion with which opioid, chosen for its ultra-short, context-insensitive elimination half-time?', '["Morphine", "Fentanyl", "Remifentanil", "Codeine"]'::jsonb, 2, 'Remifentanil is metabolized by non-specific plasma and tissue esterases, giving it a very short, predictable context-sensitive half-time regardless of infusion duration, making it ideal for TIVA.', 'Pre-Council', '🎓', true),
(7988, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Guedel''s classification describes depth of anaesthesia in how many stages, with which stage representing the ideal plane for surgery?', '["Three stages; Stage II", "Four stages; Stage III", "Five stages; Stage IV", "Two stages; Stage I"]'::jsonb, 1, 'Guedel described four stages of anaesthesia (analgesia, excitement, surgical anaesthesia, and medullary paralysis); Stage III (surgical anaesthesia) is the desired plane for operative procedures.', 'Pre-Council', '🎓', true),
(7989, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Stage II of Guedel''s classification (the "excitement" stage) is clinically significant because it is associated with:', '["Stable, regular respiration and ideal operating conditions", "Irregular breathing, involuntary movement, and heightened risk of laryngospasm or vomiting", "Complete medullary depression and respiratory arrest", "Pure analgesia with retained consciousness"]'::jsonb, 1, 'Stage II occurs between loss of consciousness and the onset of surgical anaesthesia and is marked by excitement, irregular respiration, and reflex hyperactivity, so airway stimulation should be minimized during this stage.', 'Pre-Council', '🎓', true),
(7990, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'A daily pre-use leak test of the anaesthesia breathing circuit and machine is performed primarily to:', '["Confirm accurate gas flowmeter calibration", "Detect leaks that could cause inadequate ventilation or environmental gas contamination", "Verify soda lime colour", "Test the oxygen cylinder pressure"]'::jsonb, 1, 'A leak test ensures the circuit and machine are gas-tight, preventing inadequate delivered volumes to the patient and reducing occupational exposure to waste anaesthetic gas.', 'Pre-Council', '🎓', true),
(7991, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'The soda lime CO2 absorbent in a circle breathing system should be replaced when:', '["It turns from violet back to white", "It changes colour (commonly white/pink to violet/purple) indicating exhaustion", "It becomes warm to the touch", "The canister has been in use for exactly 24 hours regardless of colour"]'::jsonb, 1, 'Ethyl violet indicator dye in soda lime changes colour as the absorbent becomes exhausted (typically turning purple), signalling that it should be replaced to prevent CO2 rebreathing.', 'Pre-Council', '🎓', true),
(7992, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Compound A, a potentially nephrotoxic breakdown product identified in animal studies, forms when which agent is used with low fresh gas flows and desiccated CO2 absorbent?', '["Isoflurane", "Sevoflurane", "Nitrous oxide", "Desflurane"]'::jsonb, 1, 'Sevoflurane degrades in contact with CO2 absorbents (particularly desiccated ones) to form Compound A, which has raised nephrotoxicity concerns at high concentrations and low fresh gas flows.', 'Pre-Council', '🎓', true),
(7993, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Clinically significant carbon monoxide production within an anaesthesia circuit is most associated with which agent reacting with desiccated (dried-out) CO2 absorbent?', '["Sevoflurane", "Desflurane", "Propofol", "Oxygen alone"]'::jsonb, 1, 'Desflurane (and to a lesser extent isoflurane) can react with desiccated absorbent, particularly older barium hydroxide lime, to generate carbon monoxide; keeping absorbent adequately hydrated and changed regularly minimizes this risk.', 'Pre-Council', '🎓', true),
(7994, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'The pin index safety system on anaesthesia machine cylinder yokes exists to:', '["Reduce cylinder weight", "Prevent accidental attachment of the wrong gas cylinder to a given yoke", "Allow rapid cylinder changeover without tools", "Measure remaining cylinder pressure"]'::jsonb, 1, 'The pin index safety system uses a unique pin arrangement for each gas so that only the correct cylinder can be physically mounted on a given yoke, preventing dangerous gas mix-ups.', 'Pre-Council', '🎓', true),
(7995, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'The safety feature that prevents anaesthesia machine gas pipeline hoses from being connected to the wrong wall gas outlet is the:', '["Pin index safety system", "Diameter Index Safety System (DISS) / non-interchangeable connectors", "Oxygen flush valve", "Common gas outlet check valve"]'::jsonb, 1, 'The Diameter (or Non-Interchangeable) Index Safety System uses gas-specific connector diameters/threads for pipeline hoses, preventing cross-connection to the wrong pipeline gas source.', 'Pre-Council', '🎓', true),
(7996, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'During prolonged anaesthesia, the pulse oximeter probe site should be repositioned periodically mainly to prevent:', '["Signal drift", "Pressure or thermal injury to the skin at the probe site", "Battery depletion", "False low heart rate readings"]'::jsonb, 1, 'Continuous pressure and light from the probe LED can cause localized skin injury or thermal burns if left on one site too long, so periodic repositioning is recommended.', 'Pre-Council', '🎓', true),
(7997, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'The anaesthesia machine''s oxygen analyzer should be calibrated before each use, typically against:', '["Nitrous oxide and carbon dioxide", "Room air (21%) and 100% oxygen", "Only 100% oxygen", "The previous day''s stored calibration value"]'::jsonb, 1, 'Calibrating the oxygen analyzer against known reference points of room air (21%) and 100% oxygen ensures accurate readings of delivered inspired oxygen concentration.', 'Pre-Council', '🎓', true),
(7998, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'The scavenging system attached to an anaesthesia machine functions to:', '["Warm and humidify inspired gases", "Remove excess or waste anaesthetic gases from the operating room to limit occupational exposure", "Filter bacteria from inspired gas", "Absorb exhaled carbon dioxide"]'::jsonb, 1, 'Scavenging systems capture excess anaesthetic gases vented from the circuit (e.g., via the APL valve or ventilator relief valve) and remove them from the room, reducing staff exposure to waste anaesthetic gas.', 'Pre-Council', '🎓', true),
(7999, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Which action is an essential part of routine care of vaporizers on an anaesthesia machine?', '["Tilting the vaporizer during transport to speed refilling", "Ensuring the vaporizer is upright and correctly filled with the specific agent it is calibrated for, avoiding cross-contamination", "Adding any available volatile agent when levels run low", "Bypassing the vaporizer interlock system to save time"]'::jsonb, 1, 'Vaporizers are agent-specific and must be filled only with the agent for which they are calibrated; tilting can allow liquid agent into the fresh gas pathway and deliver a dangerous overdose, so agent-specific keyed filling systems and upright handling are used.', 'Pre-Council', '🎓', true),
(8000, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Prolonged lithotomy positioning during anaesthesia places the patient at greatest risk of which nerve injury?', '["Radial nerve palsy", "Common peroneal nerve injury (foot drop)", "Optic nerve ischaemia", "Facial nerve palsy"]'::jsonb, 1, 'In lithotomy position, the common peroneal nerve can be compressed against the lateral head of the fibula by leg supports, resulting in foot drop if padding and positioning are inadequate.', 'Pre-Council', '🎓', true),
(8001, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Taping the eyelids closed during general anaesthesia is primarily intended to prevent:', '["Excessive lacrimation", "Corneal abrasion from loss of the protective blink reflex", "Conjunctival infection", "Intraoperative awareness"]'::jsonb, 1, 'General anaesthesia abolishes the protective blink reflex and reduces tear production, so the cornea is vulnerable to drying and abrasion; taping the eyelids closed protects the ocular surface.', 'Pre-Council', '🎓', true),
(8002, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Active warming and core temperature monitoring during general anaesthesia are important mainly to prevent complications of:', '["Hyperthermia from volatile agents", "Perioperative hypothermia (coagulopathy, arrhythmia, delayed emergence, surgical site infection)", "Excessive sweating", "Fluid overload"]'::jsonb, 1, 'Anaesthesia impairs thermoregulation and promotes heat loss, and resulting hypothermia is associated with coagulopathy, cardiac arrhythmias, delayed drug metabolism/emergence, and increased wound infection risk.', 'Pre-Council', '🎓', true),
(8003, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Hyperabduction of the arm beyond 90 degrees on an arm board during anaesthesia risks injury to which structure?', '["Sciatic nerve", "Brachial plexus", "Femoral nerve", "Ulnar styloid"]'::jsonb, 1, 'Excessive arm abduction can stretch the brachial plexus against the head of the humerus or clavicle, resulting in postoperative neurological deficits in the arm.', 'Pre-Council', '🎓', true),
(8004, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'On arrival of a patient in the post-anaesthesia care unit (PACU), the nurse''s first priority assessment is:', '["Pain score", "Airway patency and adequacy of oxygenation/breathing", "Surgical dressing status", "Urine output"]'::jsonb, 1, 'Airway and breathing take priority immediately post-anaesthesia because airway obstruction or hypoventilation can rapidly become life-threatening as protective reflexes and respiratory drive are still recovering.', 'Pre-Council', '🎓', true),
(8005, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Readiness for discharge from the PACU is commonly assessed using which scoring system?', '["Glasgow Coma Scale", "Modified Aldrete score", "APACHE II score", "Bishop score"]'::jsonb, 1, 'The Modified Aldrete score evaluates activity, respiration, circulation, consciousness, and oxygen saturation to determine a patient''s readiness for discharge from the recovery area.', 'Pre-Council', '🎓', true),
(8006, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'A patient shivering on emergence from general anaesthesia most commonly has this symptom because of:', '["Anxiety", "Perioperative hypothermia and altered thermoregulatory set point", "Hypoglycaemia", "Local anaesthetic toxicity"]'::jsonb, 1, 'Anaesthetic agents impair central thermoregulation and promote heat loss, so postoperative shivering is most often related to intraoperative hypothermia as the body attempts to generate heat.', 'Pre-Council', '🎓', true),
(8007, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'To reduce the risk of aspiration in an unconscious, non-intubated patient recovering from general anaesthesia, the recommended position is:', '["Supine with head flat", "Semi-Fowler''s with neck flexed", "Lateral (recovery) position", "Prone"]'::jsonb, 2, 'The lateral recovery position allows secretions or vomitus to drain away from the airway rather than pool at the back of the throat, reducing aspiration risk while protective reflexes are recovering.', 'Pre-Council', '🎓', true),
(8008, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Pressure area care during prolonged surgical procedures under anaesthesia is essential mainly to prevent:', '["Hypothermia", "Pressure ulcers from prolonged immobility and reduced tissue perfusion", "Deep vein thrombosis", "Emergence delirium"]'::jsonb, 1, 'Anaesthesia abolishes normal protective movement and pain sensation, and prolonged immobility with reduced perfusion at pressure points can cause tissue ischaemia and pressure ulcers if not actively prevented.', 'Pre-Council', '🎓', true),
(8009, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Bispectral index (BIS) monitoring is used intraoperatively to:', '["Measure neuromuscular blockade recovery", "Estimate depth of anaesthesia and help reduce risk of intraoperative awareness", "Monitor blood glucose", "Assess fluid responsiveness"]'::jsonb, 1, 'BIS processes EEG signals into a numeric index reflecting hypnotic depth, helping the anaesthesia team titrate agents to avoid both excessively light anaesthesia (awareness) and excessively deep anaesthesia.', 'Pre-Council', '🎓', true),
(8010, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'A key nursing responsibility during the maintenance phase of general anaesthesia is:', '["Obtaining informed consent", "Continuous monitoring of vital signs, anaesthetic depth, and fluid balance", "Performing the surgical incision", "Selecting the surgical approach"]'::jsonb, 1, 'During maintenance, the anaesthesia team continuously monitors haemodynamics, ventilation, depth of anaesthesia, and fluid/blood loss to keep the patient stable throughout the procedure.', 'Pre-Council', '🎓', true),
(8011, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Proper limb support and avoidance of joint hyperextension during anaesthesia are important because:', '["Anaesthesia enhances joint proprioception", "Loss of protective muscle tone under anaesthesia increases the risk of joint and nerve stretch injury", "Muscle relaxants strengthen ligaments", "It prevents surgical site infection"]'::jsonb, 1, 'General anaesthesia and neuromuscular blockade abolish normal muscle tone and protective reflexes, so joints and nerves can be injured by positions or forces that an awake patient would normally guard against.', 'Pre-Council', '🎓', true),
(8012, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Postoperative nausea and vomiting (PONV) is most strongly associated with the use of which anaesthetic gas?', '["Sevoflurane", "Nitrous oxide", "Oxygen", "Desflurane"]'::jsonb, 1, 'Nitrous oxide is a well-established independent risk factor for PONV, thought to relate to its effects on the middle ear, gut distension, and dopaminergic pathways.', 'Pre-Council', '🎓', true),
(8013, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Clinical use of halothane has become limited mainly because of the risk of:', '["Malignant hyperthermia only", "Halothane hepatitis (fulminant hepatic necrosis)", "Nephrotoxic Compound A formation", "Diffusion hypoxia"]'::jsonb, 1, 'Halothane is associated with rare but potentially fatal immune-mediated hepatitis, particularly with repeated exposure, which has led to its replacement by safer modern volatile agents in most settings.', 'Pre-Council', '🎓', true),
(8014, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Malignant hyperthermia is a life-threatening hypermetabolic reaction most classically triggered by:', '["Propofol and remifentanil", "Volatile anaesthetics and succinylcholine", "Nitrous oxide alone", "Local anaesthetics"]'::jsonb, 1, 'Malignant hyperthermia is triggered in genetically susceptible individuals by potent volatile anaesthetics and the depolarizing muscle relaxant succinylcholine, causing uncontrolled calcium release in skeletal muscle.', 'Pre-Council', '🎓', true),
(8015, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'An early, reliable sign of malignant hyperthermia during general anaesthesia is:', '["Falling end-tidal CO2 despite stable ventilation", "Rising end-tidal CO2 unresponsive to increased minute ventilation", "Bradycardia and hypotension", "Hypothermia"]'::jsonb, 1, 'A sudden, unexplained rise in end-tidal CO2 that persists despite increasing minute ventilation is one of the earliest and most sensitive indicators of the hypermetabolic state of malignant hyperthermia.', 'Pre-Council', '🎓', true),
(8016, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'The definitive pharmacological treatment for malignant hyperthermia is:', '["Neostigmine", "Dantrolene sodium", "Flumazenil", "Naloxone"]'::jsonb, 1, 'Dantrolene inhibits calcium release from the sarcoplasmic reticulum via the ryanodine receptor, directly reversing the pathological muscle hypermetabolism of malignant hyperthermia.', 'Pre-Council', '🎓', true),
(8017, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Nitrous oxide is contraindicated in patients with a pneumothorax or bowel obstruction because it:', '["Is metabolized to a toxic compound in these conditions", "Diffuses into closed, air-filled body spaces faster than nitrogen can leave, expanding trapped gas volume", "Causes severe bronchospasm", "Reduces intra-abdominal pressure"]'::jsonb, 1, 'Nitrous oxide is far more soluble in blood than nitrogen, so it diffuses into closed gas-filled spaces faster than nitrogen diffuses out, expanding the volume or increasing pressure within spaces such as a pneumothorax or obstructed bowel.', 'Pre-Council', '🎓', true),
(8018, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Emergence delirium after general anaesthesia is more commonly reported with which agent, particularly in paediatric patients?', '["Isoflurane", "Sevoflurane", "Propofol", "Remifentanil"]'::jsonb, 1, 'Sevoflurane, despite being favoured for smooth induction, is associated with a higher incidence of emergence agitation/delirium in children compared with some other agents.', 'Pre-Council', '🎓', true),
(8019, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Which volatile anaesthetic agent is most associated with sensitizing the myocardium to catecholamines, predisposing to arrhythmias, particularly if epinephrine is administered concurrently?', '["Sevoflurane", "Halothane", "Desflurane", "Nitrous oxide"]'::jsonb, 1, 'Halothane sensitizes the myocardium to circulating catecholamines more than other modern volatile agents, increasing the risk of ventricular arrhythmias when epinephrine-containing solutions are used.', 'Pre-Council', '🎓', true),
(8020, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Prolonged or repeated exposure to nitrous oxide can impair vitamin B12-dependent methionine synthase activity, potentially resulting in:', '["Megaloblastic anaemia and subacute combined degeneration of the spinal cord", "Iron deficiency anaemia", "Hepatic cirrhosis", "Acute tubular necrosis"]'::jsonb, 0, 'Nitrous oxide irreversibly oxidizes the cobalt ion in vitamin B12, inactivating methionine synthase; with prolonged or repeated exposure this can cause megaloblastic anaemia and neurological changes resembling subacute combined degeneration.', 'Pre-Council', '🎓', true),
(8021, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'A patient''s endotracheal tube cuff, inflated with air, is left in place during a prolonged case using nitrous oxide. A recognized risk of this combination is:', '["Cuff deflation over time", "Progressive cuff overinflation as nitrous oxide diffuses into the cuff, risking tracheal mucosal ischaemia", "Cuff material degradation", "Reduced cuff pressure requiring frequent reinflation"]'::jsonb, 1, 'Nitrous oxide diffuses into the air-filled cuff faster than air (mainly nitrogen) diffuses out, causing cuff pressure and volume to rise progressively during prolonged use, which can compress the tracheal mucosa and cause ischaemic injury.', 'Pre-Council', '🎓', true),
(8022, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'In a patient with reactive airway disease, the pungency of desflurane increases the intraoperative risk of:', '["Malignant hyperthermia", "Bronchospasm and laryngospasm", "Hepatotoxicity", "Diffusion hypoxia"]'::jsonb, 1, 'Desflurane''s airway-irritant properties can precipitate coughing, breath-holding, laryngospasm, or bronchospasm, especially in patients with hyperreactive airways, so it is generally avoided during induction or in poorly controlled asthma/COPD.', 'Pre-Council', '🎓', true),
(8023, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Compared with the other agents listed, which is most likely to cause direct, dose-dependent myocardial contractile depression rather than predominantly vasodilation?', '["Isoflurane", "Desflurane", "Halothane", "Sevoflurane at low concentrations"]'::jsonb, 2, 'Halothane depresses myocardial contractility more directly than isoflurane, desflurane, or sevoflurane, which cause relatively more vasodilation with better-preserved cardiac output at equivalent MAC.', 'Pre-Council', '🎓', true),
(8024, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Laryngospasm occurring during light planes of anaesthesia is best initially managed by:', '["Immediate tracheostomy", "Applying jaw thrust and positive pressure ventilation with 100% oxygen while deepening anaesthesia", "Administering atropine only", "Suctioning the oropharynx repeatedly without other intervention"]'::jsonb, 1, 'Initial management of laryngospasm includes removing the stimulus, applying continuous positive airway pressure with 100% oxygen and jaw thrust, and deepening anaesthesia; muscle relaxants are reserved for refractory cases.', 'Pre-Council', '🎓', true),
(8025, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Intraoperative awareness under general anaesthesia is most likely to occur when:', '["High-dose volatile anaesthesia is used throughout", "Neuromuscular blocking agents are used without adequate depth of anaesthesia, e.g., during rapid sequence induction in unstable trauma patients", "BIS monitoring reads below 40 throughout the case", "Nitrous oxide is combined with a volatile agent"]'::jsonb, 1, 'Awareness risk rises when paralysis masks inadequate hypnotic depth, such as during light anaesthesia used for haemodynamically unstable patients or rapid sequence inductions, since the patient cannot move to signal distress.', 'Pre-Council', '🎓', true),
(8026, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Anaphylaxis occurring during induction of anaesthesia is most commonly triggered by which class of drugs?', '["Inhalational agents", "Neuromuscular blocking agents", "Benzodiazepines", "Local anaesthetics"]'::jsonb, 1, 'Neuromuscular blocking agents are the most frequent cause of perioperative anaphylaxis, followed by antibiotics and latex, due to IgE-mediated or direct histamine-releasing mechanisms.', 'Pre-Council', '🎓', true),
(8027, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'A sudden, near-complete loss of the capnography waveform (end-tidal CO2 falling to near zero) in an intubated, ventilated patient most urgently suggests:', '["Mild hypoventilation", "Circuit disconnection, accidental extubation/oesophageal intubation, or cardiac arrest", "Rebreathing from exhausted soda lime", "Excessive anaesthetic depth"]'::jsonb, 1, 'An abrupt drop of ETCO2 to near zero is a critical alarm suggesting complete loss of pulmonary gas exchange from the sampled circuit — due to disconnection, tube dislodgement/oesophageal placement, or sudden loss of cardiac output — and demands immediate assessment of the airway and circulation.', 'Pre-Council', '🎓', true),
(8028, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Delivering FiO2 of 100% for a prolonged period under anaesthesia carries a risk of:', '["Diffusion hypoxia", "Absorption (resorption) atelectasis", "Oxygen toxicity to the retina in adults", "Carbon monoxide poisoning"]'::jsonb, 1, 'High inspired oxygen concentrations wash out alveolar nitrogen; when regional ventilation is low relative to perfusion, the oxygen is absorbed faster than it is replenished, causing alveolar collapse (absorption atelectasis).', 'Pre-Council', '🎓', true),
(8029, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Venous air embolism is a recognized risk particularly associated with which surgical position?', '["Supine", "Lithotomy", "Sitting/beach chair position (e.g., for posterior fossa neurosurgery)", "Prone"]'::jsonb, 2, 'The sitting position places the operative site above the level of the heart, creating a pressure gradient that can draw air into open venous sinuses (e.g., in neurosurgery), increasing venous air embolism risk.', 'Pre-Council', '🎓', true),
(8030, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Residual neuromuscular blockade in the immediate postoperative period increases the risk of:', '["Malignant hyperthermia", "Hypoxaemia and airway obstruction due to impaired pharyngeal and respiratory muscle function", "Emergence delirium only", "Hypertension"]'::jsonb, 1, 'Inadequately reversed neuromuscular blockade impairs upper airway muscle tone and ventilatory effort, predisposing to airway obstruction, hypoventilation, hypoxaemia, and aspiration.', 'Pre-Council', '🎓', true),
(8031, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Prolonged pressure over the head of the fibula during surgery, from a poorly padded leg support, places which nerve at greatest risk?', '["Common peroneal nerve", "Tibial nerve", "Obturator nerve", "Femoral nerve"]'::jsonb, 0, 'The common peroneal nerve winds superficially around the fibular head and is vulnerable to compression injury from poorly padded supports or straps, resulting in foot drop.', 'Pre-Council', '🎓', true),
(8032, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'The most common cause of hypotension immediately following the onset of spinal or epidural anaesthesia is:', '["Local anaesthetic systemic toxicity", "Sympathetic blockade causing vasodilation and venous pooling", "Anaphylaxis to local anaesthetic", "Acute blood loss"]'::jsonb, 1, 'Neuraxial blockade interrupts sympathetic outflow, causing arterial and venous vasodilation with reduced venous return and systemic vascular resistance, commonly producing hypotension.', 'Pre-Council', '🎓', true),
(8033, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'In a patient with a full stomach requiring emergency induction of anaesthesia, aspiration risk is reduced primarily by using:', '["Slow, titrated inhalational induction", "Rapid sequence induction with cricoid pressure and a cuffed endotracheal tube", "Awake fiberoptic intubation only in every case", "Deep sedation without airway securement"]'::jsonb, 1, 'Rapid sequence induction minimizes the time between loss of airway reflexes and securing the airway with a cuffed tube, while cricoid pressure aims to occlude the oesophagus and reduce passive regurgitation.', 'Pre-Council', '🎓', true),
(8034, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'During mechanical ventilation under anaesthesia, a sudden rise in peak airway pressure accompanied by absent breath sounds on the left and preserved breath sounds on the right most suggests:', '["Right mainstem bronchial intubation", "Bronchospasm", "Disconnected circuit", "Extubation"]'::jsonb, 0, 'If the endotracheal tube has migrated too far and entered the right mainstem bronchus, the left lung is excluded from ventilation, producing unilateral absent breath sounds and increased airway pressures; the tube should be withdrawn slightly and position confirmed.', 'Pre-Council', '🎓', true),
(8035, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'A postoperative patient develops sudden dyspnoea, tachycardia, hypotension, and hypoxaemia several days after major surgery; the leading concern, given prolonged immobilization, is:', '["Acute myocardial infarction only", "Pulmonary embolism from deep vein thrombosis", "Pneumothorax", "Anaphylaxis"]'::jsonb, 1, 'Postoperative immobility, surgical tissue trauma, and hypercoagulability increase venous thromboembolism risk; sudden dyspnoea, hypoxaemia, tachycardia, and hypotension in this setting should prompt urgent evaluation for pulmonary embolism.', 'Pre-Council', '🎓', true),
(8036, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Immediate management of suspected anaphylaxis during induction of anaesthesia includes:', '["Continuing the suspected triggering agent at a lower dose", "Stopping the likely triggering agent, giving 100% oxygen, and administering intramuscular or intravenous epinephrine", "Administering an antihistamine alone and observing", "Deepening anaesthesia with additional volatile agent"]'::jsonb, 1, 'Anaphylaxis is a medical emergency; management requires immediately stopping the suspected trigger, securing the airway with 100% oxygen, and giving epinephrine as first-line treatment, alongside fluids and further supportive care.', 'Pre-Council', '🎓', true),
(8037, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Which patient characteristic is most predictive of difficult bag-mask ventilation, independent of intubation difficulty?', '["Short neck circumference only", "Obesity (BMI significantly elevated), presence of a beard, or edentulous state", "Normal Mallampati score", "Full dentition"]'::jsonb, 1, 'Predictors of difficult mask ventilation include obesity, a beard (poor mask seal), edentulism (loss of facial/airway support), age, snoring history, and a limited jaw protrusion — features distinct from, though sometimes overlapping with, predictors of difficult laryngoscopy.', 'Pre-Council', '🎓', true),
(8038, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Hypoxaemic hypoxia is defined by:', '["Reduced haemoglobin concentration with normal PaO2", "Low arterial partial pressure of oxygen (PaO2)", "Normal PaO2 but impaired tissue oxygen utilization", "Reduced cardiac output with normal PaO2"]'::jsonb, 1, 'Hypoxaemic hypoxia refers specifically to a reduced arterial partial pressure of oxygen, which reduces the driving pressure for oxygen diffusion into tissues.', 'Pre-Council', '🎓', true),
(8039, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Cyanide poisoning is a classic example of which type of hypoxia?', '["Anaemic hypoxia", "Stagnant (circulatory) hypoxia", "Histotoxic hypoxia", "Hypoxaemic hypoxia"]'::jsonb, 2, 'Cyanide blocks cytochrome c oxidase in the mitochondrial electron transport chain, preventing cells from using oxygen despite normal PaO2 and haemoglobin, defining histotoxic hypoxia.', 'Pre-Council', '🎓', true),
(8040, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'In a sedated, spontaneously breathing patient developing hypoxia, which sign typically appears earliest, before overt cyanosis?', '["Cyanosis", "Restlessness and tachycardia", "Bradycardia and hypotension", "Coma"]'::jsonb, 1, 'Early hypoxia typically produces sympathetic activation with restlessness, agitation, and tachycardia; cyanosis and bradycardia are later, more ominous signs of severe or prolonged hypoxia.', 'Pre-Council', '🎓', true),
(8041, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Pulse oximetry (SpO2) shows a clinically significant drop only after PaO2 falls below approximately:', '["100 mmHg", "80 mmHg", "60 mmHg", "40 mmHg"]'::jsonb, 2, 'Because of the shape of the oxyhaemoglobin dissociation curve, SpO2 remains relatively well preserved until PaO2 drops below about 60 mmHg, after which small further falls in PaO2 cause steep drops in saturation.', 'Pre-Council', '🎓', true),
(8042, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Diffusion hypoxia after discontinuing nitrous oxide anaesthesia is best prevented by:', '["Rapidly increasing volatile agent concentration", "Administering 100% oxygen for several minutes at the end of the case before returning to room air", "Hyperventilating the patient with room air", "Administering naloxone"]'::jsonb, 1, 'When nitrous oxide is discontinued, its rapid outward diffusion into the alveoli can dilute alveolar oxygen and cause transient hypoxia; giving 100% oxygen for several minutes prevents this diffusion hypoxia.', 'Pre-Council', '🎓', true),
(8043, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'The oxyhaemoglobin dissociation curve shifts to the right, favouring oxygen unloading at the tissues, in the presence of:', '["Alkalosis, hypothermia, and low 2,3-DPG", "Acidosis, hyperthermia, hypercapnia, and increased 2,3-DPG", "Fetal haemoglobin predominance", "Carbon monoxide poisoning"]'::jsonb, 1, 'Increased temperature, PaCO2, hydrogen ion concentration (acidosis), and 2,3-DPG all shift the curve rightward, reducing haemoglobin''s oxygen affinity and enhancing oxygen release to tissues.', 'Pre-Council', '🎓', true),
(8044, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Clinically visible cyanosis typically requires an absolute deoxyhaemoglobin concentration of approximately:', '["1 g/dL", "5 g/dL", "10 g/dL", "15 g/dL"]'::jsonb, 1, 'Cyanosis generally becomes visible when deoxygenated haemoglobin reaches about 5 g/dL, which is why severely anaemic patients may not appear cyanotic even when significantly hypoxaemic.', 'Pre-Council', '🎓', true),
(8045, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Anaemic hypoxia is characterized by:', '["Low PaO2 with normal haemoglobin", "Normal PaO2 and SpO2 but reduced oxygen-carrying capacity due to low haemoglobin concentration", "Normal haemoglobin but impaired cellular oxygen use", "Reduced cardiac output with normal haemoglobin"]'::jsonb, 1, 'In anaemic hypoxia, arterial oxygen tension and saturation may be normal, but the reduced total haemoglobin lowers overall oxygen content and delivery to tissues.', 'Pre-Council', '🎓', true),
(8046, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Hypoxaemia caused by true intrapulmonary shunt (blood perfusing completely unventilated alveoli) typically:', '["Corrects readily with modest increases in FiO2", "Responds poorly to supplemental oxygen because shunted blood never contacts ventilated alveoli", "Is unaffected by PEEP", "Occurs only with hypoventilation"]'::jsonb, 1, 'Because shunted blood bypasses ventilated alveoli entirely, increasing FiO2 does little to raise its oxygen content, distinguishing shunt from V/Q mismatch, which does improve with supplemental oxygen.', 'Pre-Council', '🎓', true),
(8047, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'A common cause of hypoxaemia in the immediate period after extubation is:', '["Excessive analgesia only", "Upper airway obstruction/laryngospasm or residual neuromuscular blockade causing hypoventilation", "Hyperthyroidism", "Diuretic use"]'::jsonb, 1, 'After extubation, incompletely recovered airway reflexes, laryngospasm, or residual paralysis can cause airway obstruction or hypoventilation, both of which can produce postextubation hypoxaemia.', 'Pre-Council', '🎓', true),
(8048, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Initial management of hypoxia in a critically ill anaesthetized or ventilated patient should begin with:', '["Diuretic administration", "Ensuring airway patency and delivering a high fraction of inspired oxygen while identifying the underlying cause", "Immediate intubation regardless of the cause", "Sedation to reduce oxygen demand"]'::jsonb, 1, 'The first priority in hypoxia is to secure the airway and maximize oxygen delivery (e.g., 100% oxygen) while rapidly assessing for and treating the underlying cause, such as obstruction, hypoventilation, or shunt.', 'Pre-Council', '🎓', true),
(8049, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Diffusion-limited hypoxaemia, due to impaired gas exchange across a thickened alveolar-capillary membrane, is most characteristic of:', '["Acute asthma exacerbation", "Pulmonary fibrosis or severe pulmonary oedema", "Simple hypoventilation from opioid overdose", "High-altitude exposure alone"]'::jsonb, 1, 'Conditions that thicken or damage the alveolar-capillary interface, such as pulmonary fibrosis or oedema, impair oxygen diffusion, particularly evident during exercise or high metabolic demand.', 'Pre-Council', '🎓', true),
(8050, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Type I (hypoxaemic) respiratory failure is characterized on arterial blood gas by:', '["Low PaO2 with normal or low PaCO2", "Low PaO2 with markedly elevated PaCO2", "Normal PaO2 with elevated PaCO2", "Elevated PaO2 with elevated PaCO2"]'::jsonb, 0, 'Type I respiratory failure reflects a primary oxygenation defect (e.g., V/Q mismatch, shunt, diffusion impairment) with PaO2 low while PaCO2 remains normal or low, in contrast to Type II failure where ventilatory failure raises PaCO2.', 'Pre-Council', '🎓', true),
(8051, 'Anaesthesia and Anaesthetic Gases', 'CCN Curriculum — Anaesthesia', 'Which type of hypoxia results from inadequate blood flow to tissues despite normal arterial oxygen content, such as in cardiogenic shock?', '["Hypoxaemic hypoxia", "Stagnant (circulatory) hypoxia", "Histotoxic hypoxia", "Anaemic hypoxia"]'::jsonb, 1, 'Stagnant or circulatory hypoxia occurs when blood flow (cardiac output or regional perfusion) is inadequate to deliver oxygen to tissues, even though arterial oxygen content itself may be normal, as seen in shock states.', 'Pre-Council', '🎓', true),
(8052, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Why is close respiratory monitoring essential after IV opioid administration in the immediate post-operative period?', '["Opioids increase respiratory rate and cause hyperventilation", "Opioids depress the medullary respiratory center, causing dose-dependent respiratory depression", "Opioids cause bronchospasm in almost all patients", "Opioids stimulate the cough reflex, causing airway obstruction"]'::jsonb, 1, 'Opioids act on mu-receptors in the brainstem respiratory centers, reducing the response to rising CO2 and causing dose-dependent respiratory depression, the most dangerous complication of opioid analgesia.', 'Pre-Council', '🎓', true),
(8053, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What is the main rationale for using multimodal analgesia after major surgery?', '["It simplifies nursing documentation of pain scores", "It targets multiple pain pathways, reducing the opioid dose needed and minimizing opioid-related side effects", "It ensures the patient receives the maximum dose of every drug class", "It is required only in patients who are allergic to opioids"]'::jsonb, 1, 'Combining agents with different mechanisms (e.g., opioid, NSAID/paracetamol, regional block) provides synergistic analgesia while allowing lower doses of each, reducing opioid-related adverse effects.', 'Pre-Council', '🎓', true),
(8054, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'A post-operative patient on morphine PCA is found with a respiratory rate of 6/min, pinpoint pupils, and is difficult to rouse. What is the priority nursing action?', '["Administer an additional bolus dose to prevent breakthrough pain", "Increase the PCA basal infusion rate", "Stop the opioid, stimulate the patient, support airway/ventilation, and prepare to administer naloxone", "Administer flumazenil immediately"]'::jsonb, 2, 'This presentation is classic opioid-induced respiratory depression; the opioid must be stopped and naloxone (the opioid antagonist) prepared while supporting oxygenation/ventilation. Flumazenil reverses benzodiazepines, not opioids.', 'Pre-Council', '🎓', true),
(8055, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What precaution must nurses observe after giving naloxone to reverse opioid-induced respiratory depression?', '["Naloxone has no effect on respiratory rate", "A single dose permanently reverses opioid analgesia for 24 hours", "Naloxone is contraindicated in opioid overdose", "Naloxone''s duration of action is often shorter than the opioid''s, so renarcotization can occur and repeat dosing or close monitoring is needed"]'::jsonb, 3, 'Because naloxone is metabolized faster than many opioids, respiratory depression can recur once it wears off, so the patient must be monitored closely and may need repeated doses or an infusion.', 'Pre-Council', '🎓', true),
(8056, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What is the most concerning complication of epidural analgesia related to sympathetic nervous system blockade?', '["Hyperactive bowel sounds", "Hypertension crisis", "Hypotension from vasodilation", "Increased urine output"]'::jsonb, 2, 'Local anesthetic in the epidural space blocks sympathetic fibers, causing vasodilation and a drop in blood pressure that requires monitoring and sometimes fluids or vasopressors.', 'Pre-Council', '🎓', true),
(8057, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'A patient with an epidural infusion develops progressively worsening lower-limb weakness and new severe back pain. What complication must be urgently ruled out?', '["A slight blood pressure drop that responds to fluids", "Nausea relieved by an antiemetic", "Epidural hematoma", "Mild pruritus at the insertion site"]'::jsonb, 2, 'Progressive motor weakness with back pain after epidural placement/removal is a red-flag sign of epidural hematoma, a neurosurgical emergency requiring urgent imaging and decompression to prevent permanent paralysis.', 'Pre-Council', '🎓', true),
(8058, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What precaution should guide the use of NSAIDs such as diclofenac for post-operative pain?', '["They are safe in all patients regardless of renal function", "They should be used cautiously because they can cause GI bleeding, renal impairment, and platelet dysfunction, especially in hypovolemic or elderly patients", "They have no interaction with anticoagulant therapy", "They are always preferred over opioids for severe visceral pain"]'::jsonb, 1, 'NSAIDs inhibit prostaglandin synthesis, which can reduce renal perfusion, impair platelet aggregation, and irritate the gastric mucosa, so they require caution in high-risk patients.', 'Pre-Council', '🎓', true),
(8059, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What is the main reason pethidine (meperidine) is used with caution, especially in patients with renal impairment or requiring repeated dosing?', '["It has no active metabolites", "Its metabolite normeperidine can accumulate and cause CNS excitation and seizures", "It is preferred for prolonged use in critically ill patients", "It is safe to combine with MAOIs"]'::jsonb, 1, 'Normeperidine, an active renally-cleared metabolite of pethidine, accumulates with repeated dosing or renal impairment and can cause tremors, agitation, and seizures.', 'Pre-Council', '🎓', true),
(8060, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What is the key safety feature of a patient-controlled analgesia (PCA) pump that helps prevent opioid overdose?', '["Unlimited demand doses with no restriction", "Removing the need for ongoing nursing monitoring", "Allowing family members to press the button on the patient''s behalf when they are asleep", "A programmed lockout interval that limits how often the patient can receive a demand dose"]'::jsonb, 3, 'The lockout interval prevents the patient from redosing before the previous dose has taken effect, reducing the risk of cumulative overdose; ''PCA by proxy'' (others pressing the button) is a recognized danger that bypasses this safety mechanism.', 'Pre-Council', '🎓', true),
(8061, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Which patient would be considered a poor candidate for patient-controlled analgesia (PCA)?', '["A confused or heavily sedated patient who cannot understand how to use the device", "A patient with pre-existing opioid tolerance", "A cognitively intact adult patient", "A young adult recovering from elective surgery"]'::jsonb, 0, 'PCA relies on the patient being able to understand and self-administer doses; confusion, heavy sedation, or very young age make safe self-dosing unreliable.', 'Pre-Council', '🎓', true),
(8062, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What is the main clinical benefit of combining IV paracetamol, an NSAID, and an opioid in a multimodal regimen?', '["Reduced need for any pain assessment", "Lower overall drug cost only", "Reduced total opioid consumption and fewer opioid-related side effects such as sedation and respiratory depression", "Reduced risk of surgical site infection"]'::jsonb, 2, 'Multimodal analgesia lowers the opioid dose required to achieve pain control, which directly reduces the incidence of opioid-related adverse effects.', 'Pre-Council', '🎓', true),
(8063, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Which pain assessment tool is most appropriate for a sedated, intubated post-operative ICU patient who cannot self-report pain?', '["Behavioral Pain Scale (BPS) or Critical-Care Pain Observation Tool (CPOT)", "Numeric Rating Scale (NRS) verbal report", "FACES pain scale", "Visual Analog Scale (VAS)"]'::jsonb, 0, 'BPS and CPOT use observable indicators (facial expression, movement, muscle tension, ventilator compliance) and are validated for patients unable to self-report, unlike scales that require verbal or visual self-rating.', 'Pre-Council', '🎓', true),
(8064, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Before administering an opioid analgesic to a post-operative patient, what precaution should the nurse always take?', '["Give a double dose to first-time opioid recipients", "No assessment is needed if the patient reports pain", "Withhold supplemental oxygen before dosing", "Assess the sedation level, respiratory rate, and SpO2, and ensure naloxone and resuscitation equipment are available"]'::jsonb, 3, 'Baseline respiratory and sedation assessment before opioid administration allows early detection of over-sedation, and having reversal agents ready ensures rapid response if respiratory depression occurs.', 'Pre-Council', '🎓', true),
(8065, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'How does adequate post-operative pain control help prevent pulmonary complications after abdominal or thoracic surgery?', '["It enables the patient to breathe deeply, cough effectively, and mobilize early, reducing the risk of atelectasis", "Heavy sedation without analgesia is preferred to keep the patient still", "Withholding analgesia forces protective shallow, guarded breathing", "It keeps the patient sedated and immobile to conserve energy"]'::jsonb, 0, 'Uncontrolled pain causes splinting and shallow breathing, which predisposes to atelectasis and pneumonia; good analgesia supports deep breathing, coughing, and early ambulation.', 'Pre-Council', '🎓', true),
(8066, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Which gastrointestinal complication is commonly associated with prolonged opioid analgesic use in post-operative ICU patients?', '["Diarrhea from increased peristalsis", "Increased appetite", "Hyperactive bowel sounds", "Constipation or paralytic ileus from decreased gastrointestinal motility"]'::jsonb, 3, 'Opioids act on mu-receptors in the gut wall, slowing peristalsis and increasing sphincter tone, which commonly causes constipation and can contribute to ileus.', 'Pre-Council', '🎓', true),
(8067, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'A patient develops pruritus (itching) after intrathecal morphine for post-operative pain. What is the most appropriate initial management?', '["Switch to an NSAID immediately regardless of pain control", "Ignore it, as it never requires intervention", "Give an immediate high dose of opioid antagonist, stopping analgesia completely", "Give an antihistamine and reassure the patient; consider low-dose naloxone only if severe, without necessarily stopping analgesia"]'::jsonb, 3, 'Opioid-induced pruritus is common and usually managed symptomatically with antihistamines; complete reversal is reserved for severe or refractory cases since it would also negate analgesia.', 'Pre-Council', '🎓', true),
(8068, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'How should opioid dosing generally be adjusted in elderly post-operative patients compared with younger adults?', '["Start with higher doses than younger adults", "Start with lower doses and titrate more slowly due to altered pharmacokinetics and increased sensitivity", "Opioids are contraindicated in all elderly patients", "No dose adjustment is required"]'::jsonb, 1, 'Reduced renal/hepatic clearance, increased body fat, and greater CNS sensitivity in older adults raise the risk of accumulation and over-sedation, so lower starting doses and careful titration are recommended.', 'Pre-Council', '🎓', true),
(8069, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What is the mechanism behind opioid-induced urinary retention after post-operative analgesia?', '["Opioids have no effect on bladder function", "Opioids increase bladder detrusor contractility", "Opioids have a diuretic effect that fills the bladder faster", "Opioids inhibit detrusor muscle contraction and increase bladder sphincter tone"]'::jsonb, 3, 'Opioid receptors in the sacral spinal cord and bladder wall reduce detrusor contractility and increase sphincter tone, impairing voiding and predisposing to urinary retention.', 'Pre-Council', '🎓', true),
(8070, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What is the most common cause of unintentional hypothermia in the immediate post-anesthesia period?', '["A hypermetabolic state from surgical stress", "Shivering thermogenesis raising core temperature", "Redistribution of core body heat to the periphery caused by anesthesia-induced vasodilation", "Fever from an active infection"]'::jsonb, 2, 'General and regional anesthesia impair thermoregulation and cause vasodilation, redistributing warm core blood to cooler peripheral tissues, which is the leading cause of the early post-operative drop in core temperature.', 'Pre-Council', '🎓', true),
(8071, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Why is post-operative hypothermia (core temperature below 36 degrees C) clinically significant?', '["It speeds up drug metabolism", "It can cause coagulopathy, increased blood loss, cardiac arrhythmias, and delayed emergence from anesthesia", "It decreases oxygen consumption with no adverse effects", "It improves wound healing"]'::jsonb, 1, 'Hypothermia impairs platelet function and clotting enzymes, increases myocardial irritability, and slows drug metabolism, all of which worsen post-operative outcomes.', 'Pre-Council', '🎓', true),
(8072, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Why does shivering in a hypothermic post-operative patient pose a clinical risk?', '["It has no significant metabolic effect", "It increases oxygen supply to the tissues", "It increases oxygen consumption and metabolic demand, which can precipitate myocardial ischemia in vulnerable patients", "It restores core temperature instantly without any risk"]'::jsonb, 2, 'Shivering can increase whole-body oxygen consumption several-fold, which can be dangerous in patients with limited cardiac or respiratory reserve.', 'Pre-Council', '🎓', true),
(8073, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What is the best nursing intervention to prevent or treat post-operative hypothermia?', '["Applying ice packs to the trunk", "Rapidly infusing cold crystalloid solution", "Active external warming (e.g., forced-air warming blanket) and administration of warmed IV fluids", "Increasing room air conditioning"]'::jsonb, 2, 'Active warming measures such as forced-air blankets combined with pre-warmed IV fluids are standard interventions to restore and maintain normothermia post-operatively.', 'Pre-Council', '🎓', true),
(8074, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Malignant hyperthermia (MH) is triggered by which agents in genetically susceptible individuals?', '["IV paracetamol", "Volatile inhalational anesthetics and succinylcholine", "All opioid analgesics", "Regional anesthesia alone"]'::jsonb, 1, 'MH is a pharmacogenetic disorder triggered specifically by depolarizing muscle relaxants (succinylcholine) and volatile anesthetic gases in patients with an underlying ryanodine receptor mutation.', 'Pre-Council', '🎓', true),
(8075, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What is the underlying pathophysiology of malignant hyperthermia?', '["Adrenal insufficiency causing a cortisol deficit", "An abnormal ryanodine receptor causes uncontrolled calcium release from the sarcoplasmic reticulum, leading to sustained muscle contraction and a hypermetabolic state", "Thyroid hormone deficiency", "Acute hypoglycemia"]'::jsonb, 1, 'In susceptible individuals, the mutated ryanodine receptor (RYR1) allows massive, uncontrolled calcium efflux in skeletal muscle, driving sustained contraction, heat production, and a hypermetabolic crisis.', 'Pre-Council', '🎓', true),
(8076, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What are among the earliest signs of malignant hyperthermia during anesthesia?', '["Unexplained tachycardia, rising end-tidal CO2 (hypercarbia), and masseter muscle rigidity", "Polyuria and hypoglycemia", "Hypothermia and slow, shallow breathing", "Bradycardia and hypotension"]'::jsonb, 0, 'Early MH is typically heralded by a sudden, otherwise unexplained rise in end-tidal CO2, tachycardia, and jaw/masseter rigidity, often preceding the marked temperature rise.', 'Pre-Council', '🎓', true),
(8077, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What is the definitive pharmacologic treatment for malignant hyperthermia?', '["Additional dose of succinylcholine", "IV dantrolene sodium", "More volatile anesthetic agent", "IV morphine"]'::jsonb, 1, 'Dantrolene inhibits calcium release from the sarcoplasmic reticulum via the ryanodine receptor, directly reversing the hypermetabolic muscle crisis and is the only specific antidote for MH.', 'Pre-Council', '🎓', true),
(8078, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Besides administering dantrolene, what are the immediate management steps for suspected malignant hyperthermia?', '["Continue the anesthetic at the same dose", "Apply warming blankets to raise the temperature further", "Discontinue the triggering agent, hyperventilate with 100% oxygen, actively cool the patient, and treat hyperkalemia/arrhythmias", "Administer more succinylcholine to relax the muscles"]'::jsonb, 2, 'MH management requires immediately stopping the trigger, maximizing oxygenation to counter the hypermetabolic state, active cooling, and correction of the resulting hyperkalemia and acidosis.', 'Pre-Council', '🎓', true),
(8079, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'According to the classic ''5 W''s'' mnemonic, what is the most common cause of post-operative fever occurring within the first 24 to 48 hours?', '["Deep vein thrombosis (Walking)", "Wound infection", "Urinary tract infection (Water)", "Atelectasis (Wind)"]'::jsonb, 3, 'Atelectasis, remembered as ''Wind'' in the classic mnemonic, typically causes fever in the first 24-48 hours after surgery, before UTI (day 3), wound infection (day 5), and DVT/PE (day 5+) become more likely causes.', 'Pre-Council', '🎓', true),
(8080, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'A patient develops fever with chills and rigors shortly after a blood transfusion is started post-operatively. What is the priority nursing action?', '["No action is needed if the temperature is below 38.5 degrees C", "Increase the transfusion rate to finish it quickly", "Give an antipyretic and continue the transfusion at the same rate", "Stop the transfusion immediately, keep the IV line open with normal saline, notify the physician, and send the blood/tubing for investigation"]'::jsonb, 3, 'A suspected transfusion reaction requires immediately stopping the transfusion while maintaining venous access, notifying the physician, and preserving the blood product/tubing for laboratory investigation.', 'Pre-Council', '🎓', true),
(8081, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What is a major cardiovascular/neurological consequence of severe hyperthermia in a post-operative patient?', '["Bradycardia and hypoglycemia only", "Increased metabolic rate, increased oxygen consumption, tachycardia, and potential seizures if severe", "No cardiovascular effect at all", "Decreased oxygen demand"]'::jsonb, 1, 'Severe hyperthermia sharply raises metabolic rate and oxygen demand, causes tachycardia to compensate, and can precipitate seizures or cellular injury if uncontrolled.', 'Pre-Council', '🎓', true),
(8082, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Which core temperature range is generally considered mild post-operative hypothermia?', '["38 to 40 degrees C", "34 to 36 degrees C", "36 to 38 degrees C", "Below 28 degrees C"]'::jsonb, 1, 'Mild hypothermia is typically defined as a core temperature of 34-36 degrees C; below 28 degrees C is considered severe/profound hypothermia.', 'Pre-Council', '🎓', true),
(8083, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Why are neonates and elderly patients at higher risk of post-operative hypothermia than healthy young adults?', '["They have impaired thermoregulatory mechanisms, reduced ability to shiver or vasoconstrict effectively, and (in neonates) a greater surface-area-to-mass ratio", "They have more subcutaneous fat for insulation than adults", "They are less exposed to the environment during surgery", "They have a higher basal metabolic rate than adults"]'::jsonb, 0, 'Reduced thermoregulatory reserve, blunted vasoconstriction/shivering responses, and higher relative heat loss surface area make both age extremes especially vulnerable to intraoperative and post-operative hypothermia.', 'Pre-Council', '🎓', true),
(8084, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'How does hypothermia contribute to increased post-operative bleeding risk?', '["It accelerates the clotting cascade", "It impairs platelet function and slows clotting enzyme (coagulation cascade) activity", "It only affects red blood cell production", "It has no effect on coagulation"]'::jsonb, 1, 'Coagulation enzymes and platelet aggregation are temperature-dependent and function poorly below normal body temperature, producing a clinically significant coagulopathy even with normal clotting factor levels.', 'Pre-Council', '🎓', true),
(8085, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What is the key difference between fever and hyperthermia?', '["Hyperthermia responds well to antipyretics while fever does not", "Fever is a regulated rise in the hypothalamic set point (e.g., due to pyrogens/infection), while hyperthermia is an unregulated rise in body temperature that exceeds the body''s ability to dissipate heat", "They are identical terms with no clinical distinction", "Fever always exceeds 41 degrees C while hyperthermia is always below 38 degrees C"]'::jsonb, 1, 'Fever results from a reset hypothalamic thermostat driven by pyrogens and typically responds to antipyretics, whereas hyperthermia (e.g., malignant hyperthermia, heat stroke) is a failure of heat dissipation that does not respond to antipyretics.', 'Pre-Council', '🎓', true),
(8086, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'A patient develops a temperature of 39.5 degrees C with tachycardia and jaw muscle rigidity shortly after induction with succinylcholine. What should the nurse suspect first?', '["Malignant hyperthermia, and the MH protocol should be initiated immediately", "The jaw rigidity means more succinylcholine is needed to relax the muscle", "A routine post-operative fever, so paracetamol alone should be given", "Nothing abnormal; reassess again in 4 hours"]'::jsonb, 0, 'Tachycardia, rising temperature, and masseter/jaw rigidity occurring soon after a triggering agent is a hallmark presentation of malignant hyperthermia and demands immediate recognition and protocol activation, not more succinylcholine.', 'Pre-Council', '🎓', true),
(8087, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What is the primary indication for induced (therapeutic) hypothermia, also called targeted temperature management (TTM), in critical care?', '["All post-operative patients routinely", "Comatose adult survivors of cardiac arrest, to improve neurological outcome", "Patients with active uncontrolled hemorrhage", "Patients presenting with hyperkalemia"]'::jsonb, 1, 'TTM is indicated for adults who remain comatose (not following commands) after return of spontaneous circulation from cardiac arrest, as it reduces secondary neurological injury.', 'Pre-Council', '🎓', true),
(8088, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What is the currently recommended target temperature range for targeted temperature management after cardiac arrest?', '["40 to 42 degrees C", "20 to 25 degrees C", "32 to 36 degrees C", "38 to 39 degrees C"]'::jsonb, 2, 'Guidelines recommend selecting and maintaining a constant target temperature between 32 and 36 degrees C for post-cardiac-arrest patients who remain comatose.', 'Pre-Council', '🎓', true),
(8089, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What is the generally recommended minimum duration of the maintenance phase for targeted temperature management?', '["7 full days", "5 minutes", "At least 24 hours at the target temperature", "6 hours only"]'::jsonb, 2, 'Current guidance recommends maintaining the selected target temperature continuously for at least 24 hours before controlled rewarming begins.', 'Pre-Council', '🎓', true),
(8090, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What is the main mechanism by which induced hypothermia provides neuroprotection after cardiac arrest?', '["It has no effect on brain metabolism", "It increases cerebral blood flow in an uncontrolled manner", "It necessarily raises intracranial pressure", "It reduces cerebral metabolic rate and oxygen demand and decreases free radical production and the inflammatory cascade, limiting secondary brain injury"]'::jsonb, 3, 'Lowering brain temperature slows metabolic demand and suppresses the biochemical cascades (excitotoxicity, free radicals, inflammation) that cause secondary neuronal injury after the ischemic insult of cardiac arrest.', 'Pre-Council', '🎓', true),
(8091, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Which is a common surface cooling method used to induce therapeutic hypothermia?', '["Deliberately raising the ambient room temperature", "Overhead heating lamps", "Warm blankets applied over the trunk", "Cooling blankets/pads with circulating cold water or air, plus ice packs to the groin, axilla, and neck"]'::jsonb, 3, 'Surface cooling devices (water- or air-circulating pads) combined with ice packs over major vessels are common, noninvasive methods of inducing and maintaining therapeutic hypothermia.', 'Pre-Council', '🎓', true),
(8092, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'How does intravascular (endovascular) cooling achieve targeted temperature management?', '["A rectal thermometer is inserted for monitoring only", "A peripheral IV cannula infuses room-temperature fluid continuously", "Oral ice chips are given repeatedly", "A central venous catheter with a heat-exchange balloon or coil circulates cold saline internally to cool the blood directly"]'::jsonb, 3, 'Intravascular cooling catheters placed in a large central vein use a closed-loop heat-exchange system to cool circulating blood directly and precisely, often achieving faster and more controlled cooling than surface methods.', 'Pre-Council', '🎓', true),
(8093, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What is the most common complication during induction of therapeutic hypothermia that requires prompt nursing/medical management?', '["Polyuria that requires no intervention", "Hyperthermia developing spontaneously", "A hypertensive crisis", "Shivering, which increases metabolic rate and can counteract the cooling effort"]'::jsonb, 3, 'Shivering is a physiological defense against cooling that raises oxygen consumption and heat production; it is typically managed with sedation, analgesia, and, if needed, neuromuscular blockade.', 'Pre-Council', '🎓', true),
(8094, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What electrolyte disturbance is commonly seen during the active cooling phase of targeted temperature management?', '["Hypokalemia, due to an intracellular potassium shift", "Hyperkalemia", "Hypercalcemia", "Hyponatremia only"]'::jsonb, 0, 'Cooling shifts potassium intracellularly, causing hypokalemia during induction; caution is needed with aggressive potassium replacement because rewarming later causes potassium to shift back out, risking rebound hyperkalemia.', 'Pre-Council', '🎓', true),
(8095, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Why must rewarming after therapeutic hypothermia be performed slowly and in a controlled manner (e.g., 0.25 to 0.5 degrees C per hour)?', '["Rapid rewarming carries no physiological risk", "Rapid rewarming improves neurological outcome", "Slow rewarming is only a matter of patient comfort", "Rapid rewarming can cause rebound hyperkalemia, vasodilation, hypotension, and increased intracranial pressure"]'::jsonb, 3, 'As the body rewarms, potassium shifts back extracellularly and peripheral vasodilation occurs; doing this too quickly can precipitate dangerous hyperkalemia and hemodynamic instability, so controlled, gradual rewarming is required.', 'Pre-Council', '🎓', true),
(8096, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What cardiac risk is specifically associated with induced hypothermia, particularly at lower target temperatures?', '["Bradycardia and an increased risk of arrhythmias, including ventricular fibrillation, especially below 30 degrees C", "Tachycardia only, with no arrhythmia risk", "A hypertensive crisis", "No cardiac effects at all"]'::jsonb, 0, 'Hypothermia slows the sinoatrial node and conduction system, commonly causing bradycardia, and increases myocardial irritability, raising the risk of arrhythmias including VF at very low temperatures.', 'Pre-Council', '🎓', true),
(8097, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Which condition is a relative contraindication to initiating therapeutic hypothermia after cardiac arrest?', '["The patient remaining unconscious/comatose", "Return of spontaneous circulation", "Refractory severe bleeding/coagulopathy or hemodynamic instability that precludes safe cooling", "A shockable rhythm (VF/pVT) during the arrest"]'::jsonb, 2, 'Because hypothermia impairs coagulation, active severe bleeding or uncontrolled hemodynamic instability are relative contraindications that must be weighed against the neuroprotective benefit.', 'Pre-Council', '🎓', true),
(8098, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What is the nursing monitoring priority during induced hypothermia therapy?', '["Hourly oral temperature checks only", "Skin temperature alone is equivalent to core temperature", "Cardiac rhythm monitoring is unnecessary during TTM", "Continuous core temperature monitoring (esophageal, bladder, or rectal probe), cardiac rhythm, electrolytes, coagulation status, and neurological status"]'::jsonb, 3, 'TTM requires continuous core (not skin or oral) temperature monitoring along with close surveillance of rhythm, electrolytes, and coagulation because cooling affects all of these systems.', 'Pre-Council', '🎓', true),
(8099, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Which post-cardiac-arrest patient is generally NOT a candidate for targeted temperature management?', '["A patient who remains comatose after a PEA arrest", "A patient who remains comatose after a VF arrest", "A patient who remains comatose after an asystolic arrest", "A patient who regains consciousness and is able to follow commands after return of spontaneous circulation"]'::jsonb, 3, 'TTM is intended for patients who remain comatose after ROSC; a patient who awakens and follows commands does not require induced hypothermia.', 'Pre-Council', '🎓', true),
(8100, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Why does hyperglycemia commonly occur during therapeutic hypothermia?', '["Cooling increases insulin sensitivity", "Cooling induces insulin resistance and decreases insulin secretion", "Hypoglycemia is the typical finding instead", "Cooling has no effect on glucose metabolism"]'::jsonb, 1, 'Hypothermia reduces insulin secretion from the pancreas and increases peripheral insulin resistance, commonly causing hyperglycemia that requires glucose monitoring and titrated insulin therapy.', 'Pre-Council', '🎓', true),
(8101, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Why does induced hypothermia increase the risk of infection in critically ill patients?', '["It improves immune function, preventing all infections", "Hypothermia is protective against every type of infection", "It carries no infection risk whatsoever", "It impairs the immune response and reduces the ability to clear pathogens"]'::jsonb, 3, 'Cooling suppresses leukocyte function and the inflammatory response, which can mask signs of infection and increase susceptibility to pneumonia and other nosocomial infections during and after TTM.', 'Pre-Council', '🎓', true),
(8102, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Which isotonic crystalloid solutions are commonly used for routine post-operative fluid resuscitation?', '["Sterile water for injection", "3% hypertonic saline routinely", "5% dextrose in water alone", "0.9% normal saline or Ringer''s lactate"]'::jsonb, 3, '0.9% normal saline and Ringer''s lactate are isotonic crystalloids that expand the extracellular fluid compartment and are standard first-line choices for post-operative volume replacement.', 'Pre-Council', '🎓', true),
(8103, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What metabolic complication can result from administering large volumes of 0.9% normal saline?', '["Metabolic alkalosis in all cases", "Hyperchloremic metabolic acidosis", "Respiratory alkalosis", "Hypochloremia"]'::jsonb, 1, 'Normal saline has a high chloride content relative to plasma; large-volume infusion can cause a dilutional, hyperchloremic non-anion-gap metabolic acidosis.', 'Pre-Council', '🎓', true),
(8104, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'How do colloid solutions (e.g., albumin, hydroxyethyl starch) differ functionally from crystalloids?', '["They never cause allergic or anaphylactoid reactions", "They contain large molecules that stay in the intravascular space longer, expanding plasma volume more effectively per volume infused", "They freely and immediately cross into the interstitial space", "They are always cheaper than crystalloid solutions"]'::jsonb, 1, 'The large molecular weight of colloids keeps them largely within the vascular compartment, producing a greater and more sustained intravascular volume expansion compared with an equal volume of crystalloid.', 'Pre-Council', '🎓', true),
(8105, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Which findings should alert the nurse to fluid volume overload during IV fluid therapy?', '["Decreased urine specific gravity alone", "Dry mucous membranes", "Decreased blood pressure with flat neck veins", "Crackles on lung auscultation, dyspnea, peripheral edema, elevated jugular venous pressure, and rapid weight gain"]'::jsonb, 3, 'Pulmonary crackles, dyspnea, edema, distended neck veins, and rapid weight gain are classic signs of circulatory fluid overload requiring rate reduction and physician notification.', 'Pre-Council', '🎓', true),
(8106, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Why is an infusion pump preferred over a gravity drip for administering vasoactive medications such as norepinephrine in the ICU?', '["It allows unlimited rate changes without programming safeguards", "It removes the need for any line monitoring", "It delivers a precise, controlled, and consistent flow rate, preventing dangerous rate fluctuations", "It is cheaper than a gravity infusion set"]'::jsonb, 2, 'Vasoactive drugs have a narrow therapeutic window; an infusion pump provides accurate, steady, milliliter-per-hour dosing that gravity drips cannot reliably guarantee, preventing dangerous swings in blood pressure.', 'Pre-Council', '🎓', true),
(8107, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What safety feature on most modern infusion pumps helps prevent an uncontrolled free-flow bolus of medication when the tubing is removed from the device?', '["A manual roller clamp only, with no automatic mechanism", "A larger tubing diameter", "Modern pumps have no free-flow protection", "An anti-free-flow clamp/mechanism that automatically closes the tubing"]'::jsonb, 3, 'Anti-free-flow devices automatically occlude the tubing when it is removed from the pump, preventing gravity from causing an unintended rapid bolus of the infusate.', 'Pre-Council', '🎓', true),
(8108, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What is the most important nursing action before starting therapy on any infusion pump?', '["Verify the correct medication, concentration, and rate against the prescription, confirm the program settings, and prime the line to avoid air embolism", "Accept the pump''s default settings without checking", "Simply plug in the pump and press start", "Skip verification since the pump is automated"]'::jsonb, 0, 'Independent double-checking of the drug, concentration, and programmed rate against the order, along with proper priming, is essential to prevent dosing errors and air embolism before any infusion begins.', 'Pre-Council', '🎓', true),
(8109, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'How is the risk of air embolism during IV fluid or infusion pump therapy minimized?', '["By priming the tubing to remove air bubbles and using the pump''s air-in-line alarm/detector", "By deliberately leaving some air in the line", "By using the largest gauge cannula only", "By inverting the fluid bag during infusion"]'::jsonb, 0, 'Careful priming to expel air combined with the pump''s built-in air-in-line detection and alarm are the key safeguards against introducing air into the venous system.', 'Pre-Council', '🎓', true),
(8110, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What does an ''occlusion'' alarm on an infusion pump most likely indicate?', '["The infusion has completed successfully", "The correct rate is being delivered without any problem", "A blockage in the line (e.g., kinked tubing, clotted IV cannula, or a closed clamp) preventing flow", "The pump battery is low"]'::jsonb, 2, 'An occlusion alarm signals resistance to flow somewhere along the line, prompting the nurse to check for kinks, closed clamps, positional issues, or a clotted cannula before resuming the infusion.', 'Pre-Council', '🎓', true),
(8111, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What is the typical initial fluid resuscitation approach for a patient in hypovolemic shock?', '["A rapid bolus of isotonic crystalloid solution while closely monitoring the hemodynamic response", "Withholding fluids until blood pressure normalizes spontaneously", "Administering diuretics to reduce circulating volume", "A slow maintenance-rate infusion of hypotonic fluid"]'::jsonb, 0, 'Hypovolemic shock is treated with prompt isotonic crystalloid boluses to restore intravascular volume, with ongoing reassessment of blood pressure, heart rate, and perfusion to guide further therapy.', 'Pre-Council', '🎓', true),
(8112, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Which fluid provides free water for maintenance therapy but must be used cautiously because large volumes can cause hyponatremia and cerebral edema?', '["5% dextrose in water (D5W)", "0.9% normal saline", "3% hypertonic saline", "Ringer''s lactate"]'::jsonb, 0, 'D5W is metabolized to free water once the dextrose is used, so large volumes dilute serum sodium and can precipitate hyponatremia and cerebral edema, particularly in neurosurgical or head-injury patients.', 'Pre-Council', '🎓', true),
(8113, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Why should Ringer''s lactate be used with caution in patients with severe liver failure?', '["It cannot be infused through a peripheral line", "It contains no electrolytes at all", "Impaired hepatic lactate metabolism can lead to lactate accumulation", "It is a hypertonic solution unsuitable for any patient"]'::jsonb, 2, 'The lactate in Ringer''s lactate is normally converted to bicarbonate by the liver; in severe hepatic failure this conversion is impaired, so lactate can accumulate and confound assessment of lactic acidosis.', 'Pre-Council', '🎓', true),
(8114, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'In burn patients, formulas such as the Parkland formula are used to guide:', '["Exclusive use of hypertonic saline", "Crystalloid (usually Ringer''s lactate) volume administration over the first 24 hours, based on total body surface area burned and body weight", "Whole blood transfusion volume only", "Exclusive use of 5% dextrose"]'::jsonb, 1, 'The Parkland formula calculates the estimated crystalloid volume (typically Ringer''s lactate) needed in the first 24 hours after a major burn, based on percentage TBSA burned and patient weight.', 'Pre-Council', '🎓', true),
(8115, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What is the main purpose of a smart infusion pump''s dose-error reduction software (drug library)?', '["To prevent electrical failure of the equipment", "To prevent infection at the IV insertion site", "To prevent patient movement during the infusion", "To help prevent programming errors that could lead to over- or under-dosing of high-alert medications"]'::jsonb, 3, 'Drug libraries with pre-set dosing limits alert the nurse when a programmed rate or dose falls outside safe parameters for a specific high-alert medication, reducing the risk of serious programming errors.', 'Pre-Council', '🎓', true),
(8116, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'An infusion pump alarms ''downstream occlusion'' while infusing post-operative IV fluids. What should the nurse do first?', '["Increase the pump rate to overcome the occlusion", "Silence the alarm permanently and ignore it", "Immediately disconnect and discard the fluid bag", "Check the tubing from the pump to the patient for kinks, closed clamps, or positional issues at the IV site"]'::jsonb, 3, 'A downstream occlusion alarm points to a blockage between the pump and the patient, so the nurse should systematically inspect the tubing and IV site before resuming or troubleshooting further.', 'Pre-Council', '🎓', true),
(8117, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'How is cardiac arrest best defined?', '["Sudden cessation of effective cardiac mechanical activity/output, resulting in absence of circulation", "A transient loss of consciousness that resolves spontaneously without intervention", "A slow, gradual decline in heart rate over several hours", "Any single episode of chest pain"]'::jsonb, 0, 'Cardiac arrest is the abrupt loss of effective heart pumping function, causing circulatory collapse and loss of consciousness within seconds unless immediately reversed.', 'Pre-Council', '🎓', true),
(8118, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Which two rhythms are classified as ''shockable'' in cardiac arrest?', '["Sinus bradycardia and first-degree AV block", "Asystole and pulseless electrical activity (PEA)", "Ventricular fibrillation (VF) and pulseless ventricular tachycardia (pVT)", "Atrial fibrillation and atrial flutter with a pulse"]'::jsonb, 2, 'VF and pulseless VT are chaotic or rapid ventricular rhythms that can be terminated by defibrillation, unlike organized-but-ineffective or absent electrical rhythms.', 'Pre-Council', '🎓', true),
(8119, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Which rhythms are classified as ''non-shockable'' in cardiac arrest?', '["Ventricular flutter", "Asystole and pulseless electrical activity (PEA)", "VF and pulseless VT", "Torsades de pointes"]'::jsonb, 1, 'Asystole (no electrical activity) and PEA (organized electrical activity without a pulse) do not respond to defibrillation; management instead focuses on high-quality CPR, epinephrine, and treating reversible causes.', 'Pre-Council', '🎓', true),
(8120, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What mnemonic is commonly used to remember the reversible causes of cardiac arrest?', '["RICE", "ABCDE only", "SOAP", "The ''Hs and Ts'' (hypovolemia, hypoxia, hydrogen ion/acidosis, hypo/hyperkalemia, hypothermia, tension pneumothorax, tamponade, toxins, thrombosis)"]'::jsonb, 3, 'The Hs and Ts framework prompts responders to systematically consider and treat reversible metabolic, mechanical, and toxic causes of cardiac arrest during resuscitation.', 'Pre-Council', '🎓', true),
(8121, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'How is cardiac arrest diagnosed at the bedside in an unresponsive patient?', '["A single low blood pressure reading alone", "Absence of a palpable central pulse (e.g., carotid), checked for no more than 10 seconds, along with absent or abnormal breathing", "The patient complaining of chest pain", "Presence of a weak radial pulse"]'::jsonb, 1, 'Clinical diagnosis relies on unresponsiveness plus the absence of a central pulse (checked briefly, within 10 seconds) and absent or agonal breathing; delaying compressions to search longer for a pulse is discouraged.', 'Pre-Council', '🎓', true),
(8122, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What is the pathophysiologic consequence if circulation is not restored promptly after cardiac arrest?', '["Cessation of tissue perfusion leads to anaerobic metabolism and lactic acidosis, with irreversible brain injury typically beginning within about 4 to 6 minutes of no flow", "Tissues continue normal aerobic metabolism indefinitely", "Only skin tissue is affected by the loss of circulation", "There is no significant metabolic consequence"]'::jsonb, 0, 'Without perfusion, cells switch to anaerobic metabolism, producing lactic acid and rapidly depleting ATP; the brain is especially vulnerable, with irreversible injury beginning within minutes of no blood flow.', 'Pre-Council', '🎓', true),
(8123, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What is a common cardiac cause of sudden cardiac arrest in adults?', '["A simple febrile illness", "Chronic stable angina without infarction", "Acute myocardial infarction resulting in a lethal arrhythmia such as VF", "Mild dehydration"]'::jsonb, 2, 'Acute coronary occlusion can trigger fatal ventricular arrhythmias, making acute MI one of the most common precipitating causes of sudden cardiac arrest in adults.', 'Pre-Council', '🎓', true),
(8124, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Which signs/symptoms typically accompany the onset of cardiac arrest?', '["Gradual weight loss over several months", "Sudden collapse, unresponsiveness, absent or agonal breathing, absent pulse, and cyanosis", "Mild intermittent headache", "Chronic cough only"]'::jsonb, 1, 'Cardiac arrest presents abruptly with loss of consciousness, absence of a pulse, and absent or gasping (agonal) respirations, often with cyanosis from the sudden loss of circulation and oxygenation.', 'Pre-Council', '🎓', true),
(8125, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What is the priority first action upon discovering an unresponsive, non-breathing patient in the ICU?', '["Leave the patient to fetch a full medical history first", "Call for help/activate the emergency response system and begin chest compressions promptly once absence of a pulse is confirmed within 10 seconds", "Start giving the patient oral fluids", "Wait for the physician before doing anything"]'::jsonb, 1, 'Rapid activation of the emergency response and immediate initiation of high-quality CPR are the first priorities, since delay directly worsens survival odds.', 'Pre-Council', '🎓', true),
(8126, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What does the ''chain of survival'' for in-hospital cardiac arrest include, in sequence?', '["Obtaining informed consent before any treatment is given", "Early recognition and activation of the emergency response, early high-quality CPR, early defibrillation, effective advanced life support, and integrated post-cardiac-arrest care", "Transferring the patient to another facility before starting CPR", "Sedating the patient first, then assessing the rhythm"]'::jsonb, 1, 'The chain of survival links the sequential steps proven to improve outcomes after cardiac arrest, from rapid recognition through coordinated post-arrest care.', 'Pre-Council', '🎓', true),
(8127, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Which first-line drug is administered during ACLS for cardiac arrest, regardless of the underlying rhythm, to improve coronary and cerebral perfusion pressure?', '["Atropine", "Insulin", "Epinephrine (adrenaline)", "Furosemide"]'::jsonb, 2, 'Epinephrine''s alpha-adrenergic vasoconstrictive effect raises aortic diastolic pressure, improving coronary and cerebral perfusion pressure during CPR, and is given in all cardiac arrest algorithms.', 'Pre-Council', '🎓', true),
(8128, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What is the standard adult IV/IO dose of epinephrine during cardiac arrest, repeated every 3 to 5 minutes?', '["0.1 mg", "10 mg", "1 mg", "100 mcg given only once"]'::jsonb, 2, 'The standard ACLS dose is 1 mg IV/IO of epinephrine (1:10,000 concentration) every 3-5 minutes throughout the resuscitation.', 'Pre-Council', '🎓', true),
(8129, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Which antiarrhythmic is used as the preferred agent for refractory VF or pulseless VT after defibrillation and epinephrine have failed?', '["Verapamil", "Metoprolol", "Digoxin", "Amiodarone (with lidocaine as an alternative)"]'::jsonb, 3, 'Amiodarone (or lidocaine if amiodarone is unavailable) is recommended for shock-refractory VF/pulseless VT to help stabilize the myocardium and improve the chance of successful defibrillation.', 'Pre-Council', '🎓', true),
(8130, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Is defibrillation indicated for PEA or asystole?', '["Yes, followed routinely by synchronized cardioversion", "No; these are non-shockable rhythms, and management instead focuses on high-quality CPR, epinephrine, and treating reversible causes", "Epinephrine is contraindicated in these rhythms", "Yes, defibrillation is indicated immediately as the first step"]'::jsonb, 1, 'PEA and asystole lack the disorganized or rapid ventricular electrical activity that a shock can terminate, so defibrillation has no role; the focus shifts to CPR quality, epinephrine, and correcting reversible causes.', 'Pre-Council', '🎓', true),
(8131, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What airway-related precaution is important during cardiac arrest management?', '["Delay any airway management until after 30 minutes of compressions", "Hyperventilate the patient as much as possible for maximal oxygenation", "Ensure effective airway management while avoiding excessive ventilation (hyperventilation), which can increase intrathoracic pressure and reduce venous return/coronary perfusion", "Give continuous ventilations with no defined ratio before an advanced airway is placed"]'::jsonb, 2, 'Excessive ventilation raises intrathoracic pressure, impeding venous return and reducing coronary perfusion during compressions, so rescuers should avoid over-ventilating and follow recommended compression-ventilation ratios.', 'Pre-Council', '🎓', true),
(8132, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What does post-cardiac-arrest care after return of spontaneous circulation (ROSC) typically include?', '["Discharging the patient home once a pulse returns", "No further intervention is needed once ROSC is achieved", "Targeted temperature management, hemodynamic optimization, a 12-lead ECG, treatment of the underlying cause, and neurological assessment", "Discontinuing all monitoring immediately"]'::jsonb, 2, 'Structured post-arrest care addresses the underlying cause, optimizes oxygenation/hemodynamics, considers TTM for comatose patients, and includes ongoing neurological assessment to improve survival and recovery.', 'Pre-Council', '🎓', true),
(8133, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Why is capnography (end-tidal CO2) useful during cardiac arrest resuscitation?', '["It has no clinical use during resuscitation", "A sudden sustained rise in ETCO2 can indicate return of spontaneous circulation, and it also helps assess CPR quality and confirm correct endotracheal tube placement", "It completely replaces the need for pulse checks", "It directly measures blood glucose"]'::jsonb, 1, 'ETCO2 reflects both pulmonary blood flow (a marker of compression effectiveness) and, when it suddenly rises, often signals ROSC; it also confirms tube placement in the trachea rather than the esophagus.', 'Pre-Council', '🎓', true),
(8134, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What should patient education after surviving a cardiac arrest (secondary prevention) emphasize?', '["Medication adherence, risk factor modification (e.g., smoking cessation, diet, exercise), recognizing warning symptoms, and follow-up including possible ICD evaluation", "Avoiding all physical activity permanently", "No follow-up is needed once the patient is discharged", "Discontinuing all cardiac medications once feeling well"]'::jsonb, 0, 'Survivors need structured secondary prevention education, including medication compliance, lifestyle modification, symptom recognition, and cardiology follow-up, which may include evaluation for an implantable cardioverter-defibrillator.', 'Pre-Council', '🎓', true),
(8135, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'How is a tension pneumothorax causing PEA arrest managed?', '["Defibrillation", "IV fluids alone", "Atropine administration", "Immediate needle decompression followed by chest tube insertion"]'::jsonb, 3, 'Tension pneumothorax obstructs venous return by compressing the great vessels; immediate needle decompression relieves the pressure and is essential to restore circulation, as fluids or drugs alone will not correct the mechanical cause.', 'Pre-Council', '🎓', true),
(8136, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'How is cardiac tamponade causing PEA arrest managed?', '["Emergency pericardiocentesis to relieve pressure on the heart", "Diuretic administration", "High-dose epinephrine alone, without pericardiocentesis", "Chest compressions alone, without any mechanical intervention"]'::jsonb, 0, 'Tamponade physically restricts ventricular filling; pericardiocentesis to drain the pericardial fluid is the definitive treatment needed to restore effective cardiac output.', 'Pre-Council', '🎓', true),
(8137, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Which ICU risk factors should nurses monitor closely because they predispose to cardiac arrest?', '["Adequate oxygenation", "A stable sinus rhythm", "Normal serum potassium levels", "Electrolyte imbalances (e.g., hyperkalemia, hypokalemia), hypoxia, and arrhythmias"]'::jsonb, 3, 'Electrolyte derangements, hypoxia, and arrhythmias are common, often reversible precursors to in-hospital cardiac arrest, so vigilant monitoring allows early correction before arrest occurs.', 'Pre-Council', '🎓', true),
(8138, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Which ECG changes suggest a hyperkalemia-induced risk of cardiac arrest?', '["A shortened PR interval only", "U waves with flattened T waves", "A completely normal sinus rhythm", "Peaked T waves and widened QRS complexes, potentially progressing to a sine-wave pattern"]'::jsonb, 3, 'Hyperkalemia progressively alters cardiac conduction, producing peaked T waves, PR/QRS widening, and eventually a sine-wave pattern that can degenerate into VF or asystole; U waves with flattened T waves instead suggest hypokalemia.', 'Pre-Council', '🎓', true),
(8139, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'How does sudden cardiac death differ from cardiac arrest?', '["Cardiac arrest always results in permanent death regardless of intervention", "Sudden cardiac death occurs only in healthy young athletes", "Sudden cardiac death refers to death resulting from an unexpected cardiac arrest without successful resuscitation, whereas cardiac arrest may be reversed with prompt intervention", "They are completely unrelated clinical conditions"]'::jsonb, 2, 'Cardiac arrest is the clinical event of circulatory collapse, which is potentially reversible with timely CPR and defibrillation; sudden cardiac death is the fatal outcome when resuscitation is unsuccessful or unavailable.', 'Pre-Council', '🎓', true),
(8140, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'A patient with a recent long-bone fracture and prolonged immobility suddenly collapses with hypoxia and cardiac arrest. Which reversible cause should be suspected?', '["Pulmonary embolism (thrombosis)", "Hyperthermia", "Tension pneumothorax", "Hypoglycemia"]'::jsonb, 0, 'Immobility and long-bone fracture are major risk factors for venous thromboembolism; sudden collapse with hypoxia in this context strongly suggests a massive pulmonary embolism causing obstructive/PEA arrest.', 'Pre-Council', '🎓', true),
(8141, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'In a cardiac arrest caused by tricyclic antidepressant overdose (a ''toxin'' cause), what should be added to standard ACLS management?', '["Withhold all resuscitation efforts", "Administer the specific antidote/treatment, such as sodium bicarbonate for TCA toxicity, alongside standard resuscitation", "Give more of the causative toxin", "Ignore the toxin history and treat only the rhythm"]'::jsonb, 1, 'When a reversible toxic cause is identified, targeted therapy (e.g., sodium bicarbonate for TCA-induced cardiotoxicity) should be given in addition to standard ACLS to address the underlying cause.', 'Pre-Council', '🎓', true),
(8142, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What precaution should guide administration of high-dose vasopressors via peripheral IV during cardiac arrest?', '["Avoid IV access entirely and use only intramuscular injections", "Infuse as slowly as possible over one hour", "Use the largest, most proximal accessible vein and flush after each dose so the drug reaches central circulation", "Mix all resuscitation drugs together in a single syringe"]'::jsonb, 2, 'During arrest, peripheral perfusion is poor, so drugs should be given through the largest, most proximal vein available and followed by a fluid flush and limb elevation to help them reach the central circulation faster.', 'Pre-Council', '🎓', true),
(8143, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Which bedside tools help diagnose the underlying cause of cardiac arrest during or immediately after resuscitation?', '["A skin biopsy", "Waiting for laboratory results before initiating any resuscitation", "A full-body CT scan performed before starting CPR", "Point-of-care ECG/rhythm strip, arterial blood gas, electrolytes, and bedside echocardiography"]'::jsonb, 3, 'Rapid bedside diagnostics such as rhythm analysis, ABG, electrolytes, and point-of-care echocardiography can be obtained without interrupting resuscitation and help identify reversible causes.', 'Pre-Council', '🎓', true),
(8144, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What is an appropriate institutional practice regarding family presence during in-hospital cardiac arrest resuscitation?', '["If policy allows, a support person may be offered the option to be present, with a dedicated staff member assigned to explain the process without interfering with the resuscitation team", "Family presence is mandatory at every code", "Family members should always perform the chest compressions", "Family must never be informed until after the event is over"]'::jsonb, 0, 'Where institutional policy supports it, family-witnessed resuscitation can be offered with a dedicated support person managing the family member, but it must not disrupt the resuscitation team''s work and remains optional, not mandatory.', 'Pre-Council', '🎓', true),
(8145, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What is the current recommended adult compression-to-ventilation ratio for a single rescuer without an advanced airway?', '["30:2", "3:1", "5:1", "15:2"]'::jsonb, 0, 'For adult CPR by a single rescuer without an advanced airway, 30 chest compressions are given for every 2 rescue breaths.', 'Pre-Council', '🎓', true),
(8146, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What is the recommended chest compression rate during adult CPR?', '["100 to 120 compressions per minute", "40 to 60 per minute", "60 to 80 per minute", "140 to 160 per minute"]'::jsonb, 0, 'Guidelines recommend a compression rate of 100-120 per minute; rates outside this range are associated with reduced CPR effectiveness.', 'Pre-Council', '🎓', true),
(8147, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What is the recommended chest compression depth for an average adult during CPR?', '["8 to 10 cm", "About 1 cm", "At least 5 cm, but not exceeding 6 cm", "2 to 3 cm"]'::jsonb, 2, 'Adequate compression depth of at least 5 cm (but not more than 6 cm to avoid injury) is needed to generate sufficient blood flow during CPR.', 'Pre-Council', '🎓', true),
(8148, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Why is allowing full chest recoil between compressions important during CPR?', '["It has no physiological importance", "It only matters for reducing the risk of rib fracture", "It allows adequate venous return to the heart, improving preload and the effectiveness of the next compression", "It wastes valuable time and should be minimized"]'::jsonb, 2, 'Incomplete recoil prevents the heart from refilling adequately between compressions, reducing cardiac output generated by subsequent compressions, so full recoil is a key component of high-quality CPR.', 'Pre-Council', '🎓', true),
(8149, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Why is minimizing interruptions in chest compressions emphasized during CPR?', '["Interruptions have no measurable impact on outcome", "Interruptions actually improve blood flow", "Pauses are required every 10 seconds for rescuer safety", "Even brief pauses cause a rapid decline in coronary perfusion pressure, reducing the effectiveness of subsequent compressions"]'::jsonb, 3, 'Coronary perfusion pressure built up during compressions falls quickly once compressions stop, so minimizing hands-off time maximizes the perfusion achieved during CPR.', 'Pre-Council', '🎓', true),
(8150, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Once an advanced airway (e.g., endotracheal tube) is in place during CPR, how should compressions and ventilations be delivered?', '["Compressions must stop completely for every breath", "The 30:2 cycle must still be strictly followed", "Ventilation is no longer needed once intubated", "Continuous compressions at 100-120/min with asynchronous ventilations at about one breath every 6 seconds (roughly 10/min)"]'::jsonb, 3, 'With an advanced airway in place, compressions are delivered continuously without pausing for breaths, while ventilations are given asynchronously at a fixed rate of about 10 per minute.', 'Pre-Council', '🎓', true),
(8151, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What musculoskeletal complication is common with chest compressions during CPR?', '["Skull fracture", "Pelvic fracture", "Rib fractures and/or sternal fracture", "Femur fracture"]'::jsonb, 2, 'The repeated force applied over the sternum during compressions frequently causes rib or sternal fractures, particularly in older or osteoporotic patients; this is an accepted risk given the life-saving priority of compressions.', 'Pre-Council', '🎓', true),
(8152, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Which visceral organ injury can occur from chest compressions, especially with improper hand placement?', '["Kidney transplant rejection", "Liver or spleen laceration", "Appendix rupture", "Gallbladder removal"]'::jsonb, 1, 'Compressions placed too low, especially over the xiphoid process, can drive it into the liver, risking laceration and intra-abdominal hemorrhage.', 'Pre-Council', '🎓', true),
(8153, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What is the correct hand placement for adult chest compressions?', '["The lower half of the sternum, using the heel of one hand with the other hand on top and fingers interlocked and lifted off the chest wall", "The upper sternum near the clavicles", "Directly over the xiphoid process", "Over the left nipple only"]'::jsonb, 0, 'Compressing the lower half of the sternum generates effective forward flow while avoiding the xiphoid process, which if compressed can fracture and lacerate the liver.', 'Pre-Council', '🎓', true),
(8154, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Which pulmonary complication can result from chest compressions during CPR?', '["Asthma", "Pulmonary fibrosis", "Pneumothorax or hemothorax from a fractured rib puncturing the pleura or lung", "Chronic bronchitis"]'::jsonb, 2, 'A rib fractured during compressions can puncture the underlying pleura or lung tissue, causing a pneumothorax or hemothorax that may require chest tube drainage.', 'Pre-Council', '🎓', true),
(8155, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What is a risk of gastric insufflation caused by overly forceful bag-mask ventilation during CPR?', '["No clinical consequence", "Decreased risk of vomiting", "Regurgitation and aspiration of gastric contents into the lungs", "Improved oxygenation of the patient"]'::jsonb, 2, 'Air forced into the stomach distends it and raises intragastric pressure, promoting regurgitation of gastric contents, which can then be aspirated into the airway.', 'Pre-Council', '🎓', true),
(8156, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'How should rescue breaths be delivered during bag-mask ventilation to minimize gastric insufflation?', '["Use the maximum tidal volume with every breath", "Compress the bag with both hands using full force", "Deliver breaths as forcefully and quickly as possible", "Give each breath over about one second, just enough to produce visible chest rise, avoiding excessive volume or force"]'::jsonb, 3, 'Slow, moderate-volume breaths that produce visible chest rise minimize the pressure delivered to the esophagus and stomach, reducing the risk of gastric insufflation and subsequent aspiration.', 'Pre-Council', '🎓', true),
(8157, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'How can the quality of CPR be objectively monitored during resuscitation?', '["By checking the time of day", "Using end-tidal CO2 (capnography) and arterial diastolic pressure if an invasive line is present", "By the heart rate of the rescuer performing compressions", "By the patient''s self-report of comfort"]'::jsonb, 1, 'ETCO2 and, when available, arterial diastolic pressure correlate with the effectiveness of chest compressions and cardiac output generated during CPR, offering objective feedback on CPR quality.', 'Pre-Council', '🎓', true),
(8158, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'How often should rescuers performing chest compressions switch during ongoing CPR?', '["Every 15 minutes", "Every 30 seconds", "Rescuers should never switch during an arrest", "About every 2 minutes, to prevent fatigue and maintain compression quality"]'::jsonb, 3, 'Compressor fatigue reduces compression depth and rate within about 2 minutes, so rotating rescuers at this interval, with minimal interruption, helps sustain high-quality compressions throughout the resuscitation.', 'Pre-Council', '🎓', true),
(8159, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Which neurological complication can result from prolonged or ineffective CPR?', '["No neurological risk regardless of CPR duration or quality", "Hypoxic-ischemic brain injury due to inadequate cerebral perfusion", "Improved cognition after the arrest", "Enhanced memory function following resuscitation"]'::jsonb, 1, 'If cerebral perfusion during CPR is inadequate or resuscitation is prolonged, the brain can sustain hypoxic-ischemic injury, which is a major determinant of a survivor''s neurological outcome.', 'Pre-Council', '🎓', true),
(8160, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What important modification should be made when performing CPR on a pregnant patient in later pregnancy?', '["Manual left uterine displacement to relieve aortocaval compression and improve venous return", "Place the patient in the prone position", "Avoid performing chest compressions entirely", "Compress the abdomen instead of the chest"]'::jsonb, 0, 'In later pregnancy, the gravid uterus can compress the aorta and inferior vena cava when the patient is supine; manual left uterine displacement relieves this compression and improves the effectiveness of compressions.', 'Pre-Council', '🎓', true),
(8161, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'How does a documented ''Do Not Resuscitate'' (DNR) order affect CPR practice?', '["It instructs healthcare providers to withhold CPR/resuscitative efforts according to the patient''s or authorized surrogate''s documented wishes", "It applies automatically to every patient over 65 years old", "It requires CPR to be performed more aggressively", "It has no legal or clinical significance"]'::jsonb, 0, 'A valid DNR order is a legal and ethical directive to withhold CPR in the event of cardiac arrest, reflecting the patient''s or their authorized surrogate''s expressed wishes, and must be honored by the care team.', 'Pre-Council', '🎓', true),
(8162, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Which components define ''high-quality'' CPR according to current resuscitation guidelines?', '["Adequate rate and depth, full chest recoil, minimizing interruptions, and avoiding excessive ventilation", "Performing compressions only when convenient", "Prioritizing ventilation over compressions at all times", "Keeping compression depth under 2 cm to avoid injury"]'::jsonb, 0, 'High-quality CPR is defined by correct rate, adequate depth, complete recoil, minimal interruptions, and avoidance of excessive ventilation, all of which have been shown to improve outcomes.', 'Pre-Council', '🎓', true),
(8163, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Why are elderly or osteoporotic patients at increased risk of a specific CPR complication compared with younger patients?', '["They have a higher risk of rib and sternal fractures due to reduced bone density", "They have an increased risk of skin burns only", "They have a lower risk of any fracture during compressions", "There is no difference in complication risk compared with younger patients"]'::jsonb, 0, 'Reduced bone mineral density in elderly and osteoporotic patients makes the ribs and sternum more susceptible to fracture from the forceful, repeated compressions required for effective CPR.', 'Pre-Council', '🎓', true),
(8164, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'If a patient vomits during ongoing CPR, what is the immediate nursing action?', '["Give the patient more IV fluids immediately", "Turn the patient''s head to the side (if no spinal injury is suspected) or use suction to clear the airway, then resume CPR promptly", "Continue compressions without addressing the airway", "Stop CPR permanently"]'::jsonb, 1, 'Airway clearance takes brief priority to prevent aspiration, but compressions should be resumed as quickly as possible once the airway is cleared, since interruptions reduce CPR effectiveness.', 'Pre-Council', '🎓', true),
(8165, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Which cardiac complication can occur as a direct result of external chest compressions?', '["Myocardial contusion or other direct cardiac injury", "Myocardial hypertrophy", "Valve replacement failure", "Chronic pericarditis"]'::jsonb, 0, 'The repetitive forceful compressions applied to the chest wall during CPR can, in rare cases, directly bruise or injure the myocardium, a recognized but acceptable risk given the alternative of no resuscitation.', 'Pre-Council', '🎓', true),
(8166, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What is true about the use of mechanical chest compression devices in resuscitation?', '["They eliminate the need for defibrillation entirely", "They may be used in select settings, such as prolonged resuscitation or transport, to provide consistent compressions, but require proper training for correct placement", "They are never used in modern resuscitation practice", "They should always replace manual compressions in every arrest"]'::jsonb, 1, 'Mechanical compression devices can maintain consistent compression quality in specific situations like prolonged transport, but they require training to place correctly and do not replace defibrillation or overall resuscitation protocol.', 'Pre-Council', '🎓', true),
(8167, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Which skin complication may develop from prolonged CPR and immobility during a resuscitation event?', '["Improved skin perfusion", "Skin cancer", "There is no skin risk during a resuscitation effort", "Pressure injury/skin breakdown, especially over bony prominences"]'::jsonb, 3, 'Prolonged immobility and pressure during a resuscitation attempt, particularly over bony areas like the sacrum and heels, can predispose the patient to pressure injury, which should be assessed for after the event.', 'Pre-Council', '🎓', true),
(8168, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'What is the main quality problem caused by rescuer fatigue during prolonged chest compressions?', '["Shallower compression depth and slower rate over time, reducing CPR effectiveness", "Compressions that become faster and deeper than recommended", "Improved compression consistency over time", "No measurable change in compression quality"]'::jsonb, 0, 'Fatigue progressively degrades compression depth and rate, which is why guidelines recommend switching compressors approximately every 2 minutes to maintain effective CPR.', 'Pre-Council', '🎓', true),
(8169, 'Post-Operative Care of Anaesthetised Patients', 'CCN Curriculum — Anaesthesia', 'Why is IV or IO access preferred over intramuscular injection for administering resuscitation drugs during CPR?', '["Intramuscular injections work equally fast during cardiac arrest", "IV/IO access is never required during CPR", "IV/IO access provides faster, more reliable delivery of medication to the central circulation, which is especially important given the poor peripheral perfusion of cardiac arrest", "The intramuscular route avoids all possible complications"]'::jsonb, 2, 'During arrest, peripheral tissue perfusion (including muscle) is minimal, so absorption from an intramuscular injection would be unreliably slow; IV or IO access delivers drugs directly and rapidly into the circulation.', 'Pre-Council', '🎓', true),
(8170, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'What is Mendelson''s syndrome?', '["Chemical pneumonitis resulting from aspiration of acidic gastric contents into the lungs", "Bacterial pneumonia acquired during mechanical ventilation", "An allergic reaction to inhalational anaesthetic agents", "Pulmonary embolism occurring after prolonged bed rest"]'::jsonb, 0, 'Mendelson''s syndrome is chemical (aspiration) pneumonitis caused by inhalation of acidic gastric contents, first described in obstetric patients under general anaesthesia.', 'Pre-Council', '🎓', true),
(8171, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Aspiration of gastric contents is most likely to cause severe chemical pneumonitis when the aspirate has which characteristics?', '["pH less than 2.5 and volume greater than 0.4 mL/kg (about 25 mL in an adult)", "pH greater than 7.0 and volume less than 10 mL", "pH between 5 and 6 regardless of volume", "Any volume as long as the aspirate is sterile"]'::jsonb, 0, 'The classic Mendelson criteria for high-risk aspiration are gastric pH <2.5 and aspirate volume >0.4 mL/kg (~25 mL in an average adult); more acidic, larger-volume aspirates cause more severe lung injury.', 'Pre-Council', '🎓', true),
(8172, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Which group of patients is classically at highest risk of Mendelson''s syndrome?', '["Pregnant women undergoing emergency general anaesthesia", "Patients who fasted appropriately before elective day-case surgery", "Patients undergoing local anaesthesia for minor skin procedures", "Well-controlled type 2 diabetics undergoing outpatient dental extraction"]'::jsonb, 0, 'Pregnant women have delayed gastric emptying, reduced lower oesophageal sphincter tone, and raised intra-abdominal pressure, making them classically the highest-risk group for aspiration under general anaesthesia.', 'Pre-Council', '🎓', true),
(8173, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'The chemical injury in Mendelson''s syndrome primarily results from which mechanism?', '["Direct acid-induced destruction of the alveolar-capillary membrane leading to increased permeability and pulmonary oedema", "Mechanical obstruction of the trachea by food particles alone", "Immune complex deposition in the pulmonary vasculature", "Vasospasm of the pulmonary arteries triggered by low pH"]'::jsonb, 0, 'Acidic gastric contents directly damage the alveolar-capillary membrane, increasing capillary permeability and causing a non-cardiogenic pulmonary oedema/ARDS-like picture.', 'Pre-Council', '🎓', true),
(8174, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'A patient aspirates gastric contents during induction of anaesthesia. Which clinical picture is most typical in the following minutes?', '["Sudden dyspnoea, wheeze, tachycardia, and falling oxygen saturation", "Gradual onset of unilateral leg swelling over several days", "Painless jaundice developing over the next week", "Isolated bradycardia with normal oxygen saturation"]'::jsonb, 0, 'Acute aspiration classically presents with sudden dyspnoea, bronchospasm/wheeze, tachycardia, and hypoxaemia due to chemical injury and reflex bronchoconstriction.', 'Pre-Council', '🎓', true),
(8175, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'On chest X-ray after aspiration, infiltrates are most commonly seen in which location and why?', '["Right lower lobe, because the right main bronchus is wider, shorter, and more vertical", "Left upper lobe, because it is anatomically dependent when supine", "Bilateral upper lobes only, due to gravity-independent spread", "Left lower lobe exclusively, due to cardiac displacement"]'::jsonb, 0, 'The right main bronchus is wider, shorter and more vertically aligned with the trachea, so aspirated material preferentially enters the right lung, especially the right lower lobe in a supine or semi-recumbent patient.', 'Pre-Council', '🎓', true),
(8176, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Which investigation combination is most useful in confirming and assessing the severity of acute aspiration pneumonitis?', '["Chest X-ray and arterial blood gas analysis", "Abdominal ultrasound and liver function tests", "Electroencephalogram and lumbar puncture", "Thyroid function tests and fasting lipid profile"]'::jsonb, 0, 'Chest X-ray demonstrates infiltrates/atelectasis while ABG quantifies the degree of hypoxaemia and any respiratory acidosis, both essential for assessing severity and guiding management.', 'Pre-Council', '🎓', true),
(8177, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'What is the primary purpose of preoperative fasting (NPO) guidelines before elective general anaesthesia?', '["To reduce gastric volume and acidity, lowering the risk of aspiration pneumonitis", "To prevent postoperative nausea only", "To reduce the need for postoperative analgesia", "To shorten the duration of surgery"]'::jsonb, 0, 'Fasting reduces residual gastric volume, lowering the risk that a large-volume, acidic aspirate would be regurgitated and aspirated during induction of anaesthesia.', 'Pre-Council', '🎓', true),
(8178, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Rapid sequence induction (RSI) is indicated in which of the following situations to reduce aspiration risk?', '["A patient with a full stomach requiring emergency surgery", "A fasted, healthy patient for elective cataract surgery under local anaesthesia", "A patient undergoing awake fibre-optic intubation for a known difficult airway", "A paediatric patient for elective tonsillectomy after adequate fasting"]'::jsonb, 0, 'RSI, with pre-oxygenation, cricoid pressure, and rapid securing of the airway without bag-mask ventilation, is used specifically for patients presumed to have a full stomach (emergency, trauma, obstetric, or unfasted patients) to minimise aspiration risk.', 'Pre-Council', '🎓', true),
(8179, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'What is the physiological rationale for applying cricoid pressure (Sellick''s manoeuvre) during rapid sequence induction?', '["It compresses the oesophagus against the cervical vertebrae, occluding it to prevent passive regurgitation", "It increases lower oesophageal sphincter tone pharmacologically", "It stimulates the vagus nerve to reduce gastric secretions", "It directly splints open the vocal cords for easier intubation"]'::jsonb, 0, 'Cricoid pressure pushes the cricoid cartilage posteriorly, compressing the oesophagus between the cartilage and the cervical spine, theoretically occluding it and preventing passive regurgitation of gastric contents into the pharynx.', 'Pre-Council', '🎓', true),
(8180, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Before caesarean section under general anaesthesia, why is a non-particulate antacid (e.g., sodium citrate) preferred over a particulate antacid?', '["Particulate antacids can themselves cause severe pneumonitis if aspirated", "Non-particulate antacids act faster to induce labour", "Particulate antacids interact with oxytocin", "Non-particulate antacids provide longer-lasting analgesia"]'::jsonb, 0, 'If aspirated, particulate antacids (e.g., magnesium trisilicate) can cause a granulomatous chemical pneumonitis of their own; non-particulate agents like sodium citrate neutralise gastric acid without this risk.', 'Pre-Council', '🎓', true),
(8181, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'A patient is witnessed to regurgitate and aspirate during induction of anaesthesia. What is the immediate first step?', '["Place the patient head-down in the lateral position and suction the airway immediately", "Administer a full dose of intravenous antibiotics before any airway intervention", "Perform saline lavage of the trachea to dilute the acid", "Delay any intervention until a chest X-ray confirms aspiration"]'::jsonb, 0, 'Immediate head-down lateral positioning and suctioning helps clear the airway and limits further tracheobronchial soiling; antibiotics and imaging are not the first priority and saline lavage can worsen spread of acid into the lung.', 'Pre-Council', '🎓', true),
(8182, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Why is routine saline lavage of the airway NOT recommended after witnessed aspiration of gastric contents?', '["It can wash the acid and particulate matter further into distal airways, worsening lung injury", "It causes immediate cardiac arrest in all patients", "It neutralises stomach acid completely and is unnecessary", "It is contraindicated because it triggers anaphylaxis"]'::jsonb, 0, 'Lavage risks propelling aspirated material and acid deeper into the bronchial tree and does not neutralise the chemical injury already caused; suctioning of accessible material is preferred instead.', 'Pre-Council', '🎓', true),
(8183, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Regarding pharmacological management of acute aspiration pneumonitis, which statement is correct?', '["Prophylactic antibiotics are not routinely recommended unless there is evidence of secondary bacterial infection", "Broad-spectrum antibiotics must be started in every case immediately regardless of clinical course", "Corticosteroids are proven first-line therapy and should be given to all patients", "Antifungal therapy is first-line treatment in all cases"]'::jsonb, 0, 'Initial aspiration pneumonitis is a chemical injury, often sterile; antibiotics are reserved for patients who develop signs of secondary bacterial infection, and routine corticosteroids have not shown consistent benefit.', 'Pre-Council', '🎓', true),
(8184, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'A patient with severe Mendelson''s syndrome develops worsening bilateral infiltrates, refractory hypoxaemia, and reduced lung compliance over 24-48 hours. This most likely represents progression to which complication?', '["Acute respiratory distress syndrome (ARDS)", "Chronic bronchitis", "Pulmonary embolism", "Bronchiectasis"]'::jsonb, 0, 'Severe chemical lung injury from aspiration can progress to ARDS, characterised by bilateral infiltrates, refractory hypoxaemia, and decreased lung compliance from diffuse alveolar damage.', 'Pre-Council', '🎓', true),
(8185, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'As part of patient education after an anaesthetic-related aspiration event, the nurse should emphasise which point for future procedures?', '["Strict adherence to prescribed fasting instructions before any future sedation or anaesthesia", "There is no need to disclose the previous aspiration event to future anaesthetists", "Eating a heavy meal just before surgery reduces aspiration risk", "Fasting guidelines only apply to paediatric patients"]'::jsonb, 0, 'Patients should be counselled on strict adherence to fasting instructions and on disclosing any prior aspiration event to future anaesthetic providers, since this history affects risk assessment and airway management planning.', 'Pre-Council', '🎓', true),
(8186, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'COPD is best defined as:', '["A chronic, progressive disease characterised by persistent airflow limitation that is not fully reversible", "An acute, fully reversible bronchospastic disease triggered only by allergens", "A restrictive lung disease caused by fibrosis of the lung parenchyma", "A congenital abnormality of the bronchial tree"]'::jsonb, 0, 'COPD is defined by persistent, progressive airflow limitation that is usually only partially reversible, distinguishing it from asthma which is typically fully reversible.', 'Pre-Council', '🎓', true),
(8187, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'What is the single most important modifiable risk factor for COPD worldwide?', '["Cigarette smoking", "Excess dietary salt intake", "Sedentary lifestyle", "Seasonal pollen exposure"]'::jsonb, 0, 'Cigarette smoking is the leading cause of COPD globally, though biomass fuel exposure is also an important cause particularly in low-resource settings.', 'Pre-Council', '🎓', true),
(8188, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Chronic bronchitis, one of the components of COPD, is clinically defined as:', '["A productive cough occurring on most days for at least 3 months in each of 2 consecutive years", "A single episode of productive cough lasting more than 2 weeks", "Cough occurring only at night for one month", "Wheeze without any cough for 6 months"]'::jsonb, 0, 'Chronic bronchitis is a clinical diagnosis defined as chronic productive cough for at least 3 months in 2 consecutive years, after excluding other causes.', 'Pre-Council', '🎓', true),
(8189, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'The pathological hallmark of emphysema is:', '["Destruction of alveolar walls with permanent enlargement of airspaces distal to the terminal bronchioles", "Excess mucus gland hypertrophy in the large airways only", "Fibrotic thickening of the pleura", "Reversible smooth muscle bronchoconstriction"]'::jsonb, 0, 'Emphysema involves destruction of alveolar septa and loss of elastic recoil, causing permanent enlargement of distal airspaces and air trapping.', 'Pre-Council', '🎓', true),
(8190, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Which spirometric finding confirms the diagnosis of COPD?', '["Post-bronchodilator FEV1/FVC ratio less than 0.70", "Post-bronchodilator FEV1/FVC ratio greater than 0.90", "A normal FEV1/FVC ratio with reduced total lung capacity", "An FEV1/FVC ratio that fully normalises after bronchodilator use"]'::jsonb, 0, 'A post-bronchodilator FEV1/FVC ratio below 0.70 confirms persistent airflow limitation consistent with COPD, per GOLD criteria.', 'Pre-Council', '🎓', true),
(8191, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'A stable patient with severe COPD is likely to show which arterial blood gas pattern at baseline?', '["Chronic hypercapnia with compensatory elevation of bicarbonate and near-normal pH", "Acute respiratory alkalosis with low bicarbonate", "Normal PaCO2 with severe metabolic acidosis", "Marked hypocapnia with elevated pH"]'::jsonb, 0, 'Chronic CO2 retention in advanced COPD is renally compensated over time by bicarbonate retention, producing a near-normal pH despite elevated PaCO2 (compensated respiratory acidosis).', 'Pre-Council', '🎓', true),
(8192, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Why must supplemental oxygen be titrated carefully (e.g., controlled low-concentration delivery) in a patient with a COPD exacerbation?', '["Uncontrolled high-flow oxygen can worsen hypercapnia through loss of hypoxic respiratory drive and worsening ventilation-perfusion mismatch", "Oxygen is completely contraindicated in all COPD patients", "High-flow oxygen immediately causes pneumothorax", "Oxygen therapy has no effect on carbon dioxide levels in COPD"]'::jsonb, 0, 'In chronic CO2 retainers, high-flow oxygen can blunt hypoxic respiratory drive and, more importantly, worsens V/Q mismatch and increases the Haldane effect, all raising PaCO2; titrated oxygen (target SpO2 88-92%) is recommended.', 'Pre-Council', '🎓', true),
(8193, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'For a patient with an acute COPD exacerbation and a history of chronic CO2 retention, which initial oxygen delivery approach is most appropriate?', '["Controlled oxygen via Venturi mask titrated to a target SpO2 of about 88-92%", "Non-rebreather mask at 15 L/min regardless of saturation", "Room air only with no supplemental oxygen under any circumstance", "Nasal cannula at 6 L/min titrated to SpO2 100%"]'::jsonb, 0, 'A Venturi mask delivers a precise, controlled FiO2, allowing titration to a conservative target (SpO2 88-92%) that avoids worsening hypercapnia while still correcting dangerous hypoxaemia.', 'Pre-Council', '🎓', true),
(8194, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'What is the physiological benefit of pursed-lip breathing taught to patients with COPD?', '["It prolongs expiration and creates back-pressure that helps prevent small airway collapse", "It increases the respiratory rate to clear more carbon dioxide quickly", "It primarily strengthens the diaphragm for inspiration", "It reduces oxygen requirement by decreasing tidal volume"]'::jsonb, 0, 'Pursed-lip breathing generates positive pressure in the airways during exhalation, splinting open small airways prone to dynamic collapse and reducing air trapping, which improves gas exchange and dyspnoea.', 'Pre-Council', '🎓', true),
(8195, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'A COPD patient who is thin, has severe dyspnoea, pursed-lip breathing, and only mildly abnormal blood gases is classically described as:', '["A ''pink puffer'', typically emphysema-predominant", "A ''blue bloater'', typically chronic-bronchitis-predominant", "A patient in anaesthetic death", "A patient presenting with Mendelson''s syndrome"]'::jsonb, 0, 'The ''pink puffer'' phenotype reflects emphysema-predominant disease with increased work of breathing to maintain near-normal gas exchange, in contrast to the cyanotic, oedematous ''blue bloater'' phenotype of chronic-bronchitis-predominant disease.', 'Pre-Council', '🎓', true),
(8196, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Long-standing COPD with chronic hypoxaemia can lead to right ventricular hypertrophy and failure, a condition known as:', '["Cor pulmonale", "Constrictive pericarditis", "Dilated cardiomyopathy of the left ventricle", "Mitral stenosis"]'::jsonb, 0, 'Chronic hypoxaemia causes pulmonary vasoconstriction and pulmonary hypertension, leading over time to right ventricular hypertrophy and failure (cor pulmonale).', 'Pre-Council', '🎓', true),
(8197, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'For a patient with an acute COPD exacerbation presenting with respiratory acidosis (pH 7.30, PaCO2 60 mmHg) but still conscious and able to protect the airway, which intervention is generally tried before invasive intubation?', '["Non-invasive positive pressure ventilation (e.g., BiPAP)", "Immediate elective tracheostomy", "High-dose intravenous sedation to reduce work of breathing", "Therapeutic bronchoalveolar lavage"]'::jsonb, 0, 'Non-invasive ventilation (BiPAP) reduces work of breathing and improves gas exchange in COPD exacerbations with respiratory acidosis in an alert, cooperative patient, and can prevent the need for invasive intubation.', 'Pre-Council', '🎓', true),
(8198, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'The ''barrel chest'' appearance seen in advanced COPD results from:', '["Chronic hyperinflation of the lungs increasing the anteroposterior chest diameter", "Acute pleural effusion pushing the chest wall outward", "Rib fractures from chronic coughing", "Congenital pectus carinatum"]'::jsonb, 0, 'Air trapping and hyperinflation from loss of elastic recoil chronically increase lung volume, pushing the ribs into a more horizontal position and increasing the anteroposterior chest diameter.', 'Pre-Council', '🎓', true),
(8199, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'What is the single most effective intervention to slow the progression of COPD?', '["Smoking cessation", "Daily prophylactic antibiotics", "Long-term high-dose oral corticosteroids", "Routine chest physiotherapy alone without other interventions"]'::jsonb, 0, 'Smoking cessation is the only intervention proven to significantly slow the accelerated decline in lung function characteristic of COPD.', 'Pre-Council', '🎓', true),
(8200, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'When planning nutrition for a mechanically ventilated COPD patient with difficulty weaning, which principle is important?', '["Avoid overfeeding, particularly excess carbohydrate, since it increases CO2 production and ventilatory demand", "Provide the highest possible carbohydrate load to maximise energy delivery", "Restrict all protein intake to reduce respiratory workload", "Nutrition has no effect on ventilatory demand in COPD"]'::jsonb, 0, 'Excess carbohydrate calories increase the respiratory quotient and CO2 production, increasing ventilatory demand and potentially hindering weaning in patients with limited respiratory reserve.', 'Pre-Council', '🎓', true),
(8201, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'A COPD patient with emphysematous bullae suddenly develops acute chest pain, worsening dyspnoea, and absent breath sounds on one side. This presentation is most consistent with:', '["Spontaneous pneumothorax from a ruptured bulla", "Acute pulmonary embolism only", "A simple viral upper respiratory infection", "Mendelson''s syndrome"]'::jsonb, 0, 'Rupture of a subpleural bulla can cause spontaneous pneumothorax, presenting with sudden pleuritic chest pain, dyspnoea, and unilaterally absent breath sounds, a recognised complication in emphysematous COPD.', 'Pre-Council', '🎓', true),
(8202, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Pulmonary oedema is best defined as:', '["Abnormal accumulation of fluid in the pulmonary interstitium and alveoli, impairing gas exchange", "Accumulation of air in the pleural space", "Chronic fibrosis of the alveolar walls", "Complete collapse of a lung lobe due to bronchial obstruction"]'::jsonb, 0, 'Pulmonary oedema is the abnormal accumulation of fluid within the lung interstitium and alveolar spaces, which impairs oxygen and carbon dioxide exchange.', 'Pre-Council', '🎓', true),
(8203, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Cardiogenic pulmonary oedema most commonly results from:', '["Elevated pulmonary capillary hydrostatic pressure due to left ventricular failure", "Increased alveolar-capillary membrane permeability due to sepsis", "Decreased plasma oncotic pressure from severe malnutrition", "Lymphatic obstruction from a mediastinal tumour"]'::jsonb, 0, 'In cardiogenic pulmonary oedema, failure of the left ventricle raises left atrial and pulmonary capillary pressures, pushing fluid out of the pulmonary capillaries into the interstitium and alveoli.', 'Pre-Council', '🎓', true),
(8204, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Non-cardiogenic pulmonary oedema, as seen in ARDS, primarily results from:', '["Increased permeability of the alveolar-capillary membrane allowing protein-rich fluid to leak into alveoli", "Increased hydrostatic pressure from left ventricular failure", "Decreased hydrostatic pressure in the pulmonary capillaries", "Obstruction of the trachea by a foreign body"]'::jsonb, 0, 'In non-cardiogenic pulmonary oedema (e.g., ARDS), direct injury increases capillary permeability, allowing protein-rich fluid to leak into the alveoli even without elevated hydrostatic pressure.', 'Pre-Council', '🎓', true),
(8205, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'A classic clinical feature of acute cardiogenic pulmonary oedema is:', '["Pink, frothy sputum with severe dyspnoea and orthopnoea", "Painless haematuria", "Unilateral leg swelling with a normal respiratory rate", "Dry cough with no dyspnoea"]'::jsonb, 0, 'Acute pulmonary oedema classically presents with sudden severe dyspnoea, orthopnoea, and pink frothy sputum from alveolar flooding with blood-tinged fluid.', 'Pre-Council', '🎓', true),
(8206, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'On chest auscultation, a patient with acute pulmonary oedema is most likely to have:', '["Bilateral fine crackles (rales) at the lung bases progressing upward", "Unilateral absent breath sounds", "A pleural friction rub only", "Completely clear breath sounds bilaterally"]'::jsonb, 0, 'Fluid in the alveoli produces bilateral crackles, typically starting at the lung bases and extending upward as the oedema worsens.', 'Pre-Council', '🎓', true),
(8207, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Which chest X-ray finding is characteristic of cardiogenic pulmonary oedema?', '["Bilateral perihilar ''bat-wing'' infiltrates with Kerley B lines and cardiomegaly", "A single well-circumscribed nodule in the right upper lobe", "Complete opacification of one hemithorax with mediastinal shift away from it", "A normal chest X-ray in all cases"]'::jsonb, 0, 'Cardiogenic pulmonary oedema classically shows bilateral perihilar ''bat-wing'' infiltrates, Kerley B lines (interstitial oedema), and cardiomegaly reflecting the underlying cardiac cause.', 'Pre-Council', '🎓', true),
(8208, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Measurement of B-type natriuretic peptide (BNP) is useful in acute dyspnoea because:', '["An elevated BNP supports a cardiogenic cause of pulmonary oedema, helping differentiate it from ARDS", "A low BNP confirms cardiogenic pulmonary oedema", "BNP is elevated only in pulmonary infections", "BNP levels are unrelated to cardiac function"]'::jsonb, 0, 'BNP is released in response to ventricular wall stretch; markedly elevated levels support a cardiogenic cause of pulmonary oedema, whereas normal or low levels favour a non-cardiogenic cause such as ARDS.', 'Pre-Council', '🎓', true),
(8209, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'What positioning is most appropriate for a conscious patient in acute pulmonary oedema?', '["High Fowler''s (upright) position with legs dependent to reduce venous return", "Flat supine position to maximise cardiac output", "Trendelenburg (head-down) position", "Prone position with arms extended"]'::jsonb, 0, 'An upright position with legs dependent decreases venous return to the heart, reduces pulmonary congestion, and eases the work of breathing.', 'Pre-Council', '🎓', true),
(8210, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'First-line pharmacological management of acute cardiogenic pulmonary oedema typically includes:', '["Intravenous loop diuretics (e.g., furosemide) and vasodilators such as nitrates", "Oral antibiotics and antitussives", "High-dose beta-blockers as first-line acute therapy", "Anticoagulation as the sole initial treatment"]'::jsonb, 0, 'IV loop diuretics rapidly reduce circulating volume and preload, while vasodilators such as nitrates reduce preload and afterload, together relieving pulmonary congestion in acute cardiogenic pulmonary oedema.', 'Pre-Council', '🎓', true),
(8211, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Non-invasive ventilation (e.g., CPAP) benefits patients with acute cardiogenic pulmonary oedema mainly by:', '["Reducing preload and afterload while improving alveolar recruitment and oxygenation", "Directly increasing cardiac contractility", "Curing the underlying valvular disease", "Eliminating the need for any diuretic therapy"]'::jsonb, 0, 'CPAP increases intrathoracic pressure, which decreases venous return (preload) and left ventricular afterload while recruiting flooded alveoli, improving oxygenation and reducing work of breathing.', 'Pre-Council', '🎓', true),
(8212, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Which nursing intervention is most important for ongoing monitoring of a patient being treated for pulmonary oedema?', '["Strict intake and output measurement with daily weights", "A one-time weight measurement on admission only", "Restricting all oral fluids indefinitely without reassessment", "Avoiding oxygen saturation monitoring to reduce patient anxiety"]'::jsonb, 0, 'Strict fluid balance monitoring and daily weights allow the team to assess response to diuretic therapy and detect fluid overload or excessive diuresis promptly.', 'Pre-Council', '🎓', true),
(8213, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Respiratory insufficiency (respiratory failure) is best defined as:', '["The inability of the respiratory system to maintain adequate oxygenation and/or carbon dioxide elimination", "A complete absence of spontaneous breathing", "A permanent structural abnormality of the lung parenchyma", "An isolated increase in respiratory rate without any gas exchange abnormality"]'::jsonb, 0, 'Respiratory failure/insufficiency is a functional definition based on inadequate gas exchange - failure of oxygenation, ventilation, or both - regardless of the underlying cause.', 'Pre-Council', '🎓', true),
(8214, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Type I (hypoxaemic) respiratory failure is characterised by:', '["Low PaO2 with normal or low PaCO2", "High PaO2 with high PaCO2", "Normal PaO2 with severe hypercapnia", "Low PaO2 that never responds to any oxygen therapy"]'::jsonb, 0, 'Type I respiratory failure is defined by hypoxaemia (PaO2 <60 mmHg) with normal or low PaCO2, typically from V/Q mismatch, shunt, or diffusion impairment, as in pneumonia, ARDS, or pulmonary oedema.', 'Pre-Council', '🎓', true),
(8215, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Type II (hypercapnic) respiratory failure, defined by PaCO2 above about 45-50 mmHg with acidaemia, is most typically caused by:', '["Alveolar hypoventilation, such as in COPD, neuromuscular disease, or CNS depression", "Isolated diffusion impairment from pulmonary fibrosis alone", "A pure right-to-left cardiac shunt", "High-altitude exposure alone"]'::jsonb, 0, 'Type II respiratory failure results from inadequate alveolar ventilation, seen in conditions that reduce the drive to breathe (CNS depression), impair respiratory muscle function (neuromuscular disease), or increase airway obstruction/dead space (COPD).', 'Pre-Council', '🎓', true),
(8216, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Which is typically the EARLIEST clinical sign of developing hypoxaemia in a deteriorating patient?', '["Restlessness, anxiety, and confusion", "Central cyanosis", "Bradycardia", "Fixed and dilated pupils"]'::jsonb, 0, 'Restlessness, anxiety, and confusion from cerebral hypoxia often appear before overt cyanosis, which is a late and unreliable sign of hypoxaemia.', 'Pre-Council', '🎓', true),
(8217, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Ventilation-perfusion (V/Q) mismatch as a cause of hypoxaemia refers to:', '["A mismatch between areas of the lung that are ventilated and areas that are perfused with blood", "A complete absence of any blood flow to the lungs", "Uniformly reduced ventilation and perfusion throughout both lungs", "An excess of oxygen delivered relative to metabolic demand"]'::jsonb, 0, 'V/Q mismatch occurs when ventilation and perfusion are not well matched in various lung regions (e.g., a perfused but poorly ventilated area, as in pneumonia), leading to inefficient gas exchange and hypoxaemia.', 'Pre-Council', '🎓', true),
(8218, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'A true intrapulmonary shunt as a cause of hypoxaemia is characterised by:', '["Blood passing through unventilated alveoli so hypoxaemia responds poorly to supplemental oxygen alone", "Complete resolution of hypoxaemia with low-flow oxygen", "Normal alveolar ventilation perfectly matched with perfusion", "Increased carbon dioxide elimination without any oxygenation defect"]'::jsonb, 0, 'In a true shunt, blood bypasses ventilated alveoli entirely (e.g., filled with fluid or collapsed), so it is not oxygenated; supplemental oxygen alone often fails to correct the hypoxaemia, and interventions like PEEP to recruit alveoli are needed.', 'Pre-Council', '🎓', true),
(8219, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Diffusion impairment as a mechanism of hypoxaemia is classically seen in which condition?', '["Pulmonary fibrosis, where a thickened alveolar-capillary membrane slows gas exchange", "Simple upper airway obstruction", "Acute bronchospasm alone", "Isolated anaemia"]'::jsonb, 0, 'Pulmonary fibrosis thickens and scars the alveolar-capillary interface, slowing oxygen diffusion across the membrane, particularly evident during exertion.', 'Pre-Council', '🎓', true),
(8220, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'By common ABG criteria on room air, respiratory failure is generally diagnosed when:', '["PaO2 is less than 60 mmHg and/or PaCO2 is greater than 45-50 mmHg with associated acidaemia", "PaO2 is greater than 100 mmHg", "PaCO2 is less than 35 mmHg with alkalaemia", "Both PaO2 and PaCO2 are within normal limits"]'::jsonb, 0, 'Respiratory failure on room air is generally defined by PaO2 <60 mmHg (hypoxaemic failure) and/or PaCO2 >45-50 mmHg with acidaemia (hypercapnic failure).', 'Pre-Council', '🎓', true),
(8221, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Which of the following is an appropriate indication to initiate mechanical ventilation in a patient with worsening respiratory insufficiency?', '["Persistent severe hypoxaemia or hypercapnic acidosis despite maximal non-invasive therapy, with signs of respiratory exhaustion", "A single stable oxygen saturation reading of 96% on room air", "Mild, resolving dyspnoea after bronchodilator therapy", "Normal ABG values with no respiratory distress"]'::jsonb, 0, 'Mechanical ventilation is indicated when non-invasive measures fail to correct severe hypoxaemia or hypercapnic acidosis, or when the patient shows signs of respiratory muscle fatigue/exhaustion and cannot maintain adequate ventilation.', 'Pre-Council', '🎓', true),
(8222, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'For a patient with acute respiratory insufficiency, which nursing priority takes precedence?', '["Maintaining a patent airway and ensuring adequate oxygenation/ventilation", "Completing a full nutritional assessment before any other intervention", "Arranging discharge planning immediately", "Obtaining consent for elective surgery"]'::jsonb, 0, 'Airway patency and adequate oxygenation/ventilation are the immediate life-sustaining priorities in acute respiratory insufficiency, following the standard ABC approach to critical illness.', 'Pre-Council', '🎓', true),
(8223, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'If severe respiratory insufficiency is left uncorrected, the most life-threatening ultimate consequence is:', '["Cardiac arrest secondary to severe hypoxaemia and/or acidosis", "Immediate resolution without any intervention", "Isolated hearing loss", "Chronic constipation"]'::jsonb, 0, 'Uncorrected severe hypoxaemia and/or hypercapnic acidosis impair myocardial function and can precipitate dysrhythmias and cardiac arrest if not promptly treated.', 'Pre-Council', '🎓', true),
(8224, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Why is cyanosis considered an unreliable early indicator of hypoxaemia in critically ill patients?', '["It typically only becomes visible once deoxygenated haemoglobin reaches a critical concentration (roughly 5 g/dL), which may occur late and is affected by skin tone and haemoglobin level", "It appears immediately with even mild reductions in oxygen saturation", "It is present in 100% of anaemic patients regardless of oxygenation", "It has no relationship to hameoglobin oxygen saturation at all"]'::jsonb, 0, 'Cyanosis depends on an absolute amount of deoxygenated haemoglobin (approximately 5 g/dL), so it can be delayed, masked in anaemic patients, or harder to detect depending on skin tone, making it an unreliable early sign compared with pulse oximetry and clinical assessment.', 'Pre-Council', '🎓', true),
(8225, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'In pure alveolar hypoventilation (e.g., from opioid overdose), the expected arterial blood gas pattern is:', '["Elevated PaCO2 with a corresponding fall in PaO2, while the alveolar-arterial (A-a) gradient remains normal", "Normal PaCO2 with a markedly widened A-a gradient", "Low PaCO2 with elevated PaO2", "Elevated PaCO2 with a markedly widened A-a gradient due to shunt"]'::jsonb, 0, 'Pure hypoventilation raises PaCO2 and correspondingly lowers PaO2 (per the alveolar gas equation) while the A-a gradient stays normal, since gas exchange at the alveolar-capillary membrane itself is not impaired - distinguishing it from V/Q mismatch, shunt, or diffusion defects.', 'Pre-Council', '🎓', true),
(8226, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Which brainstem structure contains the primary neurons responsible for the automatic, rhythmic control of breathing?', '["The medulla oblongata", "The cerebellum", "The hypothalamus", "The occipital cortex"]'::jsonb, 0, 'The medulla oblongata houses the dorsal and ventral respiratory groups that generate the basic rhythm of breathing.', 'Pre-Council', '🎓', true),
(8227, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Central chemoreceptors, located near the medulla, primarily regulate ventilation in response to:', '["Changes in cerebrospinal fluid hydrogen ion concentration resulting from carbon dioxide diffusion across the blood-brain barrier", "Direct changes in arterial oxygen tension", "Changes in blood glucose concentration", "Mechanical stretch of the lung"]'::jsonb, 0, 'CO2 diffuses freely across the blood-brain barrier and is hydrated to form carbonic acid, which dissociates to release H+ ions that directly stimulate central chemoreceptors, making PaCO2 the dominant regulator of ventilation under normal conditions.', 'Pre-Council', '🎓', true),
(8228, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Peripheral chemoreceptors located in the carotid and aortic bodies are most important for detecting:', '["A significant fall in arterial oxygen tension (hypoxaemia)", "Small fluctuations in body temperature", "Changes in serum sodium concentration", "Mechanical lung stretch"]'::jsonb, 0, 'Peripheral chemoreceptors are the primary sensors of hypoxaemia, becoming an important drive to breathe particularly when PaO2 falls significantly (below about 60 mmHg), and also respond to PaCO2 and pH.', 'Pre-Council', '🎓', true),
(8229, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'In a healthy person, the primary physiological stimulus that drives minute-to-minute ventilation is:', '["A rise in arterial carbon dioxide tension (PaCO2)", "A rise in arterial oxygen tension (PaO2)", "A fall in blood glucose", "A rise in serum calcium"]'::jsonb, 0, 'Under normal physiological conditions, PaCO2 (via central chemoreceptor detection of CSF pH) is the most important and sensitive regulator of ventilation, with hypoxic drive becoming clinically significant mainly when CO2 sensitivity is chronically blunted, as in some COPD patients.', 'Pre-Council', '🎓', true),
(8230, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'The Hering-Breuer inflation reflex functions to:', '["Inhibit further inspiration when the lungs are sufficiently stretched, preventing overinflation", "Stimulate forced expiration during exercise", "Increase heart rate during inspiration", "Trigger coughing in response to airway irritants"]'::jsonb, 0, 'Stretch receptors in the airway smooth muscle send inhibitory signals via the vagus nerve to the medullary respiratory centre when the lungs are adequately inflated, terminating inspiration and preventing overdistension.', 'Pre-Council', '🎓', true),
(8231, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'The pneumotaxic centre, located in the upper pons, primarily functions to:', '["Limit the duration of inspiration and help regulate respiratory rate", "Generate the basic rhythm of breathing independently of the medulla", "Control voluntary breath-holding exclusively", "Regulate heart rate directly"]'::jsonb, 0, 'The pneumotaxic centre sends inhibitory signals that limit inspiratory duration, fine-tuning respiratory rate and the pattern set by the medullary centres.', 'Pre-Council', '🎓', true),
(8232, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'A patient in diabetic ketoacidosis develops deep, rapid respirations (Kussmaul breathing). This pattern represents:', '["A respiratory compensatory response to underlying metabolic acidosis, increasing CO2 elimination", "A primary respiratory cause of alkalosis", "A sign of central nervous system depression", "An entirely voluntary breathing pattern unrelated to acid-base status"]'::jsonb, 0, 'Kussmaul breathing is a compensatory hyperventilation response driven by chemoreceptor detection of metabolic acidosis, aiming to lower PaCO2 and raise blood pH toward normal.', 'Pre-Council', '🎓', true),
(8233, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Which condition is a common indication for lung transplantation?', '["End-stage COPD, pulmonary fibrosis, or cystic fibrosis refractory to medical management", "Mild, well-controlled asthma", "A single episode of community-acquired pneumonia", "Uncomplicated seasonal allergic rhinitis"]'::jsonb, 0, 'Lung transplantation is reserved for end-stage lung disease refractory to maximal medical therapy, such as advanced COPD, pulmonary fibrosis, cystic fibrosis, or pulmonary hypertension.', 'Pre-Council', '🎓', true),
(8234, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Primary graft dysfunction occurring in the first 72 hours after lung transplantation is best understood as:', '["A form of acute lung injury related to ischaemia-reperfusion of the donor lung", "A late chronic rejection process occurring years after transplant", "An allergic drug reaction to immunosuppressants", "A normal, expected finding requiring no intervention"]'::jsonb, 0, 'Primary graft dysfunction is an acute lung injury/ARDS-like process caused by ischaemia-reperfusion injury to the donor lung, typically presenting within 72 hours post-transplant with hypoxaemia and diffuse infiltrates.', 'Pre-Council', '🎓', true),
(8235, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Post-transplant patients are maintained on long-term immunosuppression primarily to:', '["Prevent rejection of the transplanted organ by suppressing the host immune response", "Cure the original underlying lung disease permanently", "Prevent post-operative pain", "Eliminate the need for any further monitoring"]'::jsonb, 0, 'Lifelong immunosuppressive therapy prevents the recipient''s immune system from recognising and attacking the transplanted lung as foreign tissue.', 'Pre-Council', '🎓', true),
(8236, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Because of chronic immunosuppression, post-transplant patients are at significantly increased risk of:', '["Opportunistic infections", "Improved wound healing", "Spontaneous resolution of all comorbidities", "Decreased risk of malignancy"]'::jsonb, 0, 'Immunosuppressive therapy blunts the immune response to pathogens, placing transplant recipients at increased risk of bacterial, viral (e.g., CMV), fungal, and opportunistic infections, and also increases long-term malignancy risk.', 'Pre-Council', '🎓', true),
(8237, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Chronic rejection in lung transplant recipients most commonly manifests as which pathological process?', '["Bronchiolitis obliterans (obliterative bronchiolitis), causing progressive airflow obstruction", "Acute pulmonary embolism", "Pneumothorax", "Reversible bronchospasm that resolves spontaneously"]'::jsonb, 0, 'Chronic lung allograft rejection typically manifests as bronchiolitis obliterans syndrome, a fibroproliferative process narrowing small airways and causing progressive, largely irreversible airflow obstruction.', 'Pre-Council', '🎓', true),
(8238, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Which non-invasive test is used to monitor for early signs of lung transplant rejection during routine follow-up?', '["Spirometry, watching for a decline in FEV1 from the patient''s post-transplant baseline", "Abdominal ultrasound", "Serum lipid profile", "Bone density scan"]'::jsonb, 0, 'Home and clinic spirometry monitoring for a sustained drop in FEV1 is a key non-invasive tool for the early detection of acute or chronic rejection in lung transplant recipients.', 'Pre-Council', '🎓', true),
(8239, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'A key infection-control nursing priority for a lung transplant recipient in the ICU is:', '["Strict hand hygiene and protective isolation precautions to reduce exposure to pathogens", "Allowing unrestricted visitor access without screening", "Discontinuing all isolation precautions once the patient is extubated", "Withholding immunosuppressive medications to reduce infection risk"]'::jsonb, 0, 'Because immunosuppressed transplant recipients have blunted immune defences, meticulous hand hygiene and appropriate protective precautions are essential to reduce exposure to nosocomial and opportunistic pathogens; immunosuppressants must not be stopped abruptly as this risks rejection.', 'Pre-Council', '🎓', true),
(8240, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Which patient education point is essential for a patient discharged after lung transplantation?', '["Strict adherence to the immunosuppressive regimen and prompt reporting of any signs of infection or rejection (e.g., fever, dyspnoea, falling home spirometry readings)", "It is safe to stop immunosuppressant medications once symptoms improve", "No further follow-up appointments are needed after discharge", "Avoiding all physical activity permanently"]'::jsonb, 0, 'Lifelong adherence to immunosuppression and early recognition/reporting of infection or rejection symptoms are critical to graft survival, so patient education must emphasise these points strongly.', 'Pre-Council', '🎓', true),
(8241, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Common side effects of calcineurin-inhibitor immunosuppressants (e.g., tacrolimus, cyclosporine) used after transplantation include:', '["Nephrotoxicity and hypertension", "Improved renal function", "Bradycardia and hypoglycaemia", "Enhanced wound healing"]'::jsonb, 0, 'Calcineurin inhibitors are well known to cause nephrotoxicity and hypertension, requiring regular monitoring of renal function and blood pressure in transplant recipients.', 'Pre-Council', '🎓', true),
(8242, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'In the initial assessment of a poly-traumatised patient, the primary survey follows which systematic approach?', '["Airway with cervical spine control, Breathing, Circulation with haemorrhage control, Disability, Exposure (ABCDE)", "Immediate full-body radiographic imaging before any physical examination", "Detailed history taking before any physical assessment", "Discharge planning followed by wound care"]'::jsonb, 0, 'The ABCDE approach (Airway with C-spine control, Breathing, Circulation with haemorrhage control, Disability, Exposure) is the internationally recognised systematic primary survey for trauma patients, prioritising immediately life-threatening problems.', 'Pre-Council', '🎓', true),
(8243, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'A poly-trauma patient develops sudden severe respiratory distress, absent breath sounds on one side, tracheal deviation away from that side, and hypotension. This presentation is most consistent with:', '["Tension pneumothorax requiring immediate needle decompression", "A simple rib fracture without complication", "Uncomplicated pulmonary contusion", "Chronic bronchitis exacerbation"]'::jsonb, 0, 'Tracheal deviation, absent unilateral breath sounds, respiratory distress, and haemodynamic compromise are classic for tension pneumothorax, a life-threatening emergency requiring immediate needle decompression followed by chest tube insertion.', 'Pre-Council', '🎓', true),
(8244, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Flail chest occurs when:', '["Three or more consecutive ribs are fractured in two or more places, creating a free-floating segment with paradoxical chest wall movement", "A single rib is fractured without displacement", "The sternum alone is fractured with no rib involvement", "The diaphragm ruptures without any rib fracture"]'::jsonb, 0, 'Flail chest results from multiple, multi-level rib fractures that create a free segment of chest wall which moves paradoxically (inward on inspiration, outward on expiration), often associated with significant underlying pulmonary contusion.', 'Pre-Council', '🎓', true),
(8245, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'The major clinical concern with flail chest and paradoxical chest wall movement is:', '["Underlying pulmonary contusion and impaired ventilation leading to respiratory failure", "Immediate cardiac tamponade in all cases", "Certain progression to Mendelson''s syndrome", "No clinical significance if the patient is asymptomatic"]'::jsonb, 0, 'The clinical significance of flail chest lies less in the paradoxical movement itself and more in the associated underlying pulmonary contusion, which impairs gas exchange and can progress to respiratory failure.', 'Pre-Council', '🎓', true),
(8246, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'In the ''lethal triad'' of trauma, which three interrelated physiological derangements worsen outcomes if not addressed early?', '["Hypothermia, coagulopathy, and metabolic acidosis", "Hyperthermia, hyperglycaemia, and hypertension", "Hypokalaemia, hypercalcaemia, and alkalosis", "Bradycardia, hypoglycaemia, and hypernatraemia"]'::jsonb, 0, 'The trauma ''lethal triad'' of hypothermia, coagulopathy, and metabolic acidosis creates a self-perpetuating cycle that worsens bleeding and mortality if not aggressively corrected through damage control resuscitation.', 'Pre-Council', '🎓', true),
(8247, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Damage control resuscitation in massive haemorrhage from polytrauma emphasises:', '["Early balanced transfusion of blood products (red cells, plasma, platelets) and permissive hypotension while controlling the source of bleeding", "Aggressive large-volume crystalloid resuscitation as the sole strategy", "Delaying all blood product transfusion until haemoglobin falls below 5 g/dL", "Avoiding surgical haemorrhage control until the patient is fully stabilised"]'::jsonb, 0, 'Damage control resuscitation favours early, balanced transfusion of blood products in ratios approximating whole blood, limits crystalloid to avoid dilutional coagulopathy, and pursues rapid haemorrhage source control rather than prolonged pre-operative stabilisation.', 'Pre-Council', '🎓', true),
(8248, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Pulmonary contusion following blunt chest trauma typically:', '["Worsens over the first 24-48 hours and can progress to respiratory failure or ARDS", "Is immediately visible and maximal in severity on the initial chest X-ray with no subsequent change", "Never affects oxygenation", "Requires no monitoring once diagnosed"]'::jsonb, 0, 'Pulmonary contusion characteristically worsens over the first 24-48 hours as oedema and haemorrhage evolve within the injured lung tissue, and can progress to significant hypoxaemia or ARDS, so close monitoring is essential even if initial imaging appears mild.', 'Pre-Council', '🎓', true),
(8249, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Why is cervical spine immobilisation maintained throughout initial assessment and log-rolling of a poly-trauma patient?', '["To prevent secondary spinal cord injury until a significant cervical spine injury has been excluded", "Because it is required only for patients who are fully conscious", "Because it improves oxygenation directly", "Because it is only necessary after imaging confirms a fracture"]'::jsonb, 0, 'Until a significant cervical spine injury is excluded by clinical assessment and/or imaging, immobilisation is maintained during all handling (including log-rolling) to prevent movement that could cause or worsen spinal cord injury.', 'Pre-Council', '🎓', true),
(8250, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'The Focused Assessment with Sonography for Trauma (FAST) scan is primarily used to detect:', '["Free fluid (typically blood) in the peritoneal, pericardial, or pleural spaces", "Fractures of long bones", "Cervical spine fractures", "Traumatic brain injury directly"]'::jsonb, 0, 'FAST scanning uses bedside ultrasound to rapidly detect free intraperitoneal, pericardial, or pleural fluid, helping to identify life-threatening internal haemorrhage in trauma patients.', 'Pre-Council', '🎓', true),
(8251, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'A poly-trauma patient with multiple long bone fractures develops sudden dyspnoea, a petechial rash, and confusion 24-48 hours after injury. This presentation should raise suspicion for:', '["Fat embolism syndrome", "A simple wound infection", "Chronic bronchitis exacerbation", "Anaesthetic death"]'::jsonb, 0, 'Fat embolism syndrome classically presents 24-72 hours after long bone or pelvic fractures with the triad of respiratory distress, neurological changes, and a petechial rash, resulting from fat globules entering the circulation and lodging in pulmonary and systemic capillaries.', 'Pre-Council', '🎓', true),
(8252, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'In managing a poly-traumatised ICU patient, cardio-respiratory monitoring priorities include which parameters?', '["Continuous pulse oximetry, cardiac rhythm/rate, blood pressure, and respiratory rate/pattern", "Only intermittent daily weight measurement", "Skin temperature checked once every 12 hours only", "Bowel sounds every hour as the sole monitoring parameter"]'::jsonb, 0, 'Continuous monitoring of oxygen saturation, cardiac rhythm and rate, blood pressure, and respiratory rate/pattern allows early detection of deterioration such as hypoxaemia, haemorrhagic shock, or evolving pneumothorax in poly-trauma patients.', 'Pre-Council', '🎓', true),
(8253, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Which of the following is an appropriate indication for supplemental oxygen therapy?', '["Documented or strongly suspected hypoxaemia (e.g., SpO2 below target range) from any cause", "A patient with normal oxygen saturation and no respiratory symptoms", "Routine prophylaxis for all post-operative patients regardless of saturation", "Mild anxiety with a normal oxygen saturation"]'::jsonb, 0, 'Oxygen therapy is indicated for documented or strongly suspected hypoxaemia or conditions with high risk of tissue hypoxia (e.g., shock, major trauma, carbon monoxide poisoning); it is not indicated as routine therapy in patients with normal saturation.', 'Pre-Council', '🎓', true),
(8254, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'A standard nasal cannula delivering oxygen at 1-6 L/min typically provides an approximate FiO2 range of:', '["24% to 44%", "60% to 100%", "10% to 15%", "95% to 100% consistently"]'::jsonb, 0, 'Nasal cannula flow rates of 1-6 L/min deliver an approximate FiO2 of 24-44%, though the exact FiO2 varies with the patient''s minute ventilation and breathing pattern.', 'Pre-Council', '🎓', true),
(8255, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Why must a simple face mask be run at a minimum flow rate of about 5 L/min?', '["To flush exhaled carbon dioxide from the mask and prevent rebreathing", "To increase patient comfort only", "To prevent the mask from fogging", "To reduce oxygen consumption"]'::jsonb, 0, 'Flow below about 5 L/min may not adequately flush CO2 from the mask reservoir, risking rebreathing of exhaled carbon dioxide.', 'Pre-Council', '🎓', true),
(8256, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'The main advantage of a Venturi mask over a simple face mask is:', '["It delivers a precise, fixed FiO2 regardless of the patient''s respiratory pattern", "It always delivers 100% oxygen", "It eliminates the need for humidification", "It can only be used in intubated patients"]'::jsonb, 0, 'Venturi masks use the Bernoulli principle to entrain a fixed ratio of room air to oxygen, delivering a precisely controlled, consistent FiO2 - important in conditions like COPD where controlled oxygen delivery is essential.', 'Pre-Council', '🎓', true),
(8257, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'A non-rebreather mask with a reservoir bag, run at 10-15 L/min, can deliver an approximate FiO2 of:', '["60% to 90%", "21% (room air) only", "30% to 35% maximum", "100% invariably in every patient"]'::jsonb, 0, 'A well-fitted non-rebreather mask with an adequately filled reservoir bag can deliver approximately 60-90% FiO2, the highest concentration achievable by a non-invasive, non-high-flow device.', 'Pre-Council', '🎓', true),
(8258, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'A key clinical advantage of high-flow nasal cannula (HFNC) therapy over standard low-flow oxygen devices is:', '["It can deliver heated, humidified oxygen at high flow rates with a more consistent, higher FiO2 and some positive airway pressure effect", "It requires no humidification at any flow rate", "It cannot be used in any patient with respiratory distress", "It delivers a lower FiO2 than a simple nasal cannula"]'::jsonb, 0, 'HFNC delivers heated and humidified gas at flows up to 60 L/min, achieving a more reliable, higher FiO2, washing out nasopharyngeal dead space, and generating a modest positive pressure effect that can reduce work of breathing.', 'Pre-Council', '🎓', true),
(8259, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'The primary mechanism underlying oxygen toxicity in the lungs is:', '["Generation of excess reactive oxygen free radicals that overwhelm antioxidant defences and damage cell membranes", "Direct mechanical trauma from high gas flow", "Bacterial colonisation triggered by oxygen itself", "An allergic hypersensitivity reaction to oxygen molecules"]'::jsonb, 0, 'Prolonged exposure to high concentrations of oxygen generates reactive oxygen species (free radicals) that exceed the lung''s antioxidant capacity, causing direct cellular injury, inflammation, and impaired surfactant function.', 'Pre-Council', '🎓', true),
(8260, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Pulmonary oxygen toxicity is most likely to develop with which exposure pattern?', '["FiO2 greater than about 60% sustained for more than 24-48 hours", "Brief exposure to 100% oxygen for less than 5 minutes during pre-oxygenation", "FiO2 of 21% (room air) for any duration", "Intermittent low-flow nasal cannula oxygen at 2 L/min"]'::jsonb, 0, 'Oxygen toxicity risk rises significantly with prolonged exposure (generally more than 24-48 hours) to high FiO2 (typically above 50-60%); brief high-FiO2 exposure, such as during pre-oxygenation, carries minimal risk.', 'Pre-Council', '🎓', true),
(8261, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'What is the most effective strategy to prevent oxygen toxicity in a mechanically ventilated patient?', '["Titrate to the lowest FiO2 that maintains an acceptable target oxygen saturation, weaning as tolerated", "Maintain FiO2 at 100% throughout the admission to ensure adequate oxygenation", "Avoid all pulse oximetry and ABG monitoring to reduce patient disturbance", "Increase FiO2 progressively regardless of oxygen saturation trends"]'::jsonb, 0, 'Using the lowest FiO2 necessary to achieve adequate oxygenation, guided by pulse oximetry and ABG monitoring, and weaning promptly as the patient''s condition allows, minimises the risk of oxygen toxicity while still preventing hypoxaemia.', 'Pre-Council', '🎓', true),
(8262, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Absorption atelectasis, a complication of high-FiO2 oxygen therapy, occurs because:', '["High-concentration oxygen washes out alveolar nitrogen, and when oxygen is absorbed by the blood faster than it is replaced, the alveoli collapse", "High oxygen concentrations cause bronchospasm and airway collapse", "Oxygen directly destroys surfactant-producing cells within minutes", "It only occurs with room air, never with supplemental oxygen"]'::jsonb, 0, 'Nitrogen normally helps keep alveoli splinted open since it is poorly absorbed; high FiO2 washes out this nitrogen, and because oxygen is absorbed into the blood rapidly, alveoli with poor ventilation can collapse, causing absorption atelectasis.', 'Pre-Council', '🎓', true),
(8263, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Retinopathy of prematurity is a recognised complication of high supplemental oxygen exposure specifically in which population?', '["Premature neonates, due to abnormal retinal vascular development from hyperoxia", "Adult patients with COPD", "Elderly patients on long-term home oxygen", "Pregnant women receiving oxygen during labour"]'::jsonb, 0, 'In preterm neonates, uncontrolled high oxygen exposure can disrupt normal retinal vascular development, leading to retinopathy of prematurity; oxygen saturation targets in preterm infants are therefore carefully controlled.', 'Pre-Council', '🎓', true),
(8264, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'To reduce fire hazard, which safety precaution is essential when a patient is receiving supplemental oxygen therapy?', '["Avoid open flames, smoking, and oil- or petroleum-based products near the oxygen source", "Store oxygen cylinders near any heat source for convenience", "Use petroleum jelly on the lips and nares to prevent dryness", "Allow smoking as long as the patient is clinically stable"]'::jsonb, 0, 'Oxygen supports combustion; open flames, smoking, and oil/petroleum-based products (which can ignite more readily in an oxygen-enriched environment) must be strictly avoided near any oxygen source.', 'Pre-Council', '🎓', true),
(8265, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Why is humidification important during prolonged or high-flow oxygen therapy?', '["Dry medical oxygen can irritate and dry the airway mucosa, impairing mucociliary clearance and causing discomfort", "Humidification increases the FiO2 delivered to the patient", "Humidification eliminates the need for regular oxygen saturation monitoring", "Humidification prevents oxygen toxicity entirely"]'::jsonb, 0, 'Medical oxygen is dry; without humidification, prolonged or high-flow delivery can dry and irritate the respiratory mucosa, thicken secretions, and impair mucociliary clearance, so humidified delivery is used especially for high-flow or long-duration therapy.', 'Pre-Council', '🎓', true),
(8266, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'In suspected carbon monoxide poisoning, the recommended oxygen therapy is:', '["High-concentration (ideally 100%) oxygen, as it accelerates dissociation of carbon monoxide from haemoglobin", "Low-flow nasal cannula at 1-2 L/min only", "No supplemental oxygen, since pulse oximetry will appear normal", "Oxygen therapy only if the patient is unconscious"]'::jsonb, 0, 'High-concentration oxygen (100%, or hyperbaric oxygen where available) dramatically shortens the half-life of carboxyhaemoglobin, accelerating displacement of carbon monoxide from haemoglobin binding sites.', 'Pre-Council', '🎓', true),
(8267, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Why can standard pulse oximetry be misleading in a patient with significant carbon monoxide poisoning?', '["Pulse oximetry cannot distinguish carboxyhaemoglobin from oxyhaemoglobin and may show a falsely normal or high reading despite severe tissue hypoxia", "Pulse oximetry always reads falsely low in carbon monoxide poisoning", "Pulse oximetry cannot be used at all in any critically ill patient", "Carbon monoxide poisoning has no effect on pulse oximetry readings"]'::jsonb, 0, 'Standard two-wavelength pulse oximeters cannot differentiate carboxyhaemoglobin from oxyhaemoglobin, so SpO2 can appear falsely reassuring even with dangerously reduced oxygen-carrying capacity; co-oximetry is needed to measure carboxyhaemoglobin directly.', 'Pre-Council', '🎓', true),
(8268, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'For most acutely ill adult patients without chronic CO2 retention, a commonly recommended target oxygen saturation range is:', '["94% to 98%", "70% to 80%", "100% at all times regardless of underlying condition", "Below 88% to avoid oxygen toxicity"]'::jsonb, 0, 'For most acutely unwell patients without a risk of hypercapnic respiratory failure, a target SpO2 of 94-98% is generally recommended, balancing adequate oxygenation against the risks of hyperoxia.', 'Pre-Council', '🎓', true),
(8269, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Which combination of monitoring tools provides the most complete assessment of a patient''s oxygenation and ventilation status during oxygen therapy?', '["Continuous pulse oximetry together with periodic arterial blood gas analysis", "Pulse oximetry alone, with no need for blood gas analysis", "Blood pressure monitoring alone", "Body temperature monitoring alone"]'::jsonb, 0, 'Pulse oximetry provides continuous, real-time trending of oxygen saturation, while ABG analysis provides a definitive assessment of oxygenation (PaO2), ventilation (PaCO2), and acid-base status that oximetry alone cannot capture.', 'Pre-Council', '🎓', true),
(8270, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Continuous capnography (end-tidal CO2 monitoring) in an intubated patient is most useful for:', '["Confirming correct endotracheal tube placement and continuously monitoring ventilation trends", "Measuring arterial oxygen saturation directly", "Diagnosing pneumothorax definitively", "Replacing the need for chest X-ray after intubation in every circumstance"]'::jsonb, 0, 'Capnography provides immediate confirmation of tracheal (versus oesophageal) tube placement via a sustained CO2 waveform and continuously reflects ventilation status, alerting to disconnection, obstruction, or changes in ventilatory status in real time.', 'Pre-Council', '🎓', true),
(8271, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'An arterial line provides which key advantages in a critically ill patient compared with intermittent non-invasive blood pressure measurement?', '["Continuous, beat-to-beat blood pressure monitoring and easy repeated arterial blood sampling", "It eliminates the need for any other haemodynamic monitoring", "It measures central venous pressure directly", "It is only useful for measuring body temperature"]'::jsonb, 0, 'An arterial line allows continuous, real-time blood pressure monitoring (important in haemodynamically unstable patients) and convenient repeated blood sampling for ABGs and laboratory tests without repeated venepuncture.', 'Pre-Council', '🎓', true),
(8272, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'A key limitation of standard pulse oximetry is that it:', '["Does not reflect the adequacy of ventilation (PaCO2) and can be inaccurate in poor peripheral perfusion, hypothermia, or with abnormal haemoglobins", "Provides a direct continuous measurement of PaCO2", "Cannot be affected by patient movement or poor perfusion", "Always accurately reflects carbon dioxide levels"]'::jsonb, 0, 'Pulse oximetry measures oxygen saturation, not ventilation; a patient can have a normal SpO2 while hypoventilating and accumulating CO2, and readings can be unreliable with poor perfusion, hypothermia, nail polish, or abnormal haemoglobins like carboxyhaemoglobin.', 'Pre-Council', '🎓', true),
(8273, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Central venous pressure (CVP) monitoring is primarily used to help assess:', '["Right-sided cardiac filling pressures and guide fluid management in selected patients", "Arterial oxygen saturation directly", "Airway resistance in mechanically ventilated patients", "Core body temperature trends"]'::jsonb, 0, 'CVP reflects right atrial/right ventricular filling pressure and can help guide fluid management, though it has recognised limitations and is now used alongside other dynamic measures of fluid responsiveness rather than in isolation.', 'Pre-Council', '🎓', true),
(8274, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'An increasing respiratory rate in a hospitalised patient, even with a currently normal oxygen saturation, should be regarded as:', '["A potentially important early warning sign of clinical deterioration requiring closer assessment", "An insignificant finding that can be safely ignored if SpO2 is normal", "Proof that the patient has definitely developed pneumonia", "An indication to immediately discontinue all monitoring"]'::jsonb, 0, 'Respiratory rate is a sensitive early indicator of physiological deterioration and is often included in early warning scores; a rising rate can precede measurable falls in oxygen saturation and warrants prompt clinical reassessment.', 'Pre-Council', '🎓', true),
(8275, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'In mechanically ventilated patients, monitoring of peak and plateau airway pressures is important because:', '["A rising peak pressure with a normal plateau pressure suggests increased airway resistance, while a rise in both suggests decreased lung/chest wall compliance", "Airway pressures have no relationship to lung mechanics", "These pressures only need to be checked once per week", "High airway pressures always indicate ventilator malfunction and never reflect patient pathology"]'::jsonb, 0, 'Differentiating a rise in peak pressure alone (suggesting airway resistance issues such as bronchospasm, secretions, or a kinked tube) from a rise in both peak and plateau pressure (suggesting reduced compliance, such as pneumothorax, ARDS, or worsening pulmonary oedema) helps localise the underlying problem.', 'Pre-Council', '🎓', true),
(8276, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Mixed venous oxygen saturation (SvO2) monitoring provides information about:', '["The balance between total body oxygen delivery and oxygen consumption", "Arterial carbon dioxide levels exclusively", "Airway resistance only", "Renal perfusion exclusively"]'::jsonb, 0, 'SvO2, sampled from the pulmonary artery (or ScvO2 from a central line), reflects the adequacy of oxygen delivery relative to tissue oxygen consumption, falling in states of low cardiac output, anaemia, hypoxaemia, or increased metabolic demand.', 'Pre-Council', '🎓', true),
(8277, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Why is careful alarm management important on cardio-respiratory monitors in the ICU?', '["Excessive false or non-actionable alarms contribute to alarm fatigue, which can cause staff to miss a genuinely critical alarm", "Alarms have no clinical significance and can be disabled routinely", "Alarm limits should never be individualised to the patient", "Alarms are only relevant for administrative record-keeping"]'::jsonb, 0, 'Alarm fatigue from frequent non-actionable alarms can desensitise staff and delay response to a genuinely critical event; alarm limits should be set appropriately for each patient to reduce unnecessary alerts while preserving safety.', 'Pre-Council', '🎓', true),
(8278, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Which parameter combination best reflects a comprehensive cardio-respiratory monitoring assessment of a critically ill ICU patient?', '["Heart rate/rhythm, blood pressure, respiratory rate, oxygen saturation, and temperature trended together over time", "Body weight recorded once on admission only", "A single isolated oxygen saturation reading taken once per shift", "Random intermittent checks with no defined frequency"]'::jsonb, 0, 'Comprehensive cardio-respiratory monitoring integrates trends in heart rate/rhythm, blood pressure, respiratory rate, oxygen saturation, and temperature, since the overall trend and combination of parameters is more informative than any single isolated value.', 'Pre-Council', '🎓', true),
(8279, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'A sudden, sustained loss of the capnography waveform in an intubated, mechanically ventilated patient most urgently suggests:', '["Accidental extubation, tube dislodgement, or complete airway/circuit disconnection requiring immediate assessment", "A benign, expected finding requiring no action", "Improvement in the patient''s respiratory status", "A need to increase sedation only"]'::jsonb, 0, 'Sudden loss of the CO2 waveform is a medical emergency suggesting the tube is no longer in the trachea, is completely obstructed, or the circuit is disconnected, and demands immediate assessment and intervention.', 'Pre-Council', '🎓', true),
(8280, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'In a patient recovering from anaesthesia, continuous cardio-respiratory monitoring is essential mainly because:', '["Residual anaesthetic and analgesic/sedative effects can cause delayed respiratory depression or airway obstruction that may not be apparent on a single spot-check", "Monitoring is only a legal formality with no clinical value", "Vital signs never change once a patient leaves the operating theatre", "Oxygen saturation always remains stable throughout recovery without exception"]'::jsonb, 0, 'Residual effects of anaesthetic agents, opioids, and sedatives can cause delayed or intermittent respiratory depression and airway obstruction in the recovery period, so continuous monitoring is needed to detect deterioration promptly rather than relying on infrequent spot checks.', 'Pre-Council', '🎓', true),
(8281, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'A patient with pneumonia develops persistent fever, pleuritic chest pain, and a loculated pleural fluid collection with low pH and low glucose on pleural fluid analysis. This is most consistent with:', '["Empyema (infected pleural effusion)", "A simple transudative effusion from heart failure", "Pulmonary embolism", "Chronic bronchitis"]'::jsonb, 0, 'Empyema is a complicated, infected pleural effusion characterised by turbid/purulent fluid, low pH, and low glucose, and often requires drainage in addition to antibiotics.', 'Pre-Council', '🎓', true),
(8282, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'A lung abscess is best described as:', '["A localised collection of pus within lung parenchyma resulting from necrosis of infected tissue", "A benign congenital cyst of the lung", "A collection of air within the pleural space", "A chronic fibrotic scar with no infective component"]'::jsonb, 0, 'A lung abscess is a necrotic cavity filled with pus that develops within the lung parenchyma, often as a complication of aspiration or severe pneumonia.', 'Pre-Council', '🎓', true),
(8283, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Untreated or inadequately treated severe pneumonia can progress to which life-threatening systemic complication?', '["Sepsis and septic shock", "Immediate cure without any risk of deterioration", "Chronic constipation", "An isolated skin rash with no systemic effect"]'::jsonb, 0, 'Severe pneumonia can lead to bacteraemia and a dysregulated systemic inflammatory response, progressing to sepsis and septic shock if not promptly recognised and treated.', 'Pre-Council', '🎓', true),
(8284, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Which clinical combination should raise concern for sepsis secondary to pulmonary infection?', '["Fever or hypothermia, tachycardia, tachypnoea, and altered mental status in the presence of infection", "A single normal temperature reading with no other abnormal vital signs", "Isolated mild cough without fever or haemodynamic change", "A normal white cell count with no clinical symptoms"]'::jsonb, 0, 'Sepsis is suspected when signs of infection are accompanied by physiological derangement such as fever/hypothermia, tachycardia, tachypnoea, and altered mentation, indicating a dysregulated host response requiring urgent management.', 'Pre-Council', '🎓', true),
(8285, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Severe pneumonia is a recognised precipitant of which diffuse lung injury syndrome characterised by bilateral infiltrates and refractory hypoxaemia?', '["Acute respiratory distress syndrome (ARDS)", "Chronic obstructive pulmonary disease", "Idiopathic pulmonary fibrosis", "Pneumoconiosis"]'::jsonb, 0, 'Severe pneumonia is one of the most common causes of ARDS, in which diffuse alveolar damage leads to bilateral infiltrates and refractory hypoxaemia unresponsive to oxygen alone.', 'Pre-Council', '🎓', true),
(8286, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Necrotising pneumonia, a serious complication of acute pulmonary infection, is characterised by:', '["Liquefaction and cavitation of lung tissue visible on imaging, often with a more severe clinical course", "Complete radiographic resolution within 24 hours", "No risk of respiratory compromise", "Absence of any need for antibiotic therapy"]'::jsonb, 0, 'Necrotising pneumonia involves destruction and liquefaction of lung tissue, producing cavitation on imaging, and is associated with a more prolonged, severe clinical course often requiring extended antibiotic therapy and sometimes surgical intervention.', 'Pre-Council', '🎓', true),
(8287, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'A patient recovering from severe pneumonia in ICU should be monitored closely for which late complication?', '["Development of a parapneumonic effusion or empyema requiring drainage", "Sudden complete resolution with no further monitoring required", "Permanent loss of taste sensation", "Immediate discharge readiness regardless of clinical status"]'::jsonb, 0, 'Parapneumonic effusions can develop or progress to empyema even as pneumonia is treated, so ongoing clinical and, where indicated, imaging surveillance is important during recovery.', 'Pre-Council', '🎓', true),
(8288, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'When teaching a patient how to use a metered-dose inhaler, which instruction is most important for effective drug delivery?', '["Coordinate a slow, deep inhalation with actuation of the inhaler, followed by a breath-hold of about 10 seconds", "Inhale as fast as possible immediately after actuation", "Hold the breath for less than 1 second after inhaling", "Actuate the inhaler after fully exhaling and holding the breath"]'::jsonb, 0, 'Correct inhaler technique requires slow, coordinated inhalation with actuation and a breath-hold of about 10 seconds to allow the medication to deposit in the lower airways rather than being exhaled or deposited in the oropharynx.', 'Pre-Council', '🎓', true),
(8289, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Which patient education point is most important for a patient being discharged home on long-term oxygen therapy?', '["Avoid smoking, open flames, and oil-based products near the oxygen source, and use only the prescribed flow rate", "It is safe to increase the oxygen flow rate independently whenever feeling breathless", "Oxygen concentrators require no maintenance or safety precautions", "Home oxygen therapy has no fire risk"]'::jsonb, 0, 'Patients on home oxygen must be taught fire safety precautions and to use only the prescribed flow rate, since unsupervised increases can be harmful (e.g., in CO2 retainers) and combustion risk around oxygen sources is real.', 'Pre-Council', '🎓', true),
(8290, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Incentive spirometry is taught to post-operative or immobile patients primarily to:', '["Encourage deep, sustained inspiration to prevent atelectasis and improve lung expansion", "Measure blood pressure non-invasively", "Replace the need for early mobilisation", "Diagnose pulmonary embolism"]'::jsonb, 0, 'Incentive spirometry encourages slow, deep, sustained inhalation, promoting alveolar expansion and helping prevent postoperative atelectasis and its complications.', 'Pre-Council', '🎓', true),
(8291, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'A patient with COPD should be educated to seek urgent medical attention for which warning sign?', '["A significant increase in breathlessness, a change in sputum colour/volume, or new fever suggesting an exacerbation or infection", "Occasional mild breathlessness identical to their usual baseline", "Feeling well with no change in symptoms", "A single missed dose of an as-needed bronchodilator with no symptoms"]'::jsonb, 0, 'Worsening dyspnoea, changes in sputum characteristics, or fever can signal an infective exacerbation requiring prompt evaluation and treatment to prevent respiratory failure.', 'Pre-Council', '🎓', true),
(8292, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Vaccination education for patients with chronic respiratory disease such as COPD should include recommending:', '["Annual influenza vaccination and appropriate pneumococcal vaccination", "Avoidance of all vaccines due to lung disease", "Vaccination only if the patient has never had pneumonia", "Vaccination is unnecessary once a patient is on inhaled therapy"]'::jsonb, 0, 'Patients with chronic respiratory disease are at higher risk of severe respiratory infections, so annual influenza vaccination and appropriate pneumococcal vaccination are recommended to reduce the risk and severity of infective exacerbations.', 'Pre-Council', '🎓', true),
(8293, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'For a patient recovering from aspiration pneumonitis, discharge education should include:', '["Recognising and reporting symptoms of secondary infection (fever, purulent sputum, worsening breathlessness) and adhering to any prescribed follow-up review", "No need for any follow-up care once symptoms subside", "Avoiding all future medical or dental procedures requiring sedation", "Resuming a normal diet immediately without any swallow assessment even if aspiration was related to dysphagia"]'::jsonb, 0, 'Patients should be taught to recognise signs of secondary bacterial infection and to attend follow-up review/imaging as advised; if aspiration was related to a swallowing problem, a formal swallow assessment should precede resumption of oral intake.', 'Pre-Council', '🎓', true),
(8294, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Anaesthetic death is best defined as:', '["Death occurring during or within a defined period after administration of anaesthesia, where anaesthesia is a contributing or direct cause", "Any death occurring in a hospital regardless of cause", "Death occurring more than one year after a surgical procedure", "Death occurring exclusively from the underlying surgical disease with no relation to anaesthesia"]'::jsonb, 0, 'Anaesthetic death refers to death occurring during administration of anaesthesia or within a defined perioperative period, where the anaesthetic process is implicated as a direct or contributing cause.', 'Pre-Council', '🎓', true),
(8295, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Which of the following is a recognised direct cause of anaesthetic-related death?', '["Failed airway management leading to unrecognised hypoxia", "Post-operative wound infection occurring two weeks later", "Chronic disease progression unrelated to the anaesthetic episode", "Patient non-adherence to outpatient medication after discharge"]'::jsonb, 0, 'Failed or difficult airway management leading to unrecognised or prolonged hypoxia is one of the most commonly cited direct causes of anaesthetic-related mortality and morbidity.', 'Pre-Council', '🎓', true),
(8296, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Malignant hyperthermia, a rare but life-threatening complication of certain anaesthetic agents, is characterised by:', '["A hypermetabolic crisis with rapidly rising temperature, muscle rigidity, and severe acidosis triggered by agents such as volatile anaesthetics or succinylcholine", "A slow, painless decline in body temperature over several days", "An allergic skin rash with no systemic effect", "A benign, self-limiting condition requiring no treatment"]'::jsonb, 0, 'Malignant hyperthermia is a genetically predisposed hypermetabolic crisis triggered by certain anaesthetic agents (notably volatile anaesthetics and succinylcholine), presenting with rapidly rising temperature, muscle rigidity, tachycardia, and severe metabolic acidosis; it is potentially fatal without prompt treatment (e.g., dantrolene).', 'Pre-Council', '🎓', true),
(8297, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Anaphylaxis during anaesthesia, a potential cause of anaesthetic death, most commonly occurs in response to:', '["Neuromuscular blocking agents, antibiotics, or latex exposure", "Isolated exposure to room air", "Standard surgical drapes, which are non-allergenic in all patients", "Body temperature changes alone"]'::jsonb, 0, 'Neuromuscular blocking agents, antibiotics, and latex are among the most common triggers of intraoperative anaphylaxis, which can rapidly progress to cardiovascular collapse if not promptly recognised and treated.', 'Pre-Council', '🎓', true),
(8298, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Which precaution is most important in reducing the risk of anaesthetic death related to a difficult or failed airway?', '["Thorough pre-anaesthetic airway assessment and immediate availability of a difficult airway management plan/equipment", "Proceeding with induction without any airway assessment to save time", "Relying solely on the surgeon''s assessment of airway risk", "Avoiding pre-oxygenation to reduce procedure time"]'::jsonb, 0, 'Systematic pre-anaesthetic airway assessment, along with a clear failed-airway algorithm and immediately available difficult airway equipment, significantly reduces the risk of catastrophic hypoxia from failed intubation.', 'Pre-Council', '🎓', true),
(8299, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Use of the WHO Surgical Safety Checklist before induction of anaesthesia is intended to:', '["Systematically verify patient identity, procedure, allergies, airway risk, and equipment readiness to reduce preventable perioperative errors", "Replace the need for a formal pre-anaesthetic assessment", "Serve only as a legal document with no clinical value", "Apply only to major cardiac surgery"]'::jsonb, 0, 'The WHO Surgical Safety Checklist is a structured team communication tool used at key perioperative points to confirm patient identity, procedure, known risks (e.g., allergy, difficult airway), and equipment/medication readiness, reducing preventable errors and adverse events.', 'Pre-Council', '🎓', true),
(8300, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Following an unexpected death during anaesthesia, which medico-legal step is typically required?', '["Thorough documentation of events, notification of relevant authorities, and often a post-mortem examination/coronial inquiry", "Immediate destruction of the anaesthetic record to protect the practitioner", "No formal reporting is required if the family does not ask questions", "Informing only the hospital''s finance department"]'::jsonb, 0, 'An unexpected anaesthetic-related death typically requires detailed documentation, notification to relevant regulatory/legal authorities, and often a medico-legal post-mortem or coronial-equivalent inquiry to establish the cause of death.', 'Pre-Council', '🎓', true),
(8301, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'In the context of anaesthetic death, informed consent is medico-legally significant because it:', '["Documents that the patient (or authorised surrogate) was informed of material risks, including rare but serious anaesthetic risks, before agreeing to proceed", "Guarantees that no complication, including death, can ever occur", "Is only relevant for surgical risks, not anaesthetic risks", "Removes all legal responsibility from the anaesthetic provider regardless of care provided"]'::jsonb, 0, 'Informed consent documents that the patient was made aware of material risks, including serious but rare anaesthetic risks, but it does not eliminate the practitioner''s duty to provide a reasonable standard of care; negligence can still be established despite consent having been obtained.', 'Pre-Council', '🎓', true),
(8302, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Accurate and contemporaneous anaesthetic documentation is medico-legally important primarily because it:', '["Provides an objective record of events, monitoring, and interventions that can be reviewed in the event of an adverse outcome or legal inquiry", "Is only used for billing purposes", "Has no bearing on legal proceedings following an adverse event", "Can be completed retrospectively from memory days later with equal legal value"]'::jsonb, 0, 'Contemporaneous, accurate documentation of vital signs, drugs given, and events during anaesthesia provides crucial objective evidence in any subsequent clinical review, negligence claim, or coronial/medico-legal inquiry.', 'Pre-Council', '🎓', true),
(8303, 'Pulmonary Complications and Complications of Anaesthesia', 'CCN Curriculum — Anaesthesia', 'Which factor is a recognised systems-level contributor to preventable anaesthetic death, beyond individual practitioner error?', '["Inadequate monitoring standards, equipment failure, or insufficient staffing/supervision", "A fully stocked and functioning difficult airway trolley", "Routine use of standardised monitoring protocols", "Adequate pre-anaesthetic assessment performed for every patient"]'::jsonb, 0, 'Beyond individual error, systemic factors such as inadequate monitoring standards, faulty or missing equipment, and insufficient staffing or supervision are recognised contributors to preventable anaesthetic mortality, which is why standards and checklists exist.', 'Pre-Council', '🎓', true);
